def _clean_env(v: Any, *, default: str = "") -> str:
    """Normalize env var values.
    Railway UI and some copy/paste workflows may store values with surrounding quotes.
    """
    if v is None:
        return default
    s = str(v).strip()
    if not s:
        return default
    if (len(s) >= 2) and ((s[0] == s[-1] == '"') or (s[0] == s[-1] == "'")):
        s = s[1:-1].strip()
    return s

