def _normalize_email(raw: Optional[str]) -> str:
    return (raw or "").strip().lower()


def _billing_active_status(status: Optional[str]) -> bool:
    return (status or "").strip().lower() in {"active", "comped"}


def _get_active_billing_entitlement(db: Session, org: str, email: Optional[str]) -> Optional[BillingEntitlement]:
    mail = _normalize_email(email)
    if not mail:
        return None
    ent = db.execute(
        select(BillingEntitlement).where(
            BillingEntitlement.org_slug == org,
            BillingEntitlement.email == mail,
        ).limit(1)
    ).scalars().first()
    if not ent:
        return None
    if not _billing_active_status(getattr(ent, "status", None)):
        return None
    expires_at = getattr(ent, "expires_at", None)
    if expires_at and int(expires_at) < now_ts():
        return None
    return ent


def _make_provider_event_key(event_type: str, provider_payment_id: Optional[str], provider_checkout_id: Optional[str], raw_body: bytes) -> str:
    base = f"{event_type}|{provider_payment_id or ''}|{provider_checkout_id or ''}|".encode("utf-8") + raw_body
    return hashlib.sha256(base).hexdigest()


def _resolve_checkout_success_url(checkout_id: str, request: Optional[Request]) -> str:
    base = ORKIO_WEB_BASE_URL
    if not base and request is not None:
        try:
            base = (request.headers.get("origin") or "").strip()
        except Exception:
            base = ""
    base = base.rstrip("/")
    if not base:
        return f"/auth?mode=register&checkout=success&checkout_id={checkout_id}"
    return f"{base}/auth?mode=register&checkout=success&checkout_id={checkout_id}"


def _asaas_post(path: str, payload: Dict[str, Any]) -> Dict[str, Any]:
    if not ASAAS_API_KEY:
        raise HTTPException(status_code=503, detail="Billing provider not configured.")
    url = f"{ASAAS_API_BASE_URL.rstrip('/')}/{path.lstrip('/')}"
    req = _urllib_request.Request(
        url,
        data=json.dumps(payload).encode("utf-8"),
        method="POST",
        headers={
            "Content-Type": "application/json",
            "User-Agent": f"Orkio/{APP_VERSION}",
            "access_token": ASAAS_API_KEY,
        },
    )
    try:
        with _urllib_request.urlopen(req, timeout=20) as resp:
            raw = resp.read().decode("utf-8")
            return json.loads(raw) if raw else {}
    except Exception as e:
        detail = str(e)
        try:
            if hasattr(e, "read"):
                raw = e.read().decode("utf-8")
                parsed = json.loads(raw) if raw else {}
                detail = parsed.get("errors", raw) if isinstance(parsed, dict) else raw
        except Exception:
            pass
        raise HTTPException(status_code=502, detail=f"Asaas checkout creation failed: {detail}")


def _billing_tx_for_provider_exists(db: Session, org: str, provider: str, external_ref: Optional[str], status: Optional[str] = None) -> bool:
    if not external_ref:
        return False
    stmt = select(BillingTransaction).where(
        BillingTransaction.org_slug == org,
        BillingTransaction.provider == provider,
        BillingTransaction.external_ref == external_ref,
    )
    if status:
        stmt = stmt.where(BillingTransaction.status == status)
    return db.execute(stmt.limit(1)).scalars().first() is not None


def _wallet_source_exists(db: Session, org: str, email: str, source: str, external_ref: Optional[str]) -> bool:
    if not external_ref:
        return False
    return db.execute(
        select(BillingWalletLedger).where(
            BillingWalletLedger.org_slug == org,
            BillingWalletLedger.email == _normalize_email(email),
            BillingWalletLedger.source == source,
            BillingWalletLedger.external_ref == external_ref,
        ).limit(1)
    ).scalars().first() is not None


def _get_or_create_wallet(db: Session, org: str, email: str, *, user_id: Optional[str] = None, full_name: Optional[str] = None) -> BillingWallet:
    mail = _normalize_email(email)
    wallet = db.execute(
        select(BillingWallet).where(
            BillingWallet.org_slug == org,
            BillingWallet.email == mail,
        ).limit(1)
    ).scalars().first()
    now = now_ts()
    if wallet:
        if user_id and not getattr(wallet, "user_id", None):
            wallet.user_id = user_id
        if full_name and not getattr(wallet, "full_name", None):
            wallet.full_name = full_name
        wallet.updated_at = now
        db.add(wallet)
        return wallet

    wallet = BillingWallet(
        id=new_id(),
        org_slug=org,
        user_id=user_id,
        email=mail,
        full_name=full_name,
        currency="USD",
        balance_usd=0,
        lifetime_credited_usd=0,
        lifetime_debited_usd=0,
        auto_recharge_enabled=False,
        auto_recharge_pack_code=None,
        auto_recharge_threshold_usd=3,
        low_balance_threshold_usd=3,
        created_at=now,
        updated_at=now,
    )
    db.add(wallet)
    return wallet


def _wallet_to_dict(wallet: Optional[BillingWallet]) -> Dict[str, Any]:
    if not wallet:
        return {
            "balance_usd": 0.0,
            "currency": "USD",
            "auto_recharge_enabled": False,
            "auto_recharge_pack_code": None,
            "auto_recharge_threshold_usd": 3.0,
            "low_balance_threshold_usd": 3.0,
            "lifetime_credited_usd": 0.0,
            "lifetime_debited_usd": 0.0,
        }
    return {
        "id": getattr(wallet, "id", None),
        "email": getattr(wallet, "email", None),
        "currency": getattr(wallet, "currency", "USD"),
        "balance_usd": round(float(getattr(wallet, "balance_usd", 0) or 0), 4),
        "lifetime_credited_usd": round(float(getattr(wallet, "lifetime_credited_usd", 0) or 0), 4),
        "lifetime_debited_usd": round(float(getattr(wallet, "lifetime_debited_usd", 0) or 0), 4),
        "auto_recharge_enabled": bool(getattr(wallet, "auto_recharge_enabled", False)),
        "auto_recharge_pack_code": getattr(wallet, "auto_recharge_pack_code", None),
        "auto_recharge_threshold_usd": round(float(getattr(wallet, "auto_recharge_threshold_usd", 0) or 0), 4) if getattr(wallet, "auto_recharge_threshold_usd", None) is not None else None,
        "low_balance_threshold_usd": round(float(getattr(wallet, "low_balance_threshold_usd", 0) or 0), 4) if getattr(wallet, "low_balance_threshold_usd", None) is not None else None,
        "updated_at": getattr(wallet, "updated_at", None),
    }



def _wallet_email_from_user(user: Optional[Dict[str, Any]]) -> str:
    if not isinstance(user, dict):
        return ""
    return str(user.get("email") or "").strip().lower()


def _wallet_ledger_action_exists(db: Session, org: str, email: str, action_key: Optional[str]) -> bool:
    key = str(action_key or "").strip()
    addr = str(email or "").strip().lower()
    if not key or not addr:
        return False
    row = db.execute(
        select(BillingWalletLedger.id).where(
            BillingWalletLedger.org_slug == org,
            BillingWalletLedger.email == addr,
            BillingWalletLedger.direction == "debit",
            BillingWalletLedger.action_key == key,
        ).limit(1)
    ).first()
    return bool(row)


def _wallet_insufficient_detail(
    wallet: Optional[BillingWallet],
    *,
    required_usd: float,
    route: str,
    action_key: Optional[str] = None,
) -> Dict[str, Any]:
    current = round(float(getattr(wallet, "balance_usd", 0) or 0), 4)
    needed = round(max(float(required_usd or 0) - current, 0.0), 4)
    return {
        "code": "WALLET_INSUFFICIENT_BALANCE",
        "message": "Insufficient wallet balance.",
        "route": route,
        "required_usd": round(float(required_usd or 0), 4),
        "current_balance_usd": current,
        "missing_usd": needed,
        "action_key": action_key,
        "wallet": _wallet_to_dict(wallet),
    }


def _wallet_guard_for_chat(
    db: Session,
    org: str,
    user: Optional[Dict[str, Any]],
    *,
    route: str,
    action_key: Optional[str] = None,
    min_balance_usd: Optional[float] = None,
) -> Optional[BillingWallet]:
    if not WALLET_ENFORCEMENT_ENABLED:
        return None
    email = _wallet_email_from_user(user)
    if not email:
        return None
    wallet = _get_or_create_wallet(
        db,
        org,
        email,
        user_id=(user or {}).get("sub"),
        full_name=(user or {}).get("name"),
    )
    required = max(float(min_balance_usd if min_balance_usd is not None else WALLET_CHAT_MIN_BALANCE_USD), 0.0)
    current = round(float(getattr(wallet, "balance_usd", 0) or 0), 4)
    if required > 0 and current < required and not _wallet_ledger_action_exists(db, org, email, action_key):
        raise HTTPException(
            status_code=402,
            detail=_wallet_insufficient_detail(wallet, required_usd=required, route=route, action_key=action_key),
        )
    return wallet


def _wallet_debit_for_chat_usage(
    db: Session,
    org: str,
    user: Optional[Dict[str, Any]],
    *,
    amount_usd: float,
    route: str,
    action_key: Optional[str],
    thread_id: Optional[str] = None,
    message_id: Optional[str] = None,
    agent_id: Optional[str] = None,
    usage_meta: Optional[Dict[str, Any]] = None,
) -> Optional[BillingWallet]:
    if not WALLET_ENFORCEMENT_ENABLED:
        return None
    email = _wallet_email_from_user(user)
    if not email:
        return None
    amount = round(float(amount_usd or 0), 4)
    if amount <= 0:
        return _get_or_create_wallet(
            db,
            org,
            email,
            user_id=(user or {}).get("sub"),
            full_name=(user or {}).get("name"),
        )
    if _wallet_ledger_action_exists(db, org, email, action_key):
        return _get_or_create_wallet(
            db,
            org,
            email,
            user_id=(user or {}).get("sub"),
            full_name=(user or {}).get("name"),
        )
    metadata = dict(usage_meta or {})
    metadata.update({
        "route": route,
        "thread_id": thread_id,
        "message_id": message_id,
        "agent_id": agent_id,
    })
    return _wallet_debit(
        db,
        org,
        email,
        amount_usd=amount,
        source="usage",
        created_by=((user or {}).get("sub") or route),
        action_key=action_key,
        quantity=1,
        external_ref=(message_id or action_key),
        metadata=metadata,
    )

def _wallet_credit(
    db: Session,
    org: str,
    email: str,
    *,
    amount_usd: float,
    source: str,
    created_by: str,
    external_ref: Optional[str] = None,
    provider: Optional[str] = None,
    related_checkout_id: Optional[str] = None,
    related_tx_id: Optional[str] = None,
    action_key: Optional[str] = None,
    quantity: Optional[float] = None,
    full_name: Optional[str] = None,
    metadata: Optional[Dict[str, Any]] = None,
) -> BillingWallet:
    wallet = _get_or_create_wallet(db, org, email, full_name=full_name)
    amount = max(0.0, float(amount_usd or 0))
    new_balance = round(float(wallet.balance_usd or 0) + amount, 4)
    wallet.balance_usd = new_balance
    wallet.lifetime_credited_usd = round(float(wallet.lifetime_credited_usd or 0) + amount, 4)
    wallet.updated_at = now_ts()
    db.add(wallet)
    entry = BillingWalletLedger(
        id=new_id(),
        org_slug=org,
        wallet_id=wallet.id,
        user_id=getattr(wallet, "user_id", None),
        email=wallet.email,
        direction="credit",
        source=source,
        action_key=action_key,
        quantity=quantity,
        unit_price_usd=(amount / max(quantity or 1.0, 1.0)) if quantity else None,
        amount_usd=amount,
        balance_after_usd=new_balance,
        currency="USD",
        provider=provider,
        external_ref=external_ref,
        related_checkout_id=related_checkout_id,
        related_tx_id=related_tx_id,
        metadata=json.dumps(metadata or {}),
        created_by=created_by,
        created_at=now_ts(),
    )
    db.add(entry)
    return wallet


def _wallet_debit(
    db: Session,
    org: str,
    email: str,
    *,
    amount_usd: float,
    source: str,
    created_by: str,
    action_key: Optional[str] = None,
    quantity: Optional[float] = None,
    external_ref: Optional[str] = None,
    metadata: Optional[Dict[str, Any]] = None,
) -> BillingWallet:
    wallet = _get_or_create_wallet(db, org, email)
    amount = round(float(amount_usd or 0), 4)
    if amount <= 0:
        return wallet
    current_balance = round(float(wallet.balance_usd or 0), 4)
    if current_balance < amount:
        raise HTTPException(status_code=402, detail="Insufficient wallet balance.")
    new_balance = round(current_balance - amount, 4)
    wallet.balance_usd = new_balance
    wallet.lifetime_debited_usd = round(float(wallet.lifetime_debited_usd or 0) + amount, 4)
    wallet.updated_at = now_ts()
    db.add(wallet)
    entry = BillingWalletLedger(
        id=new_id(),
        org_slug=org,
        wallet_id=wallet.id,
        user_id=getattr(wallet, "user_id", None),
        email=wallet.email,
        direction="debit",
        source=source,
        action_key=action_key,
        quantity=quantity,
        unit_price_usd=(amount / max(quantity or 1.0, 1.0)) if quantity else None,
        amount_usd=amount,
        balance_after_usd=new_balance,
        currency="USD",
        provider=None,
        external_ref=external_ref,
        related_checkout_id=None,
        related_tx_id=None,
        metadata=json.dumps(metadata or {}),
        created_by=created_by,
        created_at=now_ts(),
    )
    db.add(entry)
    return wallet


def _wallet_credit_from_checkout(db: Session, checkout: BillingCheckout, *, provider_payment_id: Optional[str], confirmed_at: int) -> Optional[BillingWallet]:
    meta = {}
    try:
        meta = json.loads(getattr(checkout, "meta", "") or "{}")
    except Exception:
        meta = {}
    checkout_kind = str(meta.get("checkout_kind") or "plan")
    item_code = str(meta.get("item_code") or checkout.plan_code or "")

    if checkout_kind == "topup":
        pack = _billing_topup_catalog().get(item_code)
        if not pack:
            return None
        external_ref = provider_payment_id or checkout.provider_payment_id or checkout.provider_checkout_id or checkout.id
        if _wallet_source_exists(db, checkout.org_slug, checkout.email, "topup", external_ref):
            return _get_or_create_wallet(db, checkout.org_slug, checkout.email, full_name=checkout.full_name)
        return _wallet_credit(
            db,
            checkout.org_slug,
            checkout.email,
            amount_usd=float(pack.get("credit_usd") or 0),
            source="topup",
            created_by="billing_webhook",
            external_ref=external_ref,
            provider="asaas",
            related_checkout_id=checkout.id,
            action_key=item_code,
            quantity=1,
            full_name=checkout.full_name,
            metadata={"pack": pack},
        )

    plan = _billing_plan_catalog().get(item_code)
    if not plan:
        return None
    included_credit = float(plan.get("included_credit_usd") or 0)
    if included_credit <= 0:
        return _get_or_create_wallet(db, checkout.org_slug, checkout.email, full_name=checkout.full_name)
    external_ref = provider_payment_id or checkout.provider_payment_id or checkout.provider_checkout_id or checkout.id
    if _wallet_source_exists(db, checkout.org_slug, checkout.email, "plan_included", external_ref):
        return _get_or_create_wallet(db, checkout.org_slug, checkout.email, full_name=checkout.full_name)
    return _wallet_credit(
        db,
        checkout.org_slug,
        checkout.email,
        amount_usd=included_credit,
        source="plan_included",
        created_by="billing_webhook",
        external_ref=external_ref,
        provider="asaas",
        related_checkout_id=checkout.id,
        action_key=item_code,
        quantity=1,
        full_name=checkout.full_name,
        metadata={"plan": plan},
    )


def _create_or_update_entitlement_from_checkout(db: Session, checkout: BillingCheckout, *, status: str, now: int):
    meta = {}
    try:
        meta = json.loads(getattr(checkout, "meta", "") or "{}")
    except Exception:
        meta = {}
    checkout_kind = str(meta.get("checkout_kind") or "plan")
    if checkout_kind == "topup":
        return

    plan = _billing_plan_catalog().get(checkout.plan_code, {})
    ent = db.execute(
        select(BillingEntitlement).where(
            BillingEntitlement.org_slug == checkout.org_slug,
            BillingEntitlement.email == checkout.email,
        )
    ).scalars().first()
    if status == "active":
        if not ent:
            ent = BillingEntitlement(
                id=new_id(),
                org_slug=checkout.org_slug,
                email=checkout.email,
                full_name=checkout.full_name,
                plan_code=checkout.plan_code,
                plan_name=checkout.plan_name,
                status="active",
                access_source="payment",
                checkout_id=checkout.id,
                starts_at=now,
                expires_at=now + int(plan.get("entitlement_days", 31)) * 86400,
                last_payment_at=now,
                created_at=now,
                updated_at=now,
            )
        else:
            ent.full_name = checkout.full_name or ent.full_name
            ent.plan_code = checkout.plan_code
            ent.plan_name = checkout.plan_name
            ent.status = "active"
            ent.access_source = "payment"
            ent.checkout_id = checkout.id
            ent.starts_at = ent.starts_at or now
            ent.expires_at = now + int(plan.get("entitlement_days", 31)) * 86400
            ent.last_payment_at = now
            ent.updated_at = now
        db.add(ent)
    elif ent:
        ent.status = status
        ent.updated_at = now
        db.add(ent)


def _record_billing_tx_from_checkout(db: Session, checkout: BillingCheckout, provider_payment_id: Optional[str], *, confirmed_at: int):
    external_ref = provider_payment_id or checkout.provider_payment_id or checkout.provider_checkout_id or checkout.id
    if _billing_tx_for_provider_exists(db, checkout.org_slug, "asaas", external_ref, "confirmed"):
        return
    meta = {}
    try:
        meta = json.loads(getattr(checkout, "meta", "") or "{}")
    except Exception:
        meta = {}
    checkout_kind = str(meta.get("checkout_kind") or "plan")
    item_code = str(meta.get("item_code") or checkout.plan_code or "")

    amount_brl = float(getattr(checkout, "amount_brl", 0) or 0)
    amount_usd = round(amount_brl / max(BILLING_USD_BRL, 0.0001), 2) if amount_brl else 0.0

    if checkout_kind == "topup":
        pack = _billing_topup_catalog().get(item_code, {})
        row = BillingTransaction(
            id=new_id(),
            org_slug=checkout.org_slug,
            payer_email=checkout.email,
            payer_name=checkout.full_name,
            provider="asaas",
            external_ref=external_ref,
            subscription_key=None,
            plan_code=item_code,
            charge_kind="wallet_topup",
            currency="USD",
            amount_original=amount_brl,
            amount_usd=amount_usd,
            normalized_mrr_usd=0,
            status="confirmed",
            occurred_at=confirmed_at,
            confirmed_at=confirmed_at,
            notes=f"Wallet top-up from Asaas checkout {checkout.id}",
            created_by="billing_webhook",
            created_at=now_ts(),
        )
        db.add(row)
        return

    plan = _billing_plan_catalog().get(item_code, {})
    normalized_mrr_usd = plan.get("normalized_mrr_usd")
    if normalized_mrr_usd is None:
        normalized_mrr_usd = amount_usd
    row = BillingTransaction(
        id=new_id(),
        org_slug=checkout.org_slug,
        payer_email=checkout.email,
        payer_name=checkout.full_name,
        provider="asaas",
        external_ref=external_ref,
        subscription_key=checkout.provider_checkout_id,
        plan_code=item_code,
        charge_kind="recurring",
        currency="USD",
        amount_original=amount_brl,
        amount_usd=amount_usd,
        normalized_mrr_usd=float(normalized_mrr_usd or 0),
        status="confirmed",
        occurred_at=confirmed_at,
        confirmed_at=confirmed_at,
        notes=f"Auto-import from Asaas checkout {checkout.id}",
        created_by="billing_webhook",
        created_at=now_ts(),
    )
    db.add(row)


PASSWORD_RESET_EXPIRES_MINUTES = int(os.getenv("PASSWORD_RESET_EXPIRES_MINUTES", "20"))
FOUNDER_FOLLOWUP_THRESHOLD = int(os.getenv("FOUNDER_FOLLOWUP_THRESHOLD", "9"))
CONFERENCE_STT_CONFIDENCE = float(os.getenv("CONFERENCE_STT_CONFIDENCE", "0.78"))

FOUNDER_ALLOWED_ACTIONS = {
    "contact_requested",
    "meeting_requested",
    "followup_scheduled",
    "warm_continue",
    "deepen_fintegra",
    "deepen_arquitec",
    "collect_qualification",
    "offer_private_followup",
    "founder_join",
    "dismissed",
}
_FOUNDER_GUIDANCE_TURNS = int(os.getenv("FOUNDER_GUIDANCE_TURNS", "4") or "4")
_founder_guidance_lock = _threading.Lock()
_founder_guidance_state: dict = {}  # {(org, thread_id): {"action": str, "turns_left": int, "goal": str}}

_GITHUB_WRITE_APPROVAL_TTL_SECONDS = int(os.getenv("GITHUB_WRITE_APPROVAL_TTL_SECONDS", "3600") or "3600")
_github_write_lock = _threading.Lock()
_github_write_approval_state: dict = {}  # {(org, thread_id, user_id): approval_dict}
_github_write_pending_approval_state: dict = {}  # {(org, thread_id/userwide, user_id): pending_proposal_dict}
_github_write_execution_state: dict = {}  # {(org, thread_id, user_id): execution_receipts}

_GITHUB_PENDING_DB_TABLE = "github_pending_approvals"

def _github_pending_db_ensure_schema(db: Session) -> None:
    """Best-effort local schema guard for governed pending patch approvals.

    This is intentionally colocated in main.py because ORKIO deploys often
    replace app/main.py without a synchronized app/db.py migration. The helper
    is idempotent and safe to call before upsert/fetch/delete.
    """
    try:
        db.execute(text(f"""
            CREATE TABLE IF NOT EXISTS {_GITHUB_PENDING_DB_TABLE} (
                lookup_key VARCHAR PRIMARY KEY,
                org_slug VARCHAR NOT NULL,
                user_id VARCHAR NOT NULL,
                thread_id VARCHAR NULL,
                scope_kind VARCHAR NOT NULL DEFAULT 'thread',
                proposal_json TEXT NOT NULL,
                expires_at BIGINT NULL,
                created_at BIGINT NOT NULL,
                updated_at BIGINT NOT NULL
            )
        """))
        db.execute(text(f"CREATE INDEX IF NOT EXISTS ix_{_GITHUB_PENDING_DB_TABLE}_org_user ON {_GITHUB_PENDING_DB_TABLE} (org_slug, user_id)"))
        db.execute(text(f"CREATE INDEX IF NOT EXISTS ix_{_GITHUB_PENDING_DB_TABLE}_thread ON {_GITHUB_PENDING_DB_TABLE} (thread_id)"))
        db.execute(text(f"CREATE INDEX IF NOT EXISTS ix_{_GITHUB_PENDING_DB_TABLE}_expires ON {_GITHUB_PENDING_DB_TABLE} (expires_at)"))
    except Exception:
        logger.exception("GITHUB_PENDING_APPROVAL_SCHEMA_ENSURE_FAILED")
        raise


def _github_write_pending_memory_key(thread_id: Optional[str]) -> str:
    return f"github_pending_proposal::{str(thread_id or 'global').strip() or 'global'}"


def _github_write_persist_pending_proposal_runtime_memory(
    *,
    org: str,
    thread_id: Optional[str],
    payload: Optional[Dict[str, Any]],
    proposal: Dict[str, Any],
) -> None:
    """No-op secondary persistence.

    RuntimeMemory is not guaranteed to exist in all deployed ORKIO databases.
    The canonical pending-approval store is github_pending_approvals, created
    lazily by _github_pending_db_ensure_schema(). This function is intentionally
    disabled to prevent UndefinedTable(runtime_memories) from poisoning the
    stream approval turn.
    """
    return


def _github_write_load_pending_proposal_runtime_memory(
    org: str,
    thread_id: Optional[str],
    payload: Optional[Dict[str, Any]],
) -> Optional[Dict[str, Any]]:
    """No-op secondary lookup.

    Do not query RuntimeMemory here: some production schemas do not have
    runtime_memories. Lookup must remain deterministic through the dedicated
    github_pending_approvals table and in-memory cache only.
    """
    return None


def _github_write_mark_pending_proposal_runtime_memory(
    *,
    org: str,
    thread_id: Optional[str],
    payload: Optional[Dict[str, Any]],
    status: str,
) -> None:
    """No-op secondary cleanup.

    The dedicated pending approval table is cleared by
    _github_write_clear_pending_proposal(). RuntimeMemory cleanup is disabled
    because runtime_memories is not present in every deployment.
    """
    return


def _github_pending_db_upsert(
    *,
    db: Session,
    lookup_key: str,
    org_slug: str,
    user_id: str,
    thread_id: Optional[str],
    scope_kind: str,
    proposal: Dict[str, Any],
) -> None:
    # Do not commit here; caller controls transaction boundaries.
    _github_pending_db_ensure_schema(db)
    now = now_ts()
    expires_at = int(proposal.get("expires_at") or 0)
    payload_json = json.dumps(proposal, ensure_ascii=False)
    db.execute(
        text(
            f"""
            INSERT INTO {_GITHUB_PENDING_DB_TABLE}
                (lookup_key, org_slug, user_id, thread_id, scope_kind, proposal_json, expires_at, created_at, updated_at)
            VALUES
                (:lookup_key, :org_slug, :user_id, :thread_id, :scope_kind, :proposal_json, :expires_at, :created_at, :updated_at)
            ON CONFLICT (lookup_key) DO UPDATE SET
                org_slug = EXCLUDED.org_slug,
                user_id = EXCLUDED.user_id,
                thread_id = EXCLUDED.thread_id,
                scope_kind = EXCLUDED.scope_kind,
                proposal_json = EXCLUDED.proposal_json,
                expires_at = EXCLUDED.expires_at,
                updated_at = EXCLUDED.updated_at
            """
        ),
        {
            "lookup_key": str(lookup_key or "").strip(),
            "org_slug": str(org_slug or "default").strip() or "default",
            "user_id": str(user_id or "unknown").strip() or "unknown",
            "thread_id": str(thread_id).strip() if thread_id is not None else None,
            "scope_kind": str(scope_kind or "thread").strip() or "thread",
            "proposal_json": payload_json,
            "expires_at": expires_at if expires_at else None,
            "created_at": int(proposal.get("created_at") or now),
            "updated_at": now,
        },
    )

def _github_pending_db_fetch(*, db: Session, lookup_key: str) -> Optional[Dict[str, Any]]:
    lookup = str(lookup_key or "").strip()
    if not lookup:
        return None
    _github_pending_db_ensure_schema(db)
    row = db.execute(
        text(f"SELECT proposal_json, expires_at FROM {_GITHUB_PENDING_DB_TABLE} WHERE lookup_key = :k"),
        {"k": lookup},
    ).fetchone()
    if not row:
        return None
    proposal_json = row[0]
    expires_at = int(row[1] or 0)
    now = now_ts()
    if expires_at and expires_at < now:
        # Expired: delete and behave as not found.
        db.execute(text(f"DELETE FROM {_GITHUB_PENDING_DB_TABLE} WHERE lookup_key = :k"), {"k": lookup})
        return None
    try:
        parsed = json.loads(proposal_json) if proposal_json else None
        return dict(parsed) if isinstance(parsed, dict) else None
    except Exception:
        return None

def _github_pending_db_delete(*, db: Session, lookup_key: str) -> None:
    lookup = str(lookup_key or "").strip()
    if not lookup:
        return
    _github_pending_db_ensure_schema(db)
    db.execute(text(f"DELETE FROM {_GITHUB_PENDING_DB_TABLE} WHERE lookup_key = :k"), {"k": lookup})

def _github_pending_db_try_session() -> Optional[Session]:
    if SessionLocal is None:
        return None
    try:
        session = SessionLocal()
        try:
            _github_pending_db_ensure_schema(session)
            session.commit()
        except Exception:
            try:
                session.rollback()
            except Exception:
                pass
            logger.exception("GITHUB_PENDING_APPROVAL_SCHEMA_BOOTSTRAP_FAILED")
        return session
    except Exception:
        return None




def _github_write_bootstrap_state() -> None:
    global _github_write_lock
    global _github_write_approval_state
    global _github_write_pending_approval_state
    global _github_write_execution_state

    if globals().get("_github_write_lock") is None:
        _github_write_lock = _threading.Lock()

    if not isinstance(globals().get("_github_write_approval_state"), dict):
        _github_write_approval_state = {}

    if not isinstance(globals().get("_github_write_pending_approval_state"), dict):
        _github_write_pending_approval_state = {}

    if not isinstance(globals().get("_github_write_execution_state"), dict):
        _github_write_execution_state = {}


def _github_write_execution_key(org: str, thread_id: Optional[str], payload: Optional[Dict[str, Any]]) -> str:
    user_id = str((payload or {}).get("sub") or "").strip() or "unknown"
    return _github_write_approval_key(org, thread_id, user_id)


def _github_write_get_execution_receipts(org: str, thread_id: Optional[str], payload: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    _github_write_bootstrap_state()
    key = _github_write_execution_key(org, thread_id, payload)
    with _github_write_lock:
        item = _github_write_execution_state.get(key)
        return dict(item) if isinstance(item, dict) else {}


def _github_write_clear_execution_receipts(org: str, thread_id: Optional[str], payload: Optional[Dict[str, Any]]) -> None:
    _github_write_bootstrap_state()
    key = _github_write_execution_key(org, thread_id, payload)
    with _github_write_lock:
        _github_write_execution_state.pop(key, None)


def _github_write_store_execution_receipts(
    *,
    org: str,
    thread_id: Optional[str],
    payload: Optional[Dict[str, Any]],
    result: Dict[str, Any],
) -> Dict[str, Any]:
    _github_write_bootstrap_state()
    key = _github_write_execution_key(org, thread_id, payload)
    with _github_write_lock:
        current = dict(_github_write_execution_state.get(key) or {})
        current["updated_at"] = now_ts()
        provider = str(result.get("provider") or "").strip()
        repo = str(result.get("repo") or "").strip()
        branch = str(result.get("branch") or "").strip()
        base_branch = str(result.get("base_branch") or "").strip()
        commit_sha = str(result.get("commit_sha") or "").strip()
        pr_number = int(result.get("pull_request_number") or 0)
        pr_url = str(result.get("pull_request_url") or "").strip()
        path = str(result.get("path") or "").strip()
        files = list(result.get("files") or []) if isinstance(result.get("files"), list) else []
        if provider:
            current["provider"] = provider
        if repo:
            current["repo"] = repo
        if branch:
            current["branch"] = branch
        if base_branch:
            current["base_branch"] = base_branch
        if str(result.get("verified_ref") or "").strip():
            current["verified_ref"] = str(result.get("verified_ref") or "").strip()
        if result.get("success") and branch and not pr_number and (result.get("message") or "").lower().find("branch") >= 0:
            current["branch_created"] = True
        if result.get("success") and path:
            current["files_written"] = sorted(set(list(current.get("files_written") or []) + [path]))
        if result.get("success") and files:
            current["files_written"] = sorted(set(list(current.get("files_written") or []) + files))
        if commit_sha:
            current["commit_sha"] = commit_sha
            current["commit_created"] = True
        if result.get("compare_ok") is True:
            current["compare_ok"] = True
            current["compare_ahead_by"] = int(result.get("ahead_by") or 0)
            current["compare_files_count"] = int(result.get("files_count") or 0)
        if pr_number > 0 or pr_url:
            current["pull_request_opened"] = bool(result.get("success"))
            current["pull_request_number"] = pr_number
            current["pull_request_url"] = pr_url
        _github_write_execution_state[key] = current
        return dict(current)


def _github_write_transaction_receipts_text(receipts: Optional[Dict[str, Any]]) -> str:
    receipts = receipts or {}
    files_written = list(receipts.get("files_written") or [])
    lines = [
        "RECEIPTS TRANSACIONAIS GITHUB:",
        f"- branch_created: {bool(receipts.get('branch_created'))}",
        f"- branch: {receipts.get('branch') or 'n/d'}",
        f"- files_written: {', '.join(files_written) if files_written else 'nenhum'}",
        f"- commit_created: {bool(receipts.get('commit_created'))}",
        f"- commit_sha: {receipts.get('commit_sha') or 'n/d'}",
        f"- compare_ok: {bool(receipts.get('compare_ok'))}",
        f"- pull_request_opened: {bool(receipts.get('pull_request_opened'))}",
    ]
    if receipts.get("pull_request_number"):
        lines.append(f"- pull_request_number: {receipts.get('pull_request_number')}")
    if receipts.get("pull_request_url"):
        lines.append(f"- pull_request_url: {receipts.get('pull_request_url')}")
    return "\n".join(lines)


def _github_open_pr_preflight_from_receipts(
    *,
    org: str,
    thread_id: Optional[str],
    payload: Optional[Dict[str, Any]],
    pr_req: Optional[Dict[str, str]] = None,
) -> Dict[str, Any]:
    pr_req = dict(pr_req or {})
    receipts = _github_write_get_execution_receipts(org, thread_id, payload)
    default_branch = _clean_env(os.getenv("GITHUB_BRANCH", "main"), default="main") or "main"
    head = str(pr_req.get("head") or receipts.get("branch") or "").strip()
    base = str(pr_req.get("base") or receipts.get("base_branch") or default_branch).strip() or default_branch
    title = str(pr_req.get("title") or "").strip()
    body = str(pr_req.get("body") or "").strip()
    repo_target = str(pr_req.get("repo_target") or receipts.get("repo") or "").strip()
    missing: List[str] = []
    if not bool(receipts.get("branch_created")) and not head:
        missing.append("branch_created")
    if not bool(receipts.get("files_written")):
        missing.append("files_written")
    if not bool(receipts.get("commit_created")) or not str(receipts.get("commit_sha") or "").strip():
        missing.append("commit_created")
    if not head:
        missing.append("head_branch")
    if not title:
        title = f"Orkio governed patch: {head or 'branch'} -> {base}"
    return {
        "receipts": receipts,
        "head": head,
        "base": base,
        "title": title,
        "body": body or None,
        "missing": missing,
        "ready": not bool(missing),
    }


def _github_build_transaction_incomplete_text(
    *,
    org: str,
    thread_id: Optional[str],
    payload: Optional[Dict[str, Any]],
    missing: List[str],
) -> str:
    receipts = _github_write_get_execution_receipts(org, thread_id, payload)
    lines = [
        "FLUXO GITHUB TRANSACIONAL INCOMPLETO.",
        f"- missing_receipts: {', '.join(missing) if missing else 'n/d'}",
        "- required_order: create_branch -> apply_patch/write_file -> prepare_commit -> compare_branches -> open_pr",
        "",
        _github_write_transaction_receipts_text(receipts),
    ]
    return "\n".join(lines)




def _parse_email_recipients(value: Any) -> List[str]:
    if value is None:
        return []
    if isinstance(value, (list, tuple, set)):
        raw_items = [str(v) for v in value]
    else:
        raw_items = [str(value)]
    joined = ",".join(raw_items)
    parts = re.split(r"[;,]", joined)
    out: List[str] = []
    for part in parts:
        email = _clean_env(part)
        if email:
            out.append(email)
    # preserve order / remove duplicates
    seen = set()
    uniq: List[str] = []
    for email in out:
        key = email.lower()
        if key in seen:
            continue
        seen.add(key)
        uniq.append(email)
    return uniq

def _send_resend_email(to_email: Any, subject: str, text_body: str, *, html_body: Optional[str] = None) -> bool:
    api_key = _clean_env(RESEND_API_KEY)
    from_email = _clean_env(RESEND_FROM, default="Orkio <no-reply@orkio.ai>")
    recipients = _parse_email_recipients(to_email)
    if not api_key:
        logger.warning("RESEND_SEND_SKIPPED missing_api_key subject=%s recipients=%s", subject, recipients)
        return False
    if not recipients:
        logger.warning("RESEND_SEND_SKIPPED empty_recipients subject=%s", subject)
        return False
    try:
        data = {
            "from": from_email,
            "to": recipients,
            "subject": subject,
            "text": text_body,
        }
        if html_body:
            data["html"] = html_body
        req = _urllib_request.Request(
            "https://api.resend.com/emails",
            data=json.dumps(data).encode("utf-8"),
            headers={
                "Authorization": f"Bearer {api_key}",
                "Content-Type": "application/json",
                "User-Agent": "orkio-backend/1.0",
            },
            method="POST",
        )
        ctx = _ssl.create_default_context()
        resp = _urllib_request.urlopen(req, context=ctx, timeout=10)
        # Consume the provider response without persisting recipient, subject or body.
        resp.read()
        logger.info(
            "RESEND_SEND_OK status=%s recipient_count=%s",
            getattr(resp, "status", "unknown"),
            len(recipients),
        )
        return True
    except Exception as e:
        logger.warning(
            "RESEND_SEND_FAILED recipient_count=%s error_type=%s",
            len(recipients),
            e.__class__.__name__,
        )
        return False

def _ascii_safe_text(v: str) -> str:
    if not v:
        return ""
    replacements = {
        "\u2192": "->",
        "\u2190": "<-",
        "\u2014": "-",
        "\u2013": "-",
        "\u2022": "-",
        "\u2018": "'",
        "\u2019": "'",
        "\u201c": '"',
        "\u201d": '"',
        "\u00a0": " ",
        "\u2026": "...",
    }
    out = v
    for src, dst in replacements.items():
        out = out.replace(src, dst)
    out = out.encode("utf-8", errors="ignore").decode("utf-8", errors="ignore")
    out = re.sub(r"[^\S\r\n]+", " ", out)
    return out.strip()

def _sanitize_tts_text(v: str) -> str:
    out = _ascii_safe_text(v or "")
    # keep line breaks readable but avoid weird punctuation that breaks TTS providers
    out = re.sub(r"[\r\n]+", " ", out)
    out = re.sub(r"\s+", " ", out).strip()
    return out[:4096]

