def _score_founder_opportunity(email: str, interest_type: str, message: str) -> int:
    score = 0
    msg = (message or "").lower()
    if any(k in msg for k in ["invest", "investment", "fund", "vc", "venture capital", "family office", "partner", "collaboration"]):
        score += 4
    if any(k in msg for k in ["fintegra", "arquitec", "patroai", "orkio"]):
        score += 2
    if any(k in msg for k in ["meeting", "call", "follow-up", "follow up", "conversation"]):
        score += 3
    if interest_type and interest_type.lower() not in ("general", "other"):
        score += 1
    if email and not email.endswith(("@gmail.com", "@hotmail.com", "@outlook.com", "@yahoo.com")):
        score += 1
    if any(k in msg for k in ["source code", "system prompt", "architecture", "financial projection", "cap table"]):
        score -= 3
    return max(score, 0)

def _build_founder_brief(full_name: str, email: str, interest_type: str, conversation_summary: str, score: int) -> str:
    next_step = "Follow-up prioritário do founder." if score >= FOUNDER_FOLLOWUP_THRESHOLD else "Continuar aquecimento com contexto."
    return (
        f"Lead: {full_name or 'Não identificado'}\n"
        f"Email: {email or 'N/A'}\n"
        f"Tipo de interesse: {interest_type or 'geral'}\n"
        f"Score: {score}\n\n"
        "Resumo da conversa:\n"
        f"{(conversation_summary or '').strip()}\n\n"
        "Próximo passo recomendado:\n"
        f"{next_step}"
    )

def _build_thread_handoff_summary(db: Session, org: str, thread_id: Optional[str], fallback_message: str, max_messages: int = 24) -> str:
    fallback = (fallback_message or "").strip()
    tid = (thread_id or "").strip()
    if not tid:
        return fallback
    try:
        rows = db.execute(
            select(Message)
            .where(Message.org_slug == org, Message.thread_id == tid)
            .order_by(Message.created_at.asc())
        ).scalars().all()
    except Exception:
        logger.exception("FOUNDER_HANDOFF_SUMMARY_LOAD_FAILED thread_id=%s", tid)
        return fallback

    parts: List[str] = []
    for msg in rows[-max_messages:]:
        role = (getattr(msg, "role", "") or "").strip().lower()
        if role not in {"user", "assistant"}:
            continue
        raw = (getattr(msg, "content", None) or "").strip()
        if not raw:
            continue
        if "ORKIO_EVENT:" in raw:
            raw = raw.split("ORKIO_EVENT:", 1)[0].strip()
        if not raw:
            continue
        speaker = "Usuário" if role == "user" else ((getattr(msg, "agent_name", None) or "Orkio").strip() or "Orkio")
        safe = _ascii_safe_text(raw)
        if safe:
            parts.append(f"{speaker}: {safe}")

    if fallback:
        safe_fallback = _ascii_safe_text(fallback)
        if safe_fallback and all(safe_fallback not in p for p in parts):
            parts.append(f"Usuário: {safe_fallback}")

    return "\n".join(parts).strip()

def _validate_access_code_no_consume(db: Session, org: str, code: str) -> Optional[SignupCode]:
    normalized = (code or "").strip().upper()
    if not normalized:
        return None
    code_hash = _hash_text(normalized)
    sc = db.execute(
        select(SignupCode).where(
            SignupCode.org_slug == org,
            SignupCode.code_hash == code_hash,
            SignupCode.active == True,
        )
    ).scalar_one_or_none()
    if not sc:
        return None
    if sc.expires_at and sc.expires_at < now_ts():
        return None
    current_used = int(sc.used_count or 0)
    max_uses = int(sc.max_uses or 0)
    if max_uses > 0 and current_used >= max_uses:
        return None
    return sc

def get_current_user(authorization: Optional[str] = Header(default=None)) -> Dict[str, Any]:
    if not authorization or not authorization.lower().startswith("bearer "):
        raise HTTPException(status_code=401, detail="Missing bearer token")
    token = authorization.split(" ", 1)[1].strip()
    try:
        payload = decode_token(token)

        summit_eligible = (
            str(payload.get("usage_tier") or "").startswith("summit_")
            or str(payload.get("signup_source") or "").lower() == "investor"
            or str(payload.get("signup_code_label") or "").lower() == "efatah777"
            or str(payload.get("product_scope") or "").lower() == "full"
        )

        if payload.get("role") != "admin" and payload.get("approved_at") is None and not summit_eligible:
            raise HTTPException(status_code=403, detail="User pending approval")

        try:
            if _summit_access_expired(payload):
                raise HTTPException(status_code=403, detail="Acesso ao Summit encerrado.")
        except HTTPException:
            raise
        except Exception:
            pass
        return payload
    except HTTPException:
        raise
    except Exception:
        raise HTTPException(status_code=401, detail="Invalid token")

def require_onboarding_complete(payload: Dict[str, Any]) -> None:
    # PATCH27_2_CLEAN: onboarding is now fluid/non-blocking for app and realtime flows.
    # Keep admin fast-path and fail-open for non-admins to avoid blocking voice/chat access.
    return

def require_admin(payload: Dict[str, Any]) -> None:
    """Require canonical admin-console authority for an already decoded payload."""
    if has_admin_console_access(payload):
        return
    raise HTTPException(status_code=403, detail="Admin console access required")

def require_admin_key(x_admin_key: Optional[str]) -> None:
    k = admin_api_key()
    # ADMIN_API_KEY is optional; if not configured, key-auth cannot be used.
    if not k:
        raise HTTPException(status_code=401, detail="ADMIN_API_KEY not configured")
    if not x_admin_key or not secrets.compare_digest(str(x_admin_key), str(k)):
        raise HTTPException(status_code=401, detail="Invalid admin key")

def require_admin_access(
    authorization: Optional[str] = Header(default=None),
    x_admin_key: Optional[str] = Header(default=None),
) -> Dict[str, Any]:
    """Allow canonical admin-console authority via JWT or X-Admin-Key.

    Console roles are resolved centrally by ``admin_master_identity`` so
    ``founder_admin``, master roles and configured admin identities behave
    consistently across legacy routes and the newer internal routers.
    """
    # 1) JWT path. A present bearer token never falls through to key auth.
    if authorization and authorization.lower().startswith("bearer "):
        payload = get_current_user(authorization)
        context = {
            **payload,
            **build_admin_authority_context(payload),
            "via": "bearer",
        }
        if context.get("admin_console_access"):
            return context
        raise HTTPException(status_code=403, detail="Admin console access required")

    # 2) Admin key path. Preserve the historical console-admin behavior.
    require_admin_key(x_admin_key)
    base = {
        "role": "admin",
        "via": "admin_key",
        "email": "x-admin-key",
        "sub": "x-admin-key",
    }
    return {
        **base,
        **build_admin_authority_context(base),
        "via": "admin_key",
    }


# PATCH0100_14 — Thread ACL helpers

def _check_thread_member(db: Session, org: str, thread_id: str, user_id: str) -> Optional[ThreadMember]:
    """Return ThreadMember row if user is a member of the thread, else None."""
    return db.execute(
        select(ThreadMember).where(
            ThreadMember.org_slug == org,
            ThreadMember.thread_id == thread_id,
            ThreadMember.user_id == user_id,
        )
    ).scalar_one_or_none()

def _require_thread_member(db: Session, org: str, thread_id: str, user_id: str) -> ThreadMember:
    """
    Ensures user is member of thread.
    Auto-heals legacy threads created before thread_members existed.
    Falls back to message ownership when Thread has no user_id column.
    """
    m = _check_thread_member(db, org, thread_id, user_id)
    if m:
        return m

    # AUTO-HEAL: if the user has authored messages in this legacy thread,
    # recreate membership as owner.
    legacy_msg = db.execute(
        select(Message).where(
            Message.org_slug == org,
            Message.thread_id == thread_id,
            Message.user_id == user_id,
        ).limit(1)
    ).scalar_one_or_none()

    if legacy_msg:
        tm = ThreadMember(
            id=new_id(),
            org_slug=org,
            thread_id=thread_id,
            user_id=user_id,
            role="owner",
            created_at=now_ts(),
        )
        db.add(tm)
        db.commit()
        return tm

    raise HTTPException(status_code=403, detail="Acesso negado a esta thread")

def _require_thread_admin_or_owner(db: Session, org: str, thread_id: str, user_id: str) -> ThreadMember:
    """Raise 403 if user is not owner or admin of the thread."""
    m = _require_thread_member(db, org, thread_id, user_id)
    if m.role not in ("owner", "admin"):
        raise HTTPException(status_code=403, detail="Somente owner/admin podem executar esta ação")
    return m

def _ensure_thread_owner(db: Session, org: str, thread_id: str, user_id: str):
    """Ensure the creator is registered as owner. Idempotent."""
    existing = _check_thread_member(db, org, thread_id, user_id)
    if existing:
        return existing
    tm = ThreadMember(
        id=new_id(), org_slug=org, thread_id=thread_id,
        user_id=user_id, role="owner", created_at=now_ts(),
    )
    db.add(tm)
    db.commit()
    return tm

def _audit_membership(db: Session, org: str, thread_id: str, actor_id: str, target_id: str, target_email: str, action_type: str, role: str):
    """Immutable audit for membership changes."""
    try:
        audit(db, org, actor_id, action_type, request_id="acl", path=f"/api/threads/{thread_id}/members",
              status_code=200, latency_ms=0,
              meta={"thread_id": thread_id, "target_user_id": target_id, "target_email": target_email, "role": role})
    except Exception:
        logger.exception("AUDIT_MEMBERSHIP_FAILED")


def db_ok() -> bool:
    """Return True if database connection is healthy."""
    if ENGINE is None:
        return False
    try:
        from sqlalchemy import text as _text
        with ENGINE.connect() as conn:
            conn.execute(_text("SELECT 1"))
        return True
    except Exception:
        return False


logger = logging.getLogger("orkio")


def _ao79a_request_id(request: Optional[Request] = None, prefix: str = "ao79a") -> str:
    try:
        if request is not None:
            return ensure_request_id(request)
    except Exception:
        pass
    return f"{prefix}_{uuid.uuid4().hex[:16]}"


def _ao79a_email_ref(email: Optional[str]) -> str:
    raw = (email or "").strip().lower()
    if not raw:
        return "email:none"
    return "email_sha256:" + hashlib.sha256(raw.encode("utf-8")).hexdigest()[:12]


def _ao79a_db_pool_status() -> str:
    try:
        pool = getattr(ENGINE, "pool", None)
        status = pool.status() if pool is not None and hasattr(pool, "status") else ""
        return str(status or "unavailable")[:240]
    except Exception:
        return "unavailable"


def _ao79a_is_db_infra_error(exc: BaseException) -> bool:
    if isinstance(exc, (OperationalError, SQLAlchemyTimeoutError, DisconnectionError)):
        return True
    text = f"{exc.__class__.__name__} {str(exc)}".lower()
    markers = (
        "queuepool",
        "connection pool",
        "pool timeout",
        "timeout",
        "could not connect",
        "connection refused",
        "connection reset",
        "server closed the connection",
        "database is locked",
        "too many connections",
    )
    return any(marker in text for marker in markers)


def _ao79a_is_public_orkio_surface(user_payload: Optional[Dict[str, Any]]) -> bool:
    payload = user_payload or {}
    try:
        if has_admin_console_access(payload):
            return False
    except Exception:
        pass
    role = str(payload.get("role") or "").strip().lower()
    return role not in {"admin", "super_admin", "founder"}


def _ao79a_scrub_public_internal_text(value: Any) -> Any:
    if not isinstance(value, str) or not value:
        return value
    text_value = value
    replacements = (
        (r"\bChris\b", "Orkio"),
        (r"\bCris\b", "Orkio"),
        (r"\bOrion\b", "Orkio"),
        (r"\bprovider\b", "runtime"),
        (r"\btrace interno\b", "contexto interno"),
    )
    for pattern, replacement in replacements:
        text_value = re.sub(pattern, replacement, text_value, flags=re.IGNORECASE)
    return text_value


def _ao79a_scrub_public_payload(value: Any) -> Any:
    if isinstance(value, str):
        return _ao79a_scrub_public_internal_text(value)
    if isinstance(value, list):
        return [_ao79a_scrub_public_payload(item) for item in value]
    if isinstance(value, dict):
        clean: Dict[str, Any] = {}
        for key, item in value.items():
            key_s = str(key)
            if key_s in {"provider", "trace", "stack", "stack_trace", "raw_error"}:
                continue
            if key_s in {"lead_agent", "last_specialist_agent", "requested_agent", "resolved_agent"}:
                clean[key] = "Orkio"
            else:
                clean[key] = _ao79a_scrub_public_payload(item)
        return clean
    return value


def _ao79a_force_public_orkio_payload(
    payload: Dict[str, Any],
    *,
    user_payload: Optional[Dict[str, Any]],
    trace_id: str = "",
    thread_id: str = "",
    routing_source: str = "",
) -> Dict[str, Any]:
    if not isinstance(payload, dict) or not _ao79a_is_public_orkio_surface(user_payload):
        return payload
    blocked_agent = str(payload.get("agent_name") or payload.get("final_speaker") or payload.get("agent_id") or "").strip()
    clean = _ao79a_scrub_public_payload(payload)
    if not isinstance(clean, dict):
        clean = dict(payload)
    clean["agent_id"] = "orkio"
    clean["agent_name"] = "Orkio"
    clean["final_speaker"] = "Orkio"
    clean["service"] = "orkio_public_surface"
    runtime_hints = clean.get("runtime_hints") if isinstance(clean.get("runtime_hints"), dict) else {}
    routing_hints = runtime_hints.get("routing") if isinstance(runtime_hints.get("routing"), dict) else {}
    routing_hints = {
        **routing_hints,
        "routing_source": routing_hints.get("routing_source") or routing_source,
        "ao79a_public_speaker_guard": True,
        "lead_agent": "Orkio",
        "last_specialist_agent": "Orkio",
    }
    runtime_hints["routing"] = routing_hints
    clean["runtime_hints"] = runtime_hints
    if blocked_agent and blocked_agent.lower() not in {"orkio", "none"}:
        try:
            logger.warning(
                "AO79A_PUBLIC_SPEAKER_GUARD_APPLIED trace_id=%s thread_id=%s blocked_agent=%s source=%s",
                trace_id,
                thread_id,
                blocked_agent[:40],
                routing_source,
            )
        except Exception:
            pass
    return clean


class _OperationalStdoutLogger:
    """
    Logger facade for operational self-heal lifecycle events.
    Railway may classify stderr logger traffic as severity=error even when the
    message is informational. This facade sends normal lifecycle lines to stdout
    and preserves real exceptions through the canonical logger.
    """
    def _fmt(self, msg: Any, *args: Any) -> str:
        try:
            text_msg = str(msg)
            return text_msg % args if args else text_msg
        except Exception:
            return str(msg)

    def info(self, msg: Any, *args: Any, **kwargs: Any) -> None:
        print(self._fmt(msg, *args), flush=True)

    def warning(self, msg: Any, *args: Any, **kwargs: Any) -> None:
        print(self._fmt(msg, *args), flush=True)

    def error(self, msg: Any, *args: Any, **kwargs: Any) -> None:
        # Deliberately stdout: self-heal loop uses error() for normal state
        # transitions in older code paths.
        print(self._fmt(msg, *args), flush=True)

    def exception(self, msg: Any, *args: Any, **kwargs: Any) -> None:
        logger.exception(msg, *args, **kwargs)


def _self_heal_operational_logger() -> _OperationalStdoutLogger:
    return _OperationalStdoutLogger()



def _capability_execution_result_from_exception(exc: Exception, *, context: str = "") -> Dict[str, Any]:
    status_code = getattr(exc, "status_code", None)
    detail = getattr(exc, "detail", None)

    message = ""
    error_code = ""

    if isinstance(detail, dict):
        message = str(
            detail.get("message")
            or detail.get("detail")
            or detail.get("error")
            or ""
        ).strip()
        error_code = str(detail.get("error_code") or detail.get("code") or "").strip()
    else:
        message = str(detail or exc or "").strip()

    base: Dict[str, Any] = {
        "handled": True,
        "success": False,
        "provider": "runtime",
        "context": context or "capability_runtime",
    }

    if status_code == 401:
        base.update({
            "status_code": 401,
            "error_code": error_code or "AUTH_SESSION_EXPIRED",
            "message": message or "Sessão inválida ou expirada.",
        })
        return base

    if status_code == 403:
        base.update({
            "status_code": 403,
            "error_code": error_code or "AUTH_FORBIDDEN",
            "message": message or "Acesso não autorizado para esta operação.",
        })
        return base

    base.update({
        "status_code": int(status_code or 500),
        "error_code": error_code or exc.__class__.__name__,
        "message": message or "Falha interna ao avaliar capability operacional.",
    })
    return base


