def _read_audio_bytes(resp) -> bytes:
    """Normalize OpenAI SDK TTS response to raw bytes across SDK versions."""
    try:
        if resp is None:
            return b""
        # OpenAI Python SDK v1 often returns an object with .content (bytes)
        c = getattr(resp, "content", None)
        if isinstance(c, (bytes, bytearray)):
            return bytes(c)
        # Some versions expose a .read() method
        r = getattr(resp, "read", None)
        if callable(r):
            data = r()
            if isinstance(data, (bytes, bytearray)):
                return bytes(data)
        # Some responses may be directly bytes-like
        if isinstance(resp, (bytes, bytearray)):
            return bytes(resp)
        # Fallback: try to access internal raw/body attributes
        for attr in ("data", "body", "_content"):
            v = getattr(resp, attr, None)
            if isinstance(v, (bytes, bytearray)):
                return bytes(v)
    except Exception:
        pass
    raise RuntimeError(f"Unsupported TTS response type: {type(resp)!r}")
def _sanitize_mentions(msg: str) -> str:
    """Remove @mentions to prevent cross-agent impersonation and noisy prompts."""
    if not msg:
        return ""
    out = re.sub(r"@([A-Za-z0-9_\-]{2,64})", "", msg)
    out = re.sub(r"\s+", " ", out).strip()
    return out


from starlette.background import BackgroundTask
from collections import defaultdict, deque

# PATCH0113: Summit hardening — admission control + auth rate limiting (per-process)
_stream_lock = asyncio.Lock()
_active_streams = 0
_streams_per_ip = defaultdict(int)

_auth_lock = asyncio.Lock()
_auth_attempts = defaultdict(deque)  # ip -> deque[timestamps]

stream_logger = logging.getLogger("orkio.stream")

def _client_ip(request: Request) -> str:
    xff = (request.headers.get("x-forwarded-for") or "").split(",")[0].strip()
    return xff or (request.client.host if request.client else "unknown")

def _chat_stream_retry_after_seconds() -> int:
    try:
        value = int(os.getenv("CHAT_STREAM_RETRY_AFTER_SECONDS", "15") or "15")
        return max(1, value)
    except Exception:
        return 15

def _chat_stream_rate_limit_payload(
    *,
    request: Request,
    scope: str,
    retry_after: Optional[int] = None,
    org: Optional[str] = None,
    user_id: Optional[str] = None,
    trace_id: Optional[str] = None,
    thread_id: Optional[str] = None,
    agent_id: Optional[str] = None,
    model: Optional[str] = None,
    provider: Optional[str] = None,
    provider_error_code: Optional[str] = None,
    provider_error_type: Optional[str] = None,
    active_streams: Optional[int] = None,
    active_streams_for_ip: Optional[int] = None,
    max_global: Optional[int] = None,
    max_ip: Optional[int] = None,
) -> Dict[str, Any]:
    return {
        "code": "CHAT_STREAM_RATE_LIMITED",
        "message": "Estamos operando no limite seguro da plataforma. Tente novamente em instantes.",
        "rate_limit_scope": scope or "unknown",
        "retry_after": retry_after,
        "provider_error_code": provider_error_code,
        "provider_error_type": provider_error_type,
        "provider": provider or "openai",
        "org": org,
        "user_id": user_id,
        "trace_id": trace_id,
        "thread_id": thread_id,
        "agent_id": agent_id,
        "model": model,
        "active_streams": active_streams,
        "active_streams_for_ip": active_streams_for_ip,
        "max_streams_global": max_global,
        "max_streams_per_ip": max_ip,
        "path": str(getattr(request, "url", "")) if request is not None else "/api/chat/stream",
        "ip": _client_ip(request) if request is not None else "unknown",
    }

def _raise_chat_stream_rate_limited(
    *,
    request: Request,
    scope: str,
    retry_after: Optional[int] = None,
    org: Optional[str] = None,
    user_id: Optional[str] = None,
    trace_id: Optional[str] = None,
    thread_id: Optional[str] = None,
    agent_id: Optional[str] = None,
    model: Optional[str] = None,
    provider: Optional[str] = None,
    provider_error_code: Optional[str] = None,
    provider_error_type: Optional[str] = None,
    active_streams: Optional[int] = None,
    active_streams_for_ip: Optional[int] = None,
    max_global: Optional[int] = None,
    max_ip: Optional[int] = None,
) -> None:
    payload = _chat_stream_rate_limit_payload(
        request=request,
        scope=scope,
        retry_after=retry_after,
        org=org,
        user_id=user_id,
        trace_id=trace_id,
        thread_id=thread_id,
        agent_id=agent_id,
        model=model,
        provider=provider,
        provider_error_code=provider_error_code,
        provider_error_type=provider_error_type,
        active_streams=active_streams,
        active_streams_for_ip=active_streams_for_ip,
        max_global=max_global,
        max_ip=max_ip,
    )
    try:
        stream_logger.warning("CHAT_STREAM_RATE_LIMITED %s", json.dumps(payload, ensure_ascii=False, sort_keys=True))
    except Exception:
        pass
    headers = {"Retry-After": str(int(retry_after or _chat_stream_retry_after_seconds()))}
    raise HTTPException(status_code=429, detail=payload, headers=headers)

async def _stream_acquire(request: Request, *, meta: Optional[Dict[str, Any]] = None) -> None:
    global _active_streams
    ip = _client_ip(request)
    meta = dict(meta or {})
    try:
        max_global = int((os.getenv("MAX_STREAMS_PER_REPLICA") or os.getenv("MAX_STREAMS_GLOBAL", "200") or "200"))
    except Exception:
        max_global = 200
    try:
        max_ip = int(os.getenv("MAX_STREAMS_PER_IP", "10") or "10")
    except Exception:
        max_ip = 10
    retry_after = _chat_stream_retry_after_seconds()

    async with _stream_lock:
        ip_active = int(_streams_per_ip[ip] or 0)
        if max_global > 0 and _active_streams >= max_global:
            _raise_chat_stream_rate_limited(
                request=request,
                scope="global",
                retry_after=retry_after,
                org=meta.get("org"),
                user_id=meta.get("user_id"),
                trace_id=meta.get("trace_id"),
                thread_id=meta.get("thread_id"),
                agent_id=meta.get("agent_id"),
                model=meta.get("model"),
                provider=meta.get("provider") or "openai",
                active_streams=_active_streams,
                active_streams_for_ip=ip_active,
                max_global=max_global,
                max_ip=max_ip,
            )
        if max_ip > 0 and ip_active >= max_ip:
            _raise_chat_stream_rate_limited(
                request=request,
                scope="ip",
                retry_after=retry_after,
                org=meta.get("org"),
                user_id=meta.get("user_id"),
                trace_id=meta.get("trace_id"),
                thread_id=meta.get("thread_id"),
                agent_id=meta.get("agent_id"),
                model=meta.get("model"),
                provider=meta.get("provider") or "openai",
                active_streams=_active_streams,
                active_streams_for_ip=ip_active,
                max_global=max_global,
                max_ip=max_ip,
            )
        _active_streams += 1
        _streams_per_ip[ip] += 1
        try:
            stream_logger.info(json.dumps({"event":"stream_start","active_streams":_active_streams,"active_streams_for_ip":_streams_per_ip[ip],"ip":ip,"org":meta.get("org"),"user_id":meta.get("user_id"),"trace_id":meta.get("trace_id")}))
        except Exception:
            pass

async def _stream_release(request: Request) -> None:
    global _active_streams
    ip = _client_ip(request)
    async with _stream_lock:
        if _active_streams > 0:
            _active_streams -= 1
        if _streams_per_ip[ip] > 0:
            _streams_per_ip[ip] -= 1
        try:
            stream_logger.info(json.dumps({"event":"stream_end","active_streams":_active_streams,"ip":ip}))
        except Exception:
            pass

def _bg_release_stream(request: Request) -> None:
    try:
        loop = asyncio.get_event_loop()
        loop.create_task(_stream_release(request))
    except Exception:
        pass

def _release_db_session(db: Optional[Session]) -> None:
    """
    Hotfix QueuePool:
    release any checked-out connection held by a long-lived request-scoped Session
    before awaiting slow provider calls or while an SSE response stays open.
    Session.close() is safe here; SQLAlchemy will lazily checkout again on demand.
    """
    if db is None:
        return
    try:
        db.rollback()
    except Exception:
        pass
    try:
        db.close()
    except Exception:
        pass


async def _auth_rate_limit(request: Request) -> None:
    ip = _client_ip(request)
    try:
        window_s = int(os.getenv("AUTH_RATE_WINDOW_SECONDS", "60") or "60")
    except Exception:
        window_s = 60
    try:
        max_hits = int(os.getenv("AUTH_RATE_MAX_PER_IP", "300") or "300")
    except Exception:
        max_hits = 300

    now = time.time()
    async with _auth_lock:
        dq = _auth_attempts[ip]
        while dq and (now - dq[0]) > window_s:
            dq.popleft()
        if max_hits > 0 and len(dq) >= max_hits:
            raise HTTPException(status_code=429, detail="AUTH_RATE_LIMIT")
        dq.append(now)

app = FastAPI(title="Patroai API", version=APP_VERSION)




# AO-13_PTE_ADMIN_EVOLUTION_PERSISTENCE
# Proposal lifecycle persistence bridge for PTE (Plano Técnico de Evolução).
#
# Contract:
# - Orion may create proposal_only records.
# - Admin may list/detail/approve/reject.
# - No code writing, no commit, no deploy, no migration execution, no runtime patch runner.
# - Data is persisted in DB when available, with in-process fallback only as resilience.
# - Execution table is bootstrapped as inert foundation; execution remains disabled.
_ADMIN_EVOLUTION_PROPOSAL_LOCK = _threading.RLock()
_ADMIN_EVOLUTION_PROPOSALS: Dict[str, Dict[str, Any]] = {}
_ADMIN_EVOLUTION_DB_BOOT_OK = False
_ADMIN_EVOLUTION_DB_BOOT_ERROR = ""


def _admin_evolution_now() -> int:
    try:
        return now_ts()
    except Exception:
        return int(time.time())


def _admin_evolution_json_dump(value: Any) -> str:
    try:
        return json.dumps(value if value is not None else [], ensure_ascii=False)
    except Exception:
        return "[]"


def _admin_evolution_json_load(value: Any, default: Any = None) -> Any:
    if default is None:
        default = []
    try:
        if value is None:
            return default
        if isinstance(value, (list, dict)):
            return value
        raw = str(value or "").strip()
        if not raw:
            return default
        return json.loads(raw)
    except Exception:
        return default


def _admin_evolution_bool(value: Any) -> bool:
    if isinstance(value, bool):
        return value
    if value is None:
        return False
    return str(value).strip().lower() in {"1", "true", "yes", "y", "on"}


def _admin_evolution_bootstrap_db_schema() -> bool:
    """
    AO-13: idempotent DB bootstrap for proposal persistence.
    This is intentionally additive and non-destructive.
    It does not enable execution and does not alter existing governance tables.
    """
    global _ADMIN_EVOLUTION_DB_BOOT_OK, _ADMIN_EVOLUTION_DB_BOOT_ERROR
    if _ADMIN_EVOLUTION_DB_BOOT_OK:
        return True
    if _env_flag("DISABLE_ADMIN_EVOLUTION_DB_PERSISTENCE", default=False):
        _ADMIN_EVOLUTION_DB_BOOT_ERROR = "disabled_by_env"
        return False
    try:
        with ENGINE.begin() as conn:
            conn.execute(text("""
                CREATE TABLE IF NOT EXISTS admin_evolution_proposals (
                    proposal_id TEXT PRIMARY KEY,
                    org_slug TEXT NOT NULL DEFAULT 'public',
                    status TEXT NOT NULL DEFAULT 'pending_approval',
                    mode TEXT NOT NULL DEFAULT 'proposal_only',
                    created_by TEXT DEFAULT '',
                    thread_id TEXT DEFAULT '',
                    source TEXT DEFAULT '',
                    source_message TEXT DEFAULT '',
                    title TEXT DEFAULT '',
                    summary TEXT DEFAULT '',
                    risk TEXT DEFAULT 'medium',
                    target_files_json TEXT DEFAULT '[]',
                    rollback_plan TEXT DEFAULT '',
                    checklist_json TEXT DEFAULT '[]',
                    write_allowed BOOLEAN NOT NULL DEFAULT FALSE,
                    execution_allowed BOOLEAN NOT NULL DEFAULT FALSE,
                    human_approval_required BOOLEAN NOT NULL DEFAULT TRUE,
                    created_at BIGINT NOT NULL,
                    updated_at BIGINT NOT NULL,
                    approved_at BIGINT,
                    approved_by TEXT DEFAULT '',
                    rejected_at BIGINT,
                    rejected_by TEXT DEFAULT '',
                    execution_id TEXT DEFAULT '',
                    execution_status TEXT NOT NULL DEFAULT 'not_started'
                )
            """))
            # AO-16B: schema compatibility guard for existing production tables.
            # CREATE TABLE IF NOT EXISTS does not add columns to an already existing table.
            # These ALTERs are additive, idempotent and required by the AO-16 dry-run update path.
            for _stmt in (
                "ALTER TABLE admin_evolution_proposals ADD COLUMN IF NOT EXISTS execution_id TEXT DEFAULT ''",
                "ALTER TABLE admin_evolution_proposals ADD COLUMN IF NOT EXISTS execution_status TEXT NOT NULL DEFAULT 'not_started'"
            ):
                conn.execute(text(_stmt))
            conn.execute(text("""
                CREATE INDEX IF NOT EXISTS ix_admin_evolution_proposals_org_status_updated
                ON admin_evolution_proposals (org_slug, status, updated_at)
            """))
            conn.execute(text("""
                CREATE TABLE IF NOT EXISTS admin_evolution_executions (
                    execution_id TEXT PRIMARY KEY,
                    proposal_id TEXT NOT NULL,
                    org_slug TEXT NOT NULL DEFAULT 'public',
                    status TEXT NOT NULL DEFAULT 'not_started',
                    mode TEXT NOT NULL DEFAULT 'disabled_until_admin_execution_runner',
                    created_by TEXT DEFAULT '',
                    approved_by TEXT DEFAULT '',
                    risk TEXT DEFAULT 'medium',
                    rollback_plan TEXT DEFAULT '',
                    smoke_checklist_json TEXT DEFAULT '[]',
                    result_json TEXT DEFAULT '{}',
                    created_at BIGINT NOT NULL,
                    updated_at BIGINT NOT NULL,
                    started_at BIGINT,
                    finished_at BIGINT
                )
            """))
            # AO-16B: execution table compatibility guard.
            # Keep the dry-run ledger compatible with earlier readonly execution foundations.
            for _stmt in (
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS result_json TEXT DEFAULT '{}'",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS smoke_checklist_json TEXT DEFAULT '[]'",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS mode TEXT NOT NULL DEFAULT 'disabled_until_admin_execution_runner'",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS created_by TEXT DEFAULT ''",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS approved_by TEXT DEFAULT ''",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS risk TEXT DEFAULT 'medium'",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS rollback_plan TEXT DEFAULT ''",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS started_at BIGINT",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS finished_at BIGINT",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS updated_at BIGINT NOT NULL DEFAULT 0",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS created_at BIGINT NOT NULL DEFAULT 0",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS org_slug TEXT NOT NULL DEFAULT 'public'",
                "ALTER TABLE admin_evolution_executions ADD COLUMN IF NOT EXISTS status TEXT NOT NULL DEFAULT 'not_started'"
            ):
                conn.execute(text(_stmt))
            conn.execute(text("""
                CREATE INDEX IF NOT EXISTS ix_admin_evolution_executions_proposal_status_updated
                ON admin_evolution_executions (proposal_id, status, updated_at)
            """))
        _ADMIN_EVOLUTION_DB_BOOT_OK = True
        _ADMIN_EVOLUTION_DB_BOOT_ERROR = ""
        try:
            logger.info("ADMIN_EVOLUTION_SCHEMA_BOOT_OK persistence=db mode=proposal_only execution_enabled=false")
        except Exception:
            pass
        return True
    except Exception as e:
        _ADMIN_EVOLUTION_DB_BOOT_OK = False
        _ADMIN_EVOLUTION_DB_BOOT_ERROR = str(e)[:300]
        try:
            logger.exception("ADMIN_EVOLUTION_SCHEMA_BOOT_FAILED fallback=memory error=%s", _ADMIN_EVOLUTION_DB_BOOT_ERROR)
        except Exception:
            pass
        return False


@app.on_event("startup")
def _startup_admin_evolution_pte_schema():
    # Best-effort: API startup must not crash because of the proposal bridge.
    _admin_evolution_bootstrap_db_schema()


def _admin_evolution_public_row(row: Dict[str, Any]) -> Dict[str, Any]:
    safe = dict(row or {})
    if "target_files_json" in safe:
        safe["target_files"] = _admin_evolution_json_load(safe.pop("target_files_json", None), [])
    if "checklist_json" in safe:
        safe["checklist"] = _admin_evolution_json_load(safe.pop("checklist_json", None), [])
    for key in ("write_allowed", "execution_allowed", "human_approval_required"):
        if key in safe:
            safe[key] = _admin_evolution_bool(safe.get(key))
    # Never expose raw secrets or hidden runtime objects if future fields are added.
    for key in list(safe.keys()):
        if "secret" in str(key).lower() or "token" in str(key).lower():
            safe.pop(key, None)
    safe.setdefault("write_allowed", False)
    safe.setdefault("execution_allowed", False)
    safe.setdefault("human_approval_required", True)
    safe.setdefault("execution_status", "not_started")
    safe.setdefault("mode", "proposal_only")

    # AO-16 — Controlled Evolution Dry-Run metadata.
    # This is intentionally conservative: real execution remains blocked.
    status_norm = str(safe.get("status") or "").strip().lower()
    execution_status = str(safe.get("execution_status") or "not_started").strip().lower()
    can_dry_run = status_norm == "approved" and execution_status not in {"dry_run_completed", "running", "started"}
    safe["can_dry_run"] = bool(can_dry_run)
    safe["can_execute_real"] = False
    safe["execution_enabled"] = False
    if status_norm == "pending_approval":
        safe["next_state"] = "waiting_admin_decision"
    elif status_norm == "approved" and can_dry_run:
        safe["next_state"] = "approved_waiting_dry_run"
    elif status_norm == "approved" and execution_status == "dry_run_completed":
        safe["next_state"] = "dry_run_ready_real_execution_blocked"
    elif status_norm == "rejected":
        safe["next_state"] = "decision_final_rejected"
    else:
        safe["next_state"] = "readonly"
    return safe


def _admin_evolution_mapping_to_public(mapping: Any) -> Dict[str, Any]:
    try:
        row = dict(mapping or {})
    except Exception:
        row = {}
    return _admin_evolution_public_row(row)


def _admin_evolution_memory_put(row: Dict[str, Any]) -> Dict[str, Any]:
    with _ADMIN_EVOLUTION_PROPOSAL_LOCK:
        _ADMIN_EVOLUTION_PROPOSALS[str(row.get("proposal_id") or "")] = dict(row)
    return _admin_evolution_public_row(row)


def _admin_evolution_create_proposal(
    *,
    org_slug: str,
    user_id: Optional[str],
    thread_id: Optional[str],
    source_message: str,
    title: str,
    summary: str,
    risk: str,
    target_files: Optional[List[str]] = None,
    rollback_plan: str = "",
    checklist: Optional[List[str]] = None,
) -> Dict[str, Any]:
    proposal_id = "evo_" + uuid.uuid4().hex[:12]
    now = _admin_evolution_now()
    row = {
        "proposal_id": proposal_id,
        "status": "pending_approval",
        "mode": "proposal_only",
        "org_slug": str(org_slug or "public"),
        "created_by": str(user_id or ""),
        "thread_id": str(thread_id or ""),
        "source": "chat_orion_ao13",
        "source_message": str(source_message or "")[:4000],
        "title": str(title or "Orion evolution proposal").strip(),
        "summary": str(summary or "").strip(),
        "risk": str(risk or "medium").strip(),
        "target_files": list(target_files or []),
        "rollback_plan": str(rollback_plan or "").strip(),
        "checklist": list(checklist or []),
        "write_allowed": False,
        "execution_allowed": False,
        "human_approval_required": True,
        "created_at": now,
        "updated_at": now,
        "approved_at": None,
        "approved_by": "",
        "rejected_at": None,
        "rejected_by": "",
        "execution_id": "",
        "execution_status": "not_started",
    }

    if _admin_evolution_bootstrap_db_schema():
        db = SessionLocal()
        try:
            db.execute(text("""
                INSERT INTO admin_evolution_proposals (
                    proposal_id, org_slug, status, mode, created_by, thread_id, source, source_message,
                    title, summary, risk, target_files_json, rollback_plan, checklist_json,
                    write_allowed, execution_allowed, human_approval_required,
                    created_at, updated_at, approved_at, approved_by, rejected_at, rejected_by,
                    execution_id, execution_status
                ) VALUES (
                    :proposal_id, :org_slug, :status, :mode, :created_by, :thread_id, :source, :source_message,
                    :title, :summary, :risk, :target_files_json, :rollback_plan, :checklist_json,
                    :write_allowed, :execution_allowed, :human_approval_required,
                    :created_at, :updated_at, :approved_at, :approved_by, :rejected_at, :rejected_by,
                    :execution_id, :execution_status
                )
            """), {
                **{k: v for k, v in row.items() if k not in {"target_files", "checklist"}},
                "target_files_json": _admin_evolution_json_dump(row.get("target_files")),
                "checklist_json": _admin_evolution_json_dump(row.get("checklist")),
            })
            db.commit()
            try:
                logger.info(
                    "ADMIN_EVOLUTION_PROPOSAL_CREATED proposal_id=%s status=%s org=%s persistence=db execution_enabled=false",
                    proposal_id,
                    row["status"],
                    row["org_slug"],
                )
            except Exception:
                pass
            return _admin_evolution_public_row(row)
        except Exception as e:
            try:
                db.rollback()
            except Exception:
                pass
            try:
                logger.exception("ADMIN_EVOLUTION_PROPOSAL_DB_CREATE_FAILED proposal_id=%s fallback=memory error=%s", proposal_id, str(e)[:200])
            except Exception:
                pass
        finally:
            try:
                db.close()
            except Exception:
                pass

    try:
        logger.info(
            "ADMIN_EVOLUTION_PROPOSAL_CREATED proposal_id=%s status=%s org=%s persistence=memory_fallback execution_enabled=false",
            proposal_id,
            row["status"],
            row["org_slug"],
        )
    except Exception:
        pass
    return _admin_evolution_memory_put(row)


def _admin_evolution_get_proposal(proposal_id: str) -> Optional[Dict[str, Any]]:
    pid = str(proposal_id or "").strip()
    if not pid:
        return None
    if _admin_evolution_bootstrap_db_schema():
        db = SessionLocal()
        try:
            res = db.execute(text("""
                SELECT * FROM admin_evolution_proposals
                WHERE proposal_id = :proposal_id
                LIMIT 1
            """), {"proposal_id": pid}).mappings().first()
            if res:
                return _admin_evolution_mapping_to_public(res)
        except SQLAlchemyTimeoutError as e:
            try:
                logger.exception(
                    "ADMIN_EVOLUTION_PROPOSAL_DB_TIMEOUT proposal_id=%s error=%s",
                    pid,
                    str(e)[:200],
                )
            except Exception:
                pass
            raise HTTPException(status_code=503, detail="evolution_db_unavailable")
        except Exception as e:
            try:
                logger.exception("ADMIN_EVOLUTION_PROPOSAL_DB_GET_FAILED proposal_id=%s error=%s", pid, str(e)[:200])
            except Exception:
                pass
        finally:
            try:
                db.close()
            except Exception:
                pass
    with _ADMIN_EVOLUTION_PROPOSAL_LOCK:
        row = _ADMIN_EVOLUTION_PROPOSALS.get(pid)
        return _admin_evolution_public_row(row) if isinstance(row, dict) else None



def _admin_evolution_list_proposals(*, status: Optional[str] = None, org_slug: Optional[str] = None) -> List[Dict[str, Any]]:
    status_norm = str(status or "").strip().lower()
    org_norm = str(org_slug or "").strip()
    if _admin_evolution_bootstrap_db_schema():
        db = SessionLocal()
        try:
            where = []
            params: Dict[str, Any] = {}
            if status_norm:
                where.append("LOWER(status) = :status")
                params["status"] = status_norm
            if org_norm:
                where.append("org_slug = :org_slug")
                params["org_slug"] = org_norm
            sql = "SELECT * FROM admin_evolution_proposals"
            if where:
                sql += " WHERE " + " AND ".join(where)
            sql += " ORDER BY updated_at DESC LIMIT 200"
            rows = db.execute(text(sql), params).mappings().all()
            return [_admin_evolution_mapping_to_public(x) for x in rows]
        except SQLAlchemyTimeoutError as e:
            try:
                logger.exception("ADMIN_EVOLUTION_PROPOSAL_DB_LIST_TIMEOUT error=%s", str(e)[:200])
            except Exception:
                pass
            raise HTTPException(status_code=503, detail="evolution_db_unavailable")
        except Exception as e:
            try:
                logger.exception("ADMIN_EVOLUTION_PROPOSAL_DB_LIST_FAILED error=%s", str(e)[:200])
            except Exception:
                pass
        finally:
            try:
                db.close()
            except Exception:
                pass

    with _ADMIN_EVOLUTION_PROPOSAL_LOCK:
        rows = list(_ADMIN_EVOLUTION_PROPOSALS.values())
    out: List[Dict[str, Any]] = []
    for row in rows:
        if status_norm and str(row.get("status") or "").lower() != status_norm:
            continue
        if org_norm and str(row.get("org_slug") or "") != org_norm:
            continue
        out.append(_admin_evolution_public_row(row))
    out.sort(key=lambda x: int(x.get("updated_at") or 0), reverse=True)
    return out



def _admin_evolution_update_status(proposal_id: str, *, status: str, actor: str) -> Dict[str, Any]:
    pid = str(proposal_id or "").strip()
    if not pid:
        raise HTTPException(status_code=400, detail="proposal_id_required")
    status_norm = str(status or "").strip().lower()
    if status_norm not in {"approved", "rejected"}:
        raise HTTPException(status_code=400, detail="invalid_status")
    now = _admin_evolution_now()

    if _admin_evolution_bootstrap_db_schema():
        db = SessionLocal()
        try:
            row = db.execute(text("""
                SELECT * FROM admin_evolution_proposals
                WHERE proposal_id = :proposal_id
                LIMIT 1
            """), {"proposal_id": pid}).mappings().first()
            if not row:
                raise HTTPException(status_code=404, detail="proposal_not_found")
            public = _admin_evolution_mapping_to_public(row)
            if str(public.get("status") or "") not in {"pending_approval", "draft"}:
                raise HTTPException(status_code=409, detail="proposal_not_pending")

            if status_norm == "approved":
                db.execute(text("""
                    UPDATE admin_evolution_proposals
                    SET status = 'approved',
                        updated_at = :updated_at,
                        approved_at = :approved_at,
                        approved_by = :actor,
                        execution_allowed = FALSE,
                        execution_status = 'not_started'
                    WHERE proposal_id = :proposal_id
                """), {"proposal_id": pid, "updated_at": now, "approved_at": now, "actor": str(actor or "")})
            else:
                db.execute(text("""
                    UPDATE admin_evolution_proposals
                    SET status = 'rejected',
                        updated_at = :updated_at,
                        rejected_at = :rejected_at,
                        rejected_by = :actor,
                        execution_allowed = FALSE,
                        execution_status = 'not_started'
                    WHERE proposal_id = :proposal_id
                """), {"proposal_id": pid, "updated_at": now, "rejected_at": now, "actor": str(actor or "")})
            db.commit()
            fresh = db.execute(text("""
                SELECT * FROM admin_evolution_proposals
                WHERE proposal_id = :proposal_id
                LIMIT 1
            """), {"proposal_id": pid}).mappings().first()
            try:
                logger.info(
                    "ADMIN_EVOLUTION_PROPOSAL_%s proposal_id=%s actor=%s persistence=db execution_enabled=false",
                    status_norm.upper(),
                    pid,
                    actor,
                )
            except Exception:
                pass
            return _admin_evolution_mapping_to_public(fresh)
        except HTTPException:
            raise
        except Exception as e:
            try:
                db.rollback()
            except Exception:
                pass
            try:
                logger.exception("ADMIN_EVOLUTION_PROPOSAL_DB_STATUS_FAILED proposal_id=%s error=%s", pid, str(e)[:200])
            except Exception:
                pass
        finally:
            try:
                db.close()
            except Exception:
                pass

    with _ADMIN_EVOLUTION_PROPOSAL_LOCK:
        row = _ADMIN_EVOLUTION_PROPOSALS.get(pid)
        if not isinstance(row, dict):
            raise HTTPException(status_code=404, detail="proposal_not_found")
        if str(row.get("status") or "") not in {"pending_approval", "draft"}:
            raise HTTPException(status_code=409, detail="proposal_not_pending")
        row["status"] = status_norm
        row["updated_at"] = now
        if status_norm == "approved":
            row["approved_at"] = now
            row["approved_by"] = str(actor or "")
            row["execution_allowed"] = False
        else:
            row["rejected_at"] = now
            row["rejected_by"] = str(actor or "")
            row["execution_allowed"] = False
        row["execution_status"] = "not_started"
        _ADMIN_EVOLUTION_PROPOSALS[pid] = dict(row)
    try:
        logger.info("ADMIN_EVOLUTION_PROPOSAL_%s proposal_id=%s actor=%s persistence=memory_fallback", status_norm.upper(), pid, actor)
    except Exception:
        pass
    return _admin_evolution_public_row(row)


def _admin_evolution_list_executions(*, proposal_id: Optional[str] = None, status: Optional[str] = None, org_slug: Optional[str] = None) -> List[Dict[str, Any]]:
    """
    AO-13: read-only execution foundation.
    No execution is created or run by this endpoint.
    """
    if not _admin_evolution_bootstrap_db_schema():
        return []
    db = SessionLocal()
    try:
        where = []
        params: Dict[str, Any] = {}
        if proposal_id:
            where.append("proposal_id = :proposal_id")
            params["proposal_id"] = str(proposal_id)
        if status:
            where.append("LOWER(status) = :status")
            params["status"] = str(status).lower()
        if org_slug:
            where.append("org_slug = :org_slug")
            params["org_slug"] = str(org_slug)
        sql = "SELECT * FROM admin_evolution_executions"
        if where:
            sql += " WHERE " + " AND ".join(where)
        sql += " ORDER BY updated_at DESC LIMIT 200"
        rows = db.execute(text(sql), params).mappings().all()
        out = []
        for row in rows:
            d = dict(row or {})
            d["smoke_checklist"] = _admin_evolution_json_load(d.pop("smoke_checklist_json", None), [])
            d["result"] = _admin_evolution_json_load(d.pop("result_json", None), {})
            out.append(_admin_evolution_public_row(d))
        return out
    except SQLAlchemyTimeoutError as e:
        try:
            logger.exception("ADMIN_EVOLUTION_EXECUTION_DB_LIST_TIMEOUT error=%s", str(e)[:200])
        except Exception:
            pass
        raise HTTPException(status_code=503, detail="evolution_db_unavailable")
    except Exception as e:
        try:
            logger.exception("ADMIN_EVOLUTION_EXECUTION_DB_LIST_FAILED error=%s", str(e)[:200])
        except Exception:
            pass
        return []
    finally:
        try:
            db.close()
        except Exception:
            pass



# ================================
# AO-16 — Controlled Evolution Dry-Run Runner
# ================================


def _admin_evolution_default_smoke_checklist(proposal: Dict[str, Any]) -> List[str]:
    base = [
        "API sobe sem erro de import/sintaxe.",
        "/api/health retorna 200.",
        "Login/Admin continuam funcionando.",
        "Nenhuma escrita real em repo, commit, deploy ou migration é executada.",
        "Rollback plan está presente.",
    ]
    extra = []
    try:
        extra = [str(x).strip() for x in list(proposal.get("checklist") or []) if str(x).strip()]
    except Exception:
        extra = []
    out: List[str] = []
    for item in base + extra:
        if item and item not in out:
            out.append(item)
    return out[:20]


def _admin_evolution_build_diff_preview(proposal: Dict[str, Any]) -> str:
    title = str(proposal.get("title") or "Evolução governada").strip()
    summary = str(proposal.get("summary") or "").strip()
    target_files = [str(x).strip() for x in list(proposal.get("target_files") or []) if str(x).strip()]
    if not target_files:
        target_files = ["app/main.py"]
    lines = [
        "AO-16 CONTROLLED DRY-RUN DIFF PREVIEW",
        "",
        f"Proposal: {proposal.get('proposal_id') or 'n/d'}",
        f"Title: {title}",
        "",
        "This is a non-executable preview. No file was written, committed, migrated or deployed.",
        "",
        "Target files:",
    ]
    for path in target_files:
        lines.append(f"- {path}")
    lines.extend([
        "",
        "Conceptual change:",
        f"+ {summary or 'Implementar evolução governada com dry-run, smoke plan e rollback obrigatório.'}",
        "",
        "Blocked real actions:",
        "- write_repository=false",
        "- commit=false",
        "- deploy=false",
        "- migration=false",
        "- main_branch_write=false",
    ])
    return "\n".join(lines)


def _admin_evolution_create_dry_run_execution(
    proposal_id: str,
    *,
    actor: str = "",
    org_slug: Optional[str] = None,
) -> Dict[str, Any]:
    """Create a governed dry-run execution record for an approved proposal.

    AO-16 contract:
    - requires proposal.status == approved
    - creates execution_id
    - records diff_preview/smoke_plan/rollback_plan
    - does not write files
    - does not commit
    - does not deploy
    - does not run migrations
    - keeps real execution disabled
    """
    pid = str(proposal_id or "").strip()
    if not pid:
        raise HTTPException(status_code=400, detail="proposal_id_required")
    proposal = _admin_evolution_get_proposal(pid)
    if not proposal:
        raise HTTPException(status_code=404, detail="proposal_not_found")

    status_norm = str(proposal.get("status") or "").strip().lower()
    if status_norm != "approved":
        raise HTTPException(status_code=409, detail="proposal_must_be_approved_before_dry_run")

    org = str(org_slug or proposal.get("org_slug") or "public").strip() or "public"
    now = _admin_evolution_now()
    execution_id = "exec_" + uuid.uuid4().hex[:12]
    smoke_plan = _admin_evolution_default_smoke_checklist(proposal)
    rollback_plan = str(proposal.get("rollback_plan") or "").strip()
    if not rollback_plan:
        rollback_plan = "Rollback seguro: não há alteração real neste dry-run. Para voltar ao estado anterior, ignore a execução dry-run e mantenha a proposta sem execução real."

    diff_preview = _admin_evolution_build_diff_preview(proposal)
    # AO-23B_DRYRUN_STAGE_AWARE_METADATA
    ao23b_dryrun = False
    ao23_dryrun = False
    try:
        ao23b_dryrun = bool(_admin_evolution_is_frontend_push_stage(proposal))
    except Exception:
        ao23b_dryrun = False
    try:
        ao23_dryrun = bool((not ao23b_dryrun) and _admin_evolution_is_frontend_publication_stage(proposal))
    except Exception:
        ao23_dryrun = False

    if ao23b_dryrun:
        try:
            diff_preview = str(diff_preview or "").replace(
                "AO-16 CONTROLLED DRY-RUN DIFF PREVIEW",
                "AO-23B CONTROLLED FRONTEND PUSH DRY-RUN PREVIEW",
                1,
            )
        except Exception:
            pass
    elif ao23_dryrun:
        try:
            diff_preview = str(diff_preview or "").replace(
                "AO-16 CONTROLLED DRY-RUN DIFF PREVIEW",
                "AO-23 CONTROLLED FRONTEND PUBLICATION DRY-RUN PREVIEW",
                1,
            )
        except Exception:
            pass

    dryrun_smoke_note = (
        "Smoke tests planejados/simulados no AO-23B. Nenhum push, deploy, migration ou comando destrutivo foi executado."
        if ao23b_dryrun
        else "Smoke tests planejados/simulados no AO-23. Nenhum push, deploy, migration ou comando destrutivo foi executado."
        if ao23_dryrun
        else "Smoke tests planejados/simulados no AO-16. Nenhum comando destrutivo foi executado."
    )
    dryrun_next_required_stage = (
        "AO-23C governed frontend push execution only after explicit Admin confirmation and publication preflight validation"
        if ao23b_dryrun
        else "AO-23B governed frontend push/publication only after explicit Admin approval and publication preflight validation"
        if ao23_dryrun
        else "AO-17 branch/PR runner only after explicit Admin approval and executable artifact validation"
    )
    dryrun_message = (
        "AO-23B dry-run concluído. Nenhum push, deploy, migration ou alteração de API foi executada."
        if ao23b_dryrun
        else "AO-23 dry-run concluído. Nenhum push, deploy, migration ou alteração de API foi executada."
        if ao23_dryrun
        else "AO-16 dry-run concluído. Nenhuma escrita, commit, deploy ou migration foi executada."
    )

    result = {
        "ok": True,
        "proposal_id": pid,
        "execution_id": execution_id,
        "status": "dry_run_completed",
        "dry_run": True,
        "execution_enabled": False,
        "can_execute_real": False,
        "write_allowed": False,
        "commit_allowed": False,
        "deploy_allowed": False,
        "migration_allowed": False,
        "main_branch_write_allowed": False,
        "diff_preview": diff_preview,
        "smoke_plan": smoke_plan,
        "smoke_result": {
            "ok": True,
            "mode": "simulated",
            "passed": smoke_plan,
            "failed": [],
            "note": dryrun_smoke_note,
        },
        "rollback_plan": rollback_plan,
        "blocked_actions": ["write_repository", "commit", "deploy", "migration", "main_branch_write"],
        "next_required_stage": dryrun_next_required_stage,
    }

    if not _admin_evolution_bootstrap_db_schema():
        raise HTTPException(status_code=503, detail="evolution_schema_unavailable")

    db = SessionLocal()
    try:
        db.execute(text("""
            INSERT INTO admin_evolution_executions (
                execution_id, proposal_id, org_slug, status, mode, created_by, approved_by,
                risk, rollback_plan, smoke_checklist_json, result_json,
                created_at, updated_at, started_at, finished_at
            ) VALUES (
                :execution_id, :proposal_id, :org_slug, :status, :mode, :created_by, :approved_by,
                :risk, :rollback_plan, :smoke_checklist_json, :result_json,
                :created_at, :updated_at, :started_at, :finished_at
            )
        """), {
            "execution_id": execution_id,
            "proposal_id": pid,
            "org_slug": org,
            "status": "dry_run_completed",
            "mode": "controlled_dry_run_no_write",
            "created_by": str(actor or ""),
            "approved_by": str(proposal.get("approved_by") or ""),
            "risk": str(proposal.get("risk") or "medium"),
            "rollback_plan": rollback_plan,
            "smoke_checklist_json": _admin_evolution_json_dump(smoke_plan),
            "result_json": _admin_evolution_json_dump(result),
            "created_at": now,
            "updated_at": now,
            "started_at": now,
            "finished_at": now,
        })
        db.execute(text("""
            UPDATE admin_evolution_proposals
            SET execution_id = :execution_id,
                execution_status = 'dry_run_completed',
                execution_allowed = FALSE,
                updated_at = :updated_at
            WHERE proposal_id = :proposal_id
        """), {
            "proposal_id": pid,
            "execution_id": execution_id,
            "updated_at": now,
        })
        db.commit()
        try:
            logger.info(
                "ADMIN_EVOLUTION_DRY_RUN_COMPLETED proposal_id=%s execution_id=%s actor=%s execution_enabled=false write_allowed=false",
                pid,
                execution_id,
                actor,
            )
        except Exception:
            pass
    except HTTPException:
        raise
    except SQLAlchemyTimeoutError as e:
        try:
            db.rollback()
        except Exception:
            pass
        try:
            logger.exception("ADMIN_EVOLUTION_DRY_RUN_DB_TIMEOUT proposal_id=%s error=%s", pid, str(e)[:240])
        except Exception:
            pass
        raise HTTPException(status_code=503, detail="evolution_db_unavailable")
    except Exception as e:
        try:
            db.rollback()
        except Exception:
            pass
        try:
            logger.exception("ADMIN_EVOLUTION_DRY_RUN_FAILED proposal_id=%s error=%s", pid, str(e)[:240])
        except Exception:
            pass
        raise HTTPException(status_code=500, detail="dry_run_creation_failed")
    finally:
        try:
            db.close()
        except Exception:
            pass

    try:
        fresh = _admin_evolution_get_proposal(pid) or proposal
    except HTTPException as e:
        if getattr(e, "status_code", None) == 503:
            try:
                logger.exception("ADMIN_EVOLUTION_DRY_RUN_FRESH_LOOKUP_UNAVAILABLE proposal_id=%s", pid)
            except Exception:
                pass
            fresh = proposal
        else:
            raise
    return {
        "ok": True,
        "mode": "controlled_dry_run",
        "proposal_id": pid,
        "proposal_status": fresh.get("status") or "approved",
        "execution_id": execution_id,
        "execution_status": "dry_run_completed",
        "execution_enabled": False,
        "can_execute_real": False,
        "write_allowed": False,
        "dry_run": True,
        "proposal": fresh,
        "result": result,
        "diff_preview": diff_preview,
        "smoke_plan": smoke_plan,
        "smoke_result": result["smoke_result"],
        "rollback_plan": rollback_plan,
        "message": dryrun_message,
    }


