@app.get("/api/internal/self-evolution-health")
def self_evolution_health():
    return {
        "status": "ok",
        "proposal": True,
        "approval": True,
        "execution": True,
        "github_pr": True,
    }


def _route_methods_for(path: str) -> List[str]:
    methods = set()
    try:
        for route in app.routes:
            if getattr(route, "path", None) == path:
                for m in (getattr(route, "methods", None) or []):
                    methods.add(str(m).upper())
    except Exception:
        pass
    return sorted(methods)


def _safe_build_fingerprint() -> str:
    """
    Fingerprint leve para troubleshooting de runtime/deploy.
    """
    try:
        here = os.path.dirname(__file__)
        main_file = os.path.join(here, "main.py")
        if os.path.exists(main_file):
            with open(main_file, "rb") as f:
                raw = f.read()
            return hashlib.sha256(raw).hexdigest()[:12]
    except Exception:
        pass
    return "unknown"


@app.on_event("startup")
def _startup_runtime_fingerprint():
    """
    P0 HOTFIX:
    Loga patch e rotas críticas carregadas para detectar drift entre ZIP e runtime.
    """
    try:
        logger.info(
            "ORKIO_API_STARTUP patch=%s version=%s build=%s sentinel=%s feature=%s behavior=%s",
            patch_id(),
            APP_VERSION,
            _safe_build_fingerprint(),
            PATCH_SENTINEL,
            PATCH_FEATURE,
            PATCH_EXPECTED_BEHAVIOR,
        )
        logger.info(
            "ORKIO_API_ROUTES register=%s validate_access_code=%s summit_session_start=%s audio_transcriptions=%s realtime_start=%s realtime_end=%s",
            _route_methods_for("/api/auth/register"),
            _route_methods_for("/api/auth/validate-access-code"),
            _route_methods_for("/api/summit/sessions/start"),
            _route_methods_for("/api/audio/transcriptions"),
            _route_methods_for("/api/realtime/start"),
            _route_methods_for("/api/realtime/end"),
        )
    except Exception as e:
        try:
            logger.exception("startup runtime fingerprint failed: %s", e)
        except Exception:
            pass




def _bootstrap_orkio_governance_state() -> Dict[str, Any]:
    identity = load_active_identity()
    constitution = load_constitution()
    permissions = load_permissions()
    runtime_registry = get_capability_registry()
    capabilities = load_runtime_governed_capabilities(runtime_registry)
    memory = bootstrap_live_memory(
        identity=identity,
        constitution=constitution,
        permissions=permissions,
        capabilities=capabilities,
    )
    health = build_governance_health(
        identity=identity,
        constitution=constitution,
        permissions=permissions,
        capabilities=capabilities,
        memory=memory,
    )
    return {
        "identity": identity,
        "constitution": constitution,
        "permissions": permissions,
        "capabilities": capabilities,
        "memory": memory,
        "health": health,
    }


@app.on_event("startup")
def _startup_orkio_governance_bootstrap():
    try:
        boot = _bootstrap_orkio_governance_state()
        app.state.orkio_identity = boot["identity"]
        app.state.orkio_constitution = boot["constitution"]
        app.state.orkio_permissions = boot["permissions"]
        app.state.orkio_capabilities = boot["capabilities"]
        app.state.orkio_memory = boot["memory"]
        app.state.governance_ready = bool(boot["health"].get("governance_ready"))
        app.state.safe_mode = bool(boot["health"].get("safe_mode"))
        app.state.safe_mode_reason = str(boot["health"].get("safe_mode_reason") or "")
        logger.info(
            "ORKIO_GOVERNANCE_READY ready=%s safe_mode=%s reason=%s identity=%s constitution=%s capabilities=%s",
            app.state.governance_ready,
            app.state.safe_mode,
            app.state.safe_mode_reason,
            boot["health"].get("identity_version"),
            boot["health"].get("constitution_version"),
            len(boot["capabilities"] or {}),
        )
    except Exception as exc:
        app.state.orkio_identity = {}
        app.state.orkio_constitution = {}
        app.state.orkio_permissions = {}
        app.state.orkio_capabilities = {}
        app.state.orkio_memory = {}
        app.state.governance_ready = False
        app.state.safe_mode = True
        app.state.safe_mode_reason = "governance_bootstrap_failed"
        logger.exception("ORKIO_SAFE_MODE_ENABLED reason=governance_bootstrap_failed error=%s", exc)


@app.get("/api/auth/validate-access-code")
def validate_access_code(
    code: str,
    email: Optional[str] = None,
    tenant: Optional[str] = None,
    x_org_slug: Optional[str] = Header(default=None),
    db: Session = Depends(get_db),
):
    org = (get_org(x_org_slug) if x_org_slug else (tenant or default_tenant())).strip()
    sc = _validate_access_code_no_consume(db, org, code)
    if not sc:
        raise HTTPException(status_code=403, detail="Invalid, expired or exhausted access code.")
    return {
        "ok": True,
        "valid": True,
        "label": sc.label,
        "source": sc.source,
        "org": org,
    }


