@app.middleware("http")
async def audit_middleware(request: Request, call_next):
    start = time.time()
    path = request.url.path

    STREAMING_PATHS = {
        "/api/chat/stream",
        "/api/realtime",
        "/api/audio_transcriptions",
    }
    DB_HOT_PATHS = {
        "/api/auth/login",
        "/api/auth/register",
        "/api/auth/otp/verify",
        "/api/auth/heartbeat",
        "/api/agents/capabilities",
    }

    # Skip noisy, streaming and login-critical endpoints.
    # WAR_ROOM_AUTH_DB_POOL_V1: these routes must not spend an extra DB checkout
    # in the audit middleware while auth/console recovery is being validated.
    if path.startswith("/api/health") or path in ("/", "/health") or path in STREAMING_PATHS or path in DB_HOT_PATHS:
        return await call_next(request)

    try:
        response = await call_next(request)
    except Exception as exc:
        # RTB09_HF5_1 — sanitize audit middleware runtime fallback.
        # Keep the internal exception in logs only; never expose str(exc), path,
        # stack, version, architecture, or product codename in the public body.
        try:
            logger.exception("AUDIT_MIDDLEWARE_RUNTIME_ERROR")
        except Exception:
            pass

        rid = ensure_request_id(request)
        duration_ms = int(max((time.time() - start) * 1000, 0))
        safe_response = JSONResponse(
            status_code=500,
            content={
                "detail": "Internal server error",
                "request_id": rid,
            },
        )
        safe_response.headers["x-request-id"] = rid
        safe_response.headers["x-patroai-duration-ms"] = str(duration_ms)
        safe_response.headers["access-control-expose-headers"] = "x-request-id, x-patroai-duration-ms"
        return safe_response

    # Best-effort audit (never block the response)
    try:
        audit_db_enabled = _env_flag("AUDIT_DB_ENABLED", default=False)
        if audit_db_enabled and path.startswith("/api/") and SessionLocal is not None:
            latency_ms = int((time.time() - start) * 1000)
            status_code = int(getattr(response, "status_code", 0) or 0)
            rid = ensure_request_id(request)
            org = get_org(request.headers.get("x-org-slug"))
            uid = None
            auth = request.headers.get("authorization")
            if auth:
                try:
                    token = auth.split(" ", 1)[1] if " " in auth else auth
                    payload = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGORITHM])
                    uid = payload.get("sub")
                except Exception:
                    uid = None
            meta = {"method": request.method}
            _db = SessionLocal()
            try:
                audit(db=_db, org_slug=org, user_id=uid, action="http.request", request_id=rid, path=path, status_code=status_code, latency_ms=latency_ms, meta=meta)
            finally:
                _db.close()
    except Exception:
        pass
    return response

