def _verify_turnstile(token: Optional[str], ip: str = "unknown") -> bool:
    """Verify Cloudflare Turnstile token. Returns True if valid or if Turnstile is not configured."""
    if not TURNSTILE_SECRET:
        return True  # Turnstile not configured, skip
    if not token:
        return False
    try:
        data = json.dumps({"secret": TURNSTILE_SECRET, "response": token, "remoteip": ip}).encode()
        req = _urllib_request.Request(
            "https://challenges.cloudflare.com/turnstile/v0/siteverify",
            data=data, headers={"Content-Type": "application/json"}, method="POST"
        )
        ctx = _ssl.create_default_context()
        with _urllib_request.urlopen(req, context=ctx, timeout=5) as resp:
            result = json.loads(resp.read().decode())
            return result.get("success", False)
    except Exception:
        logger.exception("TURNSTILE_VERIFY_FAILED")
        return False  # fail-closed: if Turnstile is down, block registration

def _validate_access_code(db: Session, org: str, code: str) -> Optional[SignupCode]:
    """Validate and consume an access code with row-level locking to prevent race conditions."""
    normalized = (code or "").strip().upper()
    if not normalized:
        return None
    code_hash = hashlib.sha256(normalized.encode()).hexdigest()
    sc = db.execute(
        select(SignupCode)
        .where(
            SignupCode.org_slug == org,
            SignupCode.code_hash == code_hash,
            SignupCode.active == True,
        )
        .with_for_update()
    ).scalar_one_or_none()
    if not sc:
        return None
    if sc.expires_at and sc.expires_at < now_ts():
        return None
    current_used = int(sc.used_count or 0)
    max_uses = int(sc.max_uses or 0)
    if max_uses > 0 and current_used >= max_uses:
        return None
    sc.used_count = current_used + 1
    db.add(sc)
    return sc

def _rate_limit_check(lock, calls_dict, key, max_per_min, window=60):
    """Generic in-memory rate limiter. Returns True if allowed, False if over limit."""
    now = time.time()
    with lock:
        calls = calls_dict.get(key, [])
        calls = [t for t in calls if now - t < window]
        if len(calls) >= max_per_min:
            calls_dict[key] = calls
            return False
        calls.append(now)
        calls_dict[key] = calls
        # Eviction
        if len(calls_dict) > 1000:
            stale = [k for k, ts in calls_dict.items() if not ts or (now - max(ts)) > 120]
            for k in stale:
                del calls_dict[k]
        return True

def _create_user_session(db: Session, user_id: str, org: str, ip: str = "unknown", code_label: str = None, tier: str = None):
    """Create a user_session record for presence tracking."""
    try:
        ts = now_ts()
        sess = UserSession(
            id=new_id(), user_id=user_id, org_slug=org,
            login_at=ts, last_seen_at=ts,
            source_code_label=code_label, usage_tier=tier, ip_address=ip,
        )
        db.add(sess)
        db.commit()
        return sess.id
    except Exception:
        logger.exception("USER_SESSION_CREATE_FAILED")
        try: db.rollback()
        except: pass
        return None

def _send_otp_email(to_email: str, otp_code: str):
    """Send OTP code via Resend first, then SMTP fallback. Best-effort, never blocks auth flow."""
    email_ref = _ao79a_email_ref(to_email)
    subject = f"Orkio — Seu código de verificação: {otp_code}"
    text_body = (
        "Seu código de verificação do Orkio é:\n\n"
        f"{otp_code}\n\n"
        "Válido por 10 minutos. Não compartilhe este código."
    )
    html = f"""
    <div style="font-family:system-ui;max-width:480px;margin:0 auto;padding:24px">
        <h2 style="color:#111">Orkio</h2>
        <p>Seu código de verificação é:</p>
        <div style="font-size:32px;font-weight:bold;letter-spacing:8px;padding:16px;background:#f5f5f5;border-radius:8px;text-align:center">{otp_code}</div>
        <p style="color:#666;font-size:13px;margin-top:16px">Válido por 10 minutos. Não compartilhe este código.</p>
    </div>
    """

    # Preferred path: Resend
    try:
        if _clean_env(RESEND_API_KEY):
            ok = _send_resend_email(to_email, subject, text_body, html_body=html)
            if ok:
                logger.info("OTP_EMAIL_SENT provider=resend email_ref=%s", email_ref)
                return True
            logger.warning("OTP_EMAIL_RESEND_FAILED_FALLING_BACK_SMTP email_ref=%s", email_ref)
    except Exception:
        logger.exception("OTP_EMAIL_RESEND_EXCEPTION email_ref=%s", email_ref)

    # Fallback path: SMTP
    smtp_host = _clean_env(os.getenv("SMTP_HOST", ""), default="")
    smtp_port_raw = _clean_env(os.getenv("SMTP_PORT", "587"), default="587")
    smtp_user = _clean_env(os.getenv("SMTP_USER", ""), default="")
    smtp_pass = _clean_env(os.getenv("SMTP_PASS", ""), default="")
    smtp_from = _clean_env(os.getenv("SMTP_FROM", smtp_user), default=smtp_user)

    try:
        smtp_port = int(smtp_port_raw or "587")
    except Exception:
        smtp_port = 587

    if not smtp_host or not smtp_user:
        logger.warning("OTP_EMAIL_SEND_SKIPPED missing_email_provider_config email_ref=%s", email_ref)
        return False

    try:
        msg = MIMEMultipart("alternative")
        msg["Subject"] = subject
        msg["From"] = smtp_from
        msg["To"] = to_email
        msg.attach(MIMEText(text_body, "plain", "utf-8"))
        msg.attach(MIMEText(html, "html", "utf-8"))

        with smtplib.SMTP(smtp_host, smtp_port, timeout=10) as s:
            s.starttls()
            s.login(smtp_user, smtp_pass)
            s.sendmail(smtp_from, [to_email], msg.as_string())

        logger.info("OTP_EMAIL_SENT provider=smtp email_ref=%s", email_ref)
        return True
    except Exception:
        logger.exception("OTP_EMAIL_SEND_FAILED provider=smtp email_ref=%s", email_ref)
        return False

def _get_feature_flag(db: Session, org: str, key: str) -> Optional[str]:
    """Get feature flag value. Returns None if not set."""
    try:
        ff = db.execute(
            select(FeatureFlag).where(FeatureFlag.org_slug == org, FeatureFlag.flag_key == key)
        ).scalar_one_or_none()
        return ff.flag_value if ff else None
    except Exception:
        logger.exception("FEATURE_FLAG_READ_FAILED org=%s key=%s", org, key)
        return None


def _is_summit_auto_approved_code(raw_access_code: Optional[str], signup_code_label: Optional[str], signup_source: Optional[str]) -> bool:
    """
    Summit access code EFATAH777 must auto-approve without manual admin approval.
    Compatible with legacy states where the signal may live in label/source.
    """
    raw = (raw_access_code or "").strip().lower()
    label = (signup_code_label or "").strip().lower()
    source = (signup_source or "").strip().lower()
    if raw == "efatah777":
        return True
    if label == "efatah777":
        return True
    if source == "investor":
        return True

    # ORKIO_AO58_AMCHAM_RS_PARTNER_ACCESS_V1
    if raw == "amchamrsorkio":
        return True
    if label == "amcham_rs_orkio_only":
        return True
    if source == "amcham_rs_partner":
        return True

    return False

# AO20K-HF6A_TESTER_BILLING_BYPASS
def _tester_billing_bypass_plan_codes() -> set:
    raw = _clean_env(os.getenv("TESTER_BILLING_BYPASS_PLAN_CODES", "founder_access"), default="founder_access")
    return {part.strip().lower() for part in raw.split(",") if part.strip()}


def _tester_billing_bypass_emails() -> set:
    raw = _clean_env(os.getenv("TESTER_BILLING_BYPASS_EMAILS", ""), default="")
    return {part.strip().lower() for part in raw.split(",") if part.strip()}


def _tester_billing_bypass_env_enabled() -> bool:
    raw = _clean_env(os.getenv("TESTER_BILLING_BYPASS_ENABLED", ""), default="")
    return raw.strip().lower() in {"1", "true", "yes", "on"}


def _tester_billing_bypass_allowed_for_user(u: Optional[User], item_code: Optional[str]) -> bool:
    code = str(item_code or "").strip().lower()
    if code not in _tester_billing_bypass_plan_codes():
        return False
    if not u:
        return False
    if _is_summit_auto_approved_code(None, getattr(u, "signup_code_label", None), getattr(u, "signup_source", None)):
        return True
    email = str(getattr(u, "email", "") or "").strip().lower()
    return bool(_tester_billing_bypass_env_enabled() and email in _tester_billing_bypass_emails())


@app.post("/api/auth/register", response_model=TokenOut)
def register(inp: RegisterIn, request: Request = None, x_org_slug: Optional[str] = Header(default=None), db: Session = Depends(get_db)):
    ip = (request.client.host if request and request.client else "unknown")
    org = (get_org(x_org_slug) if x_org_slug else (inp.tenant or default_tenant())).strip()
    email = inp.email.lower().strip()
    request_id = _ao79a_request_id(request, "register")
    email_ref = _ao79a_email_ref(email)
    is_admin_email = email in admin_emails()

    try:
        logger.warning(
            "REGISTER_ATTEMPT request_id=%s org=%s email_ref=%s summit_mode=%s access_code_present=%s accept_terms=%s",
            request_id,
            org,
            email_ref,
            SUMMIT_MODE,
            bool(inp.access_code),
            bool(inp.accept_terms),
        )
    except Exception:
        pass

    if not _rate_limit_check(_rl_register_lock, _rl_register_calls, ip, _REGISTER_MAX_PER_MINUTE):
        raise HTTPException(status_code=429, detail="Muitas tentativas de registro. Aguarde 1 minuto.")

    signup_code_label = None
    signup_source = None
    usage_tier = "summit_investor"
    product_scope = "full"
    is_amcham_partner_access = False

    if SUMMIT_MODE and not is_admin_email:
        if not inp.access_code:
            logger.warning("REGISTER_DENIED reason=missing_code ip=%s org=%s", ip, org)
            raise HTTPException(status_code=403, detail="Access code is required in Summit mode.")

        normalized_input_code = (inp.access_code or "").strip().lower()
        allowed_partner_codes = {"efatah777", "amchamrsorkio"}
        if normalized_input_code not in allowed_partner_codes:
            logger.warning("REGISTER_DENIED reason=unsupported_partner_code ip=%s org=%s", ip, org)
            raise HTTPException(status_code=403, detail="Access code is not enabled for this build.")

        sc = _validate_access_code(db, org, inp.access_code)
        if not sc:
            logger.warning("REGISTER_DENIED reason=invalid_code ip=%s org=%s", ip, org)
            raise HTTPException(status_code=403, detail="Invalid, expired or exhausted access code.")

        signup_code_label = sc.label
        signup_source = sc.source

        if now_ts() > int(SUMMIT_EXPIRES_AT):
            raise HTTPException(status_code=403, detail="Summit access window has ended.")

        normalized_signup_source = (sc.source or "").strip().lower()
        normalized_signup_label = (sc.label or "").strip().lower()

        is_investor_access = normalized_signup_source == "investor" or normalized_signup_label == "efatah777"
        is_amcham_partner_access = (
            normalized_input_code == "amchamrsorkio"
            or normalized_signup_source == "amcham_rs_partner"
            or normalized_signup_label == "amcham_rs_orkio_only"
        )

        if not (is_investor_access or is_amcham_partner_access):
            logger.warning("REGISTER_DENIED reason=unsupported_signup_source ip=%s org=%s", ip, org)
            raise HTTPException(status_code=403, detail="Access code is not enabled for this build.")

        if is_amcham_partner_access:
            usage_tier = "partner_access"
            product_scope = "orkio_only"
            signup_code_label = "amcham_rs_orkio_only"
            signup_source = "amcham_rs_partner"
        else:
            usage_tier = "summit_investor"
            product_scope = "full"

    elif SUMMIT_MODE and is_admin_email:
        usage_tier = "summit_admin"
        product_scope = "full"

    elif inp.access_code:
        sc = _validate_access_code(db, org, inp.access_code)
        if sc:
            signup_code_label = sc.label
            signup_source = sc.source

    if SUMMIT_MODE and not inp.accept_terms:
        logger.warning("REGISTER_DENIED reason=terms_not_accepted ip=%s org=%s", ip, org)
        raise HTTPException(status_code=400, detail="Você precisa aceitar os Termos de Uso para continuar.")

    role = "admin" if is_admin_email else "user"

    existing = db.execute(select(User).where(User.org_slug == org, User.email == email)).scalar_one_or_none()
    if existing:
        raise HTTPException(status_code=409, detail="Email already registered")

    tester_billing_bypass_access = _is_summit_auto_approved_code(inp.access_code, signup_code_label, signup_source)
    if tester_billing_bypass_access and not is_admin_email and not is_amcham_partner_access:
        usage_tier = usage_tier or "summit_investor"
        product_scope = "full"

    approved_at_value = now_ts() if (is_admin_email or (SUMMIT_MODE and not is_admin_email) or tester_billing_bypass_access) else None

    salt = new_salt()
    pw_hash = pbkdf2_hash(inp.password, salt)

    u = User(
        id=new_id(),
        org_slug=org,
        email=email,
        name=inp.name.strip(),
        role=role,
        salt=salt,
        pw_hash=pw_hash,
        created_at=now_ts(),
        approved_at=approved_at_value,
        signup_code_label=signup_code_label,
        signup_source=signup_source or ("investor" if SUMMIT_MODE and not is_admin_email else None),
        usage_tier=usage_tier,
        terms_accepted_at=(now_ts() if inp.accept_terms else None),
        terms_version=(TERMS_VERSION if inp.accept_terms else None),
        marketing_consent=inp.marketing_consent,
        onboarding_completed=False,
    )

    try:
        if SUMMIT_MODE and not is_admin_email:
            if is_amcham_partner_access:
                # ORKIO_AO58_AMCHAM_RS_PARTNER_ACCESS_V1
                usage_tier = "partner_access"
                signup_source = "amcham_rs_partner"
                signup_code_label = "amcham_rs_orkio_only"
                product_scope = "orkio_only"
            else:
                # HARD ENFORCEMENT FOR INVESTOR-ONLY SUMMIT
                usage_tier = "summit_investor"
                signup_source = "investor" if not signup_source else signup_source
                product_scope = "full"

            if hasattr(u, "usage_tier"):
                setattr(u, "usage_tier", usage_tier)
            if hasattr(u, "signup_source"):
                setattr(u, "signup_source", signup_source)
            if hasattr(u, "signup_code_label"):
                setattr(u, "signup_code_label", signup_code_label)
            if hasattr(u, "product_scope"):
                setattr(u, "product_scope", product_scope)

        if hasattr(u, "approved_via") and SUMMIT_MODE and not is_admin_email:
            setattr(u, "approved_via", "access_code")
        if hasattr(u, "access_code_used") and SUMMIT_MODE and not is_admin_email:
            setattr(u, "access_code_used", (inp.access_code or "").strip().upper())
        if hasattr(u, "status"):
            setattr(u, "status", "active")
        if hasattr(u, "product_scope") and getattr(u, "product_scope", None) in (None, "", "basic", "orkio"):
            setattr(u, "product_scope", product_scope)
    except Exception:
        logger.exception("REGISTER_INVESTOR_METADATA_FAILED request_id=%s email_ref=%s", request_id, email_ref)

    db.add(u)
    db.commit()

    if inp.accept_terms:
        try:
            db.add(TermsAcceptance(
                id=new_id(),
                user_id=u.id,
                terms_version=TERMS_VERSION,
                accepted_at=now_ts(),
                ip_address=ip,
                user_agent=(request.headers.get("user-agent", "") if request else None),
            ))
            db.commit()
        except Exception:
            logger.exception("TERMS_ACCEPTANCE_RECORD_FAILED")

    if inp.marketing_consent:
        try:
            db.add(MarketingConsent(
                id=new_id(),
                user_id=u.id,
                channel="email",
                opt_in_date=now_ts(),
                ip=ip,
                source="register",
                created_at=now_ts(),
            ))
            db.commit()
        except Exception:
            logger.exception("MARKETING_CONSENT_RECORD_FAILED")

    try:
        audit(
            db,
            org,
            u.id,
            "user.register",
            request_id=request_id,
            path="/api/auth/register",
            status_code=200,
            latency_ms=0,
            meta={
                "email_ref": email_ref,
                "signup_code_label": signup_code_label,
                "signup_source": getattr(u, "signup_source", None),
                "usage_tier": getattr(u, "usage_tier", usage_tier),
                "product_scope": getattr(u, "product_scope", product_scope),
                "summit_mode": SUMMIT_MODE,
                "investor_only": not is_amcham_partner_access,
                "amcham_partner_access": bool(is_amcham_partner_access),
            },
        )
    except Exception:
        pass

    try:
        if _ensure_admin_user_state(u):
            db.add(u)
            db.commit()
    except Exception:
        logger.exception("ADMIN_SYNC_FAILED register user_id=%s", getattr(u, "id", None))

    response = _build_fresh_auth_response(db, org, u.id, usage_tier=usage_tier, auth_context="register")

    if response.get("pending_approval"):
        response["message"] = "Conta criada com sucesso. Seu acesso ao app será liberado após aprovação manual."
        return response

    _create_user_session(db, u.id, org, ip, signup_code_label, usage_tier)
    try:
        logger.warning("REGISTER_SUCCESS request_id=%s org=%s email_ref=%s usage_tier=%s", request_id, org, email_ref, usage_tier)
    except Exception:
        pass

    response["message"] = "Conta criada com sucesso."
    response["authenticated"] = True
    response["redirect_to"] = "/app"
    return response

@app.post("/api/auth/login")
def login(inp: LoginIn, x_org_slug: Optional[str] = Header(default=None), db: Session = Depends(get_db), request: Request = None):
    login_started_at = time.perf_counter()
    ip = (request.client.host if request and request.client else "unknown")
    request_id = _ao79a_request_id(request, "login")
    # F-10 FIX: rate limit brute-force
    if not _rate_limit_check(_login_rl_lock, _login_rl_calls, ip, _LOGIN_MAX_PER_MINUTE):
        raise HTTPException(status_code=429, detail="Muitas tentativas de login. Aguarde 1 minuto.")

    org = (get_org(x_org_slug) if x_org_slug else (inp.tenant or default_tenant())).strip()
    email = inp.email.lower().strip()
    email_ref = _ao79a_email_ref(email)
    try:
        u = db.execute(select(User).where(User.org_slug == org, User.email == email)).scalar_one_or_none()
    except Exception as e:
        try:
            db.rollback()
        except Exception:
            pass
        elapsed_ms = int((time.perf_counter() - login_started_at) * 1000)
        if _ao79a_is_db_infra_error(e):
            logger.exception(
                "LOGIN_DB_INFRA_ERROR request_id=%s org=%s email_ref=%s status_code=503 elapsed_ms=%s db_pool=%s error=%s",
                request_id,
                org,
                email_ref,
                elapsed_ms,
                _ao79a_db_pool_status(),
                e.__class__.__name__,
            )
            raise HTTPException(status_code=503, detail="Autenticacao temporariamente indisponivel. Tente novamente em instantes.")
        logger.exception(
            "LOGIN_DB_QUERY_FAILED request_id=%s org=%s email_ref=%s status_code=500 elapsed_ms=%s error=%s",
            request_id,
            org,
            email_ref,
            elapsed_ms,
            e.__class__.__name__,
        )
        raise HTTPException(status_code=500, detail="Falha temporaria no login. Tente novamente.")
    if not u or not verify_password(inp.password, u.salt, u.pw_hash):
        logger.info(
            "LOGIN_INVALID_CREDENTIALS request_id=%s org=%s email_ref=%s status_code=401 elapsed_ms=%s",
            request_id,
            org,
            email_ref,
            int((time.perf_counter() - login_started_at) * 1000),
        )
        raise HTTPException(status_code=401, detail="Invalid credentials")

    logger.info(
        "LOGIN_PASSWORD_OK request_id=%s email_ref=%s org=%s status_code=200 elapsed_ms=%s db_pool=%s",
        request_id,
        email_ref,
        org,
        int((time.perf_counter() - login_started_at) * 1000),
        _ao79a_db_pool_status(),
    )

    # PATCH0216C: structural admin sync (role + approved_at) for configured emails
    try:
        if _ensure_admin_user_state(u):
            db.add(u)
            db.commit()
    except Exception:
        logger.exception("ADMIN_ELEVATE_FAILED")


    usage_tier = getattr(u, "usage_tier", "summit_standard") or "summit_standard"

    # Summit access window enforcement (standard users only)
    if _summit_access_expired({"role": u.role, "usage_tier": usage_tier}):
        raise HTTPException(status_code=403, detail="Acesso ao Summit encerrado.")

    # Summit 2FA: password + OTP (OTP is issued only after password verification)
    # WAR_ROOM_AUTH_DB_POOL_V1:
    # OTP must be explicitly enabled only after the e-mail provider is confirmed.
    # Production default cannot require OTP, otherwise users can be locked out when
    # the mail provider is not configured or delivery is degraded.
    require_otp = _env_flag("SUMMIT_REQUIRE_OTP", default=False)
    otp_for_admins = (os.getenv("SUMMIT_OTP_FOR_ADMINS", "false").lower() in ("1", "true", "yes"))
    if require_otp and (u.role != "admin" or otp_for_admins):
        logger.warning(
            "OTP_BRANCH_ENTERED request_id=%s email_ref=%s role=%s summit_mode=%s require_otp=%s otp_for_admins=%s",
            request_id,
            email_ref,
            u.role,
            SUMMIT_MODE,
            require_otp,
            otp_for_admins,
        )
        try:
            import random
            otp_plain = f"{random.randint(0, 999999):06d}"
            otp_hash = hashlib.sha256(otp_plain.encode()).hexdigest()
            expires = now_ts() + 600  # 10 minutes

            # Invalidate old OTPs
            try:
                db.execute(text("UPDATE otp_codes SET verified = TRUE WHERE user_id = :uid AND verified = FALSE"), {"uid": u.id})
                db.commit()
            except Exception:
                try:
                    db.rollback()
                except Exception:
                    pass

            db.add(OtpCode(
                id=new_id(), user_id=u.id, code_hash=otp_hash,
                expires_at=expires, created_at=now_ts(),
            ))
            db.commit()

            # Send email (fail-closed by default so the UI does not ask for a code that was never delivered)
            otp_send_started_at = time.perf_counter()
            logger.warning(
                "OTP_SEND_ATTEMPT request_id=%s email_ref=%s summit_mode=%s require_otp=%s elapsed_ms=%s",
                request_id,
                email_ref,
                SUMMIT_MODE,
                os.getenv("SUMMIT_REQUIRE_OTP"),
                int((otp_send_started_at - login_started_at) * 1000),
            )

            sent = False
            try:
                sent = _send_otp_email(email, otp_plain)
            except Exception as send_exc:
                logger.exception("OTP_SEND_EXCEPTION request_id=%s email_ref=%s error=%s", request_id, email_ref, send_exc.__class__.__name__)

            logger.warning(
                "OTP_SEND_RESULT request_id=%s email_ref=%s sent=%s otp_send_ms=%s total_login_ms=%s",
                request_id,
                email_ref,
                sent,
                int((time.perf_counter() - otp_send_started_at) * 1000),
                int((time.perf_counter() - login_started_at) * 1000),
            )

            if not sent and os.getenv("SUMMIT_OTP_FAIL_OPEN", "false").lower() not in ("1", "true", "yes"):
                logger.error("OTP_FAIL_CLOSED_TRIGGERED request_id=%s email_ref=%s", request_id, email_ref)
                raise HTTPException(status_code=500, detail="Falha ao enviar código de verificação. Tente novamente.")

            try:
                audit(db, org, u.id, "login.otp_issued", request_id=request_id, path="/api/auth/login",
                      status_code=200, latency_ms=0, meta={"email_ref": email_ref, "summit_mode": True})
            except Exception:
                pass
        except Exception:
            logger.exception("LOGIN_OTP_ISSUE_FAILED")
            # Fail-open: allow login without OTP only if explicitly configured
            if os.getenv("SUMMIT_OTP_FAIL_OPEN", "false").lower() not in ("1", "true", "yes"):
                raise HTTPException(status_code=500, detail="Falha ao enviar código de verificação. Tente novamente.")
        logger.warning(
            "LOGIN_PENDING_OTP_RETURN request_id=%s email_ref=%s org=%s total_login_ms=%s",
            request_id,
            email_ref,
            org,
            int((time.perf_counter() - login_started_at) * 1000),
        )
        return {"pending_otp": True, "message": "Enviamos um código de verificação para seu e-mail. Digite-o para continuar.", "email": email, "tenant": org}

    response = _build_fresh_auth_response(db, org, u.id, usage_tier=usage_tier, auth_context="login")
    if response.get("pending_approval"):
        return response

    # Create user session for presence tracking
    _create_user_session(db, u.id, org, ip, getattr(u, "signup_code_label", None), usage_tier)

    logger.info(
        "LOGIN_SUCCESS_RETURN request_id=%s email_ref=%s org=%s status_code=200 total_login_ms=%s",
        request_id,
        email_ref,
        org,
        int((time.perf_counter() - login_started_at) * 1000),
    )

    return response

@app.get("/api/threads")
def list_threads(x_org_slug: Optional[str] = Header(default=None), user=Depends(get_current_user), db: Session = Depends(get_db)):
    org = get_request_org(user, x_org_slug)
    require_onboarding_complete(user)
    uid = user.get("sub")

    # AO50A_THREAD_RESTORE_LAST_ACTIVE
    # Contract: sidebar/bootstrap must receive useful conversations before empty ones.
    # Useful thread = user/admin visible thread with at least one real user/assistant message.
    try:
        logger.info("THREADS_LIST_REQUEST user_id=%s tenant=%s role=%s", uid, org, user.get("role"))
    except Exception:
        pass

    # Ensure core agents exist (solo-supervised defaults).
    # EFATA777-WR-20260622: this must not break conversation restore.
    try:
        ensure_core_agents(db, org)
    except Exception:
        try:
            db.rollback()
        except Exception:
            pass
        try:
            logger.exception("THREADS_LIST_ENSURE_CORE_AGENTS_FAILED_FAIL_OPEN org=%s user_id=%s", org, uid)
        except Exception:
            pass

    real_message_roles = ["user", "assistant"]

    msg_stats = (
        select(
            Message.thread_id.label("thread_id"),
            func.count(Message.id).label("message_count"),
            func.max(Message.created_at).label("last_message_at"),
        )
        .where(
            Message.org_slug == org,
            Message.role.in_(real_message_roles),
            Message.content.isnot(None),
            func.length(func.trim(Message.content)) > 0,
        )
        .group_by(Message.thread_id)
        .subquery()
    )

    stmt = (
        select(
            Thread,
            func.coalesce(msg_stats.c.message_count, 0).label("message_count"),
            msg_stats.c.last_message_at.label("last_message_at"),
        )
        .outerjoin(msg_stats, Thread.id == msg_stats.c.thread_id)
        .where(Thread.org_slug == org)
    )

    if user.get("role") != "admin":
        member_tids = db.execute(
            select(ThreadMember.thread_id).where(
                ThreadMember.org_slug == org,
                ThreadMember.user_id == uid,
            )
        ).scalars().all()

        if not member_tids:
            try:
                logger.info("THREADS_LIST_RESPONSE count=0 first_thread_id=None first_title=None first_message_count=0")
            except Exception:
                pass
            return []

        stmt = stmt.where(Thread.id.in_(member_tids))

    rows = db.execute(
        stmt.order_by(
            msg_stats.c.last_message_at.desc().nullslast(),
            Thread.created_at.desc(),
        )
    ).all()

    thread_ids = [row[0].id for row in rows]
    previews = {}

    if thread_ids:
        preview_rows = db.execute(
            select(Message.thread_id, Message.content)
            .where(
                Message.org_slug == org,
                Message.thread_id.in_(thread_ids),
                Message.role.in_(real_message_roles),
                Message.content.isnot(None),
                func.length(func.trim(Message.content)) > 0,
            )
            .order_by(Message.thread_id.asc(), Message.created_at.desc())
        ).all()

        for tid, content in preview_rows:
            if tid not in previews:
                preview = str(content or "").strip().replace("\n", " ")
                previews[tid] = preview[:160]

    result = []
    for t, message_count, last_message_at in rows:
        count = int(message_count or 0)
        has_messages = count > 0
        updated_at = getattr(t, "updated_at", None) or last_message_at or t.created_at

        result.append({
            "id": t.id,
            "title": t.title,
            "created_at": t.created_at,
            "updated_at": updated_at,
            "last_message_at": last_message_at,
            "message_count": count,
            "last_message_preview": previews.get(t.id, ""),
            "has_messages": has_messages,
            "is_empty": not has_messages,
        })

    try:
        first = result[0] if result else {}
        logger.info(
            "THREADS_LIST_RESPONSE count=%s first_thread_id=%s first_title=%s first_message_count=%s",
            len(result),
            first.get("id"),
            first.get("title"),
            first.get("message_count"),
        )
    except Exception:
        pass

    return result

@app.post("/api/threads")
def create_thread(inp: ThreadIn, x_org_slug: Optional[str] = Header(default=None), user=Depends(get_current_user), db: Session = Depends(get_db)):
    org = get_request_org(user, x_org_slug)
    require_onboarding_complete(user)
    t = Thread(id=new_id(), org_slug=org, title=inp.title, created_at=now_ts())
    db.add(t)
    db.commit()
    # PATCH0100_14: creator becomes owner
    _ensure_thread_owner(db, org, t.id, user.get("sub"))
    return {"id": t.id, "title": t.title, "created_at": t.created_at}

@app.patch("/api/threads/{thread_id}")
def rename_thread(thread_id: str, inp: ThreadUpdate, x_org_slug: Optional[str] = Header(default=None), user=Depends(get_current_user), db: Session = Depends(get_db)):
    org = get_request_org(user, x_org_slug)
    # PATCH0100_14: ACL check
    _require_thread_member(db, org, thread_id, user.get("sub"))
    t = db.execute(select(Thread).where(Thread.org_slug == org, Thread.id == thread_id)).scalar_one_or_none()
    if not t:
        raise HTTPException(status_code=404, detail="Thread not found")
    t.title = inp.title.strip()
    db.add(t)
    db.commit()
    return {"id": t.id, "title": t.title, "created_at": t.created_at}
@app.delete("/api/threads/{thread_id}")
def delete_thread(thread_id: str, x_org_slug: Optional[str] = Header(default=None), user=Depends(get_current_user), db: Session = Depends(get_db)):
    org = get_request_org(user, x_org_slug)
    # PATCH0100_14: only owner/admin can delete
    _require_thread_admin_or_owner(db, org, thread_id, user.get("sub"))
    t = db.execute(select(Thread).where(Thread.org_slug == org, Thread.id == thread_id)).scalar_one_or_none()
    if not t:
        raise HTTPException(status_code=404, detail="Thread not found")
    db.execute(delete(Message).where(Message.org_slug == org, Message.thread_id == thread_id))
    db.execute(delete(File).where(File.org_slug == org, File.thread_id == thread_id))
    db.execute(delete(ThreadMember).where(ThreadMember.org_slug == org, ThreadMember.thread_id == thread_id))
    db.execute(delete(Thread).where(Thread.org_slug == org, Thread.id == thread_id))
    db.commit()
    try:
        audit(db, org, user.get("sub"), "chat.thread.deleted", request_id="thread", path="/api/threads/{thread_id}", status_code=200, latency_ms=0, meta={"thread_id": thread_id})
    except Exception:
        pass
    return {"ok": True}



def _orkio_welcome_message(name: Optional[str]) -> str:
    return _orkio_premium_first_contact_text(name)


@app.get("/api/messages")
def list_messages(
    thread_id: str,
    include_welcome: bool = False,
    x_org_slug: Optional[str] = Header(default=None),
    user=Depends(get_current_user),
    db: Session = Depends(get_db),
):
    org = get_request_org(user, x_org_slug)
    require_onboarding_complete(user)
    # PATCH0100_14: ACL check (admin bypass)
    if user.get("role") != "admin":
        _require_thread_member(db, org, thread_id, user.get("sub"))
    rows = db.execute(select(Message).where(Message.org_slug == org, Message.thread_id == thread_id).order_by(Message.created_at.asc())).scalars().all()

    if not rows and include_welcome:
        try:
            orkio = db.execute(
                select(Agent).where(
                    Agent.org_slug == org,
                    ((Agent.is_default == True) | (Agent.name.ilike("%orkio%")))
                ).order_by(Agent.is_default.desc(), Agent.created_at.asc())
            ).scalars().first()
        except Exception:
            orkio = None

        welcome = Message(
            id=new_id(),
            org_slug=org,
            thread_id=thread_id,
            role="assistant",
            content=_orkio_welcome_message(user.get("name")),
            created_at=now_ts(),
            agent_id=(orkio.id if orkio else None),
            agent_name=(orkio.name if orkio else "Orkio"),
        )
        db.add(welcome)
        db.commit()
        rows = [welcome]

    return [{
        "id": m.id,
        "role": m.role,
        "content": m.content,
        "created_at": m.created_at,
        "user_id": getattr(m, "user_id", None),
        "user_name": getattr(m, "user_name", None),
        "agent_id": getattr(m, "agent_id", None),
        "agent_name": getattr(m, "agent_name", None),
    } for m in rows]


# EFATA777-WR-20260622 — compat endpoint for realtime/front-end message persistence.
# Production logs showed POST /api/messages returning 405 while realtime generated
# transcript.final events. This endpoint is intentionally small: it persists a
# single message into an existing thread and returns the persisted record.
@app.post("/api/messages")
def create_message_compat(
    inp: MessageCreateIn,
    x_org_slug: Optional[str] = Header(default=None),
    user=Depends(get_current_user),
    db: Session = Depends(get_db),
):
    org = get_request_org(user, x_org_slug)
    require_onboarding_complete(user)
    uid = user.get("sub")
    thread_id = str(inp.thread_id or "").strip()
    if not thread_id:
        raise HTTPException(status_code=400, detail="thread_id required")

    if user.get("role") != "admin":
        _require_thread_member(db, org, thread_id, uid)

    t = db.execute(
        select(Thread).where(Thread.org_slug == org, Thread.id == thread_id)
    ).scalar_one_or_none()
    if not t:
        raise HTTPException(status_code=404, detail="Thread not found")

    role = str(inp.role or "user").strip().lower()
    if role not in {"user", "assistant", "system"}:
        role = "user"

    content = str(inp.content or "").strip()
    if not content:
        raise HTTPException(status_code=400, detail="content required")

    created = int(inp.created_at or now_ts())
    agent_id = str(inp.agent_id or "").strip() or None
    agent_name = str(inp.agent_name or "").strip() or None
    if role == "assistant" and agent_id and not agent_name:
        try:
            ag = db.execute(
                select(Agent).where(Agent.org_slug == org, Agent.id == agent_id)
            ).scalar_one_or_none()
            if ag:
                agent_name = getattr(ag, "name", None)
        except Exception:
            pass

    msg = Message(
        id=new_id(),
        org_slug=org,
        thread_id=thread_id,
        user_id=uid if role == "user" else None,
        user_name=(str(inp.user_name or user.get("name") or "").strip() or None) if role == "user" else None,
        role=role,
        content=content,
        agent_id=agent_id if role == "assistant" else None,
        agent_name=agent_name if role == "assistant" else None,
        created_at=created,
    )
    db.add(msg)

    try:
        if hasattr(t, "updated_at"):
            t.updated_at = created
            db.add(t)
    except Exception:
        pass

    try:
        _ensure_thread_owner(db, org, thread_id, uid)
    except Exception:
        # Owner bootstrap is useful but must not block message persistence.
        pass

    db.commit()
    return {
        "id": msg.id,
        "thread_id": thread_id,
        "role": msg.role,
        "content": msg.content,
        "created_at": msg.created_at,
        "user_id": getattr(msg, "user_id", None),
        "user_name": getattr(msg, "user_name", None),
        "agent_id": getattr(msg, "agent_id", None),
        "agent_name": getattr(msg, "agent_name", None),
        "ok": True,
        "compatibility_endpoint": "POST /api/messages",
    }




_SUMMIT_SENSITIVE_PATTERNS = [
    r"\b(source\s*code|codebase|repository|repo|github)\b",
    r"\b(system\s*prompt|prompt\s*interno|internal\s*prompt|hidden\s*instructions?)\b",
    r"\b(architecture|arquitetura|api|apis|endpoint|database|postgres|schema|railway|fastapi|react)\b",
    r"\b(financial\s*projections?|revenue\s*forecast|cap\s*table|valuation|roadmap\s*privado|internal\s*strategy)\b",
]


def _block_if_sensitive(user_message: str) -> Optional[str]:
    if not SUMMIT_MODE:
        return None
    raw = (user_message or "").strip()
    if not raw:
        return None
    for pat in _SUMMIT_SENSITIVE_PATTERNS:
        if re.search(pat, raw, re.I):
            return (
                "That layer is proprietary and not shared publicly. "
                "At Summit level I can explain the business value, venture model, and collaboration paths at a high level."
            )
    return None


def _sensitive_guard_instruction() -> str:
    blocked = _block_if_sensitive("source code, architecture, prompts, APIs, database, financial projections, cap table, roadmap")
    blocked_text = (blocked or "That layer is proprietary and not shared publicly.").strip()
    return (
        "Sensitive-content enforcement: before answering, classify the user's request against the same protected categories used by the Summit server guard. "
        "If the request touches source code, architecture, prompts, APIs, database, financial projections, cap table, valuation, internal strategy, or roadmap, "
        "do not answer the request. Reply with this exact message: "
        f"{json.dumps(blocked_text, ensure_ascii=False)}"
    )


def _guard_realtime_message(user_message: str) -> Optional[str]:
    """
    AO19E_VOICE_INTENT_STABILIZER
    Deterministic guard for short realtime utterances.

    Purpose:
    - prevent voice/realtime context drift;
    - avoid routing short mic tests into stale valuation/audit intents;
    - answer presence/ack/squad-check commands without invoking the heavy LLM;
    - keep sensitive-safety blocking intact.
    """
    blocked = _block_if_sensitive(user_message)
    if blocked:
        return blocked

    raw = (user_message or "").strip()
    if not raw:
        return None

    def _norm(txt: str) -> str:
        try:
            import unicodedata as _ud
            txt = _ud.normalize("NFD", txt)
            txt = "".join(ch for ch in txt if _ud.category(ch) != "Mn")
        except Exception:
            pass
        txt = txt.lower()
        txt = re.sub(r"[^a-z0-9@\s]+", " ", txt, flags=re.I)
        return re.sub(r"\s+", " ", txt).strip()

    n = _norm(raw)
    words = n.split()
    word_count = len(words)

    # Presence / mic check. Includes common STT variations observed in PT-BR.
    presence_markers = [
        "esta na escuta",
        "estas na escuta",
        "ta na escuta",
        "voce esta me ouvindo",
        "voce ta me ouvindo",
        "esta me ouvindo",
        "estas me ouvindo",
        "online",
        "na escuta",
        "me ouvindo",
        "orquius",
        "orkius",
        "orkio voce esta",
    ]
    if any(marker in n for marker in presence_markers) and word_count <= 12:
        return "Sim, estou online e na escuta."

    # Explicit squad presence test. Must not call valuation/war-room templates.
    if (
        ("digam" in n or "diga" in n or "respondam" in n or "responda" in n)
        and "sim" in n
        and ("um apos o outro" in n or "um por vez" in n or "online" in n or "estao online" in n or "estao na escuta" in n)
    ):
        return "Orkio: sim.\nOrion: sim.\nChris: sim."

    # Short acknowledgements should not trigger previous intent continuation.
    ack_set = {
        "ok", "okay", "certo", "beleza", "perfeito", "entendi", "ta", "tá",
        "sim", "nao", "não", "olha", "olhe", "hum", "uhum", "legal"
    }
    if word_count <= 3 and n in ack_set:
        return "Entendido."

    # Voice test for Orion orchestration should stay controlled unless the user
    # gives the full audit command.
    if "testar" in n and ("orquestracao" in n or "orquestracao" in n or "orquestrar" in n) and "orion" in n and word_count <= 18:
        return (
            "Sim. Orion está disponível para teste de orquestração. "
            "Para auditoria completa, diga ou envie: Orion, execute a auditoria de orquestração real em modo readonly."
        )

    return None



# AO20BC-LITE — Router Precedence + Unified Realtime Intent + Execution Trace Lite
# Central, deterministic intent resolver used as a lightweight lock before
# agent fast-paths, proposal builders and realtime multi-agent execution.
def _ao20bc_norm(text: Any) -> str:
    raw = str(text or "")
    try:
        import unicodedata as _ud
        raw = _ud.normalize("NFD", raw)
        raw = "".join(ch for ch in raw if _ud.category(ch) != "Mn")
    except Exception:
        pass
    raw = raw.lower()
    raw = re.sub(r"[^a-z0-9@/\-_.\s:]+", " ", raw, flags=re.I)
    return re.sub(r"\s+", " ", raw).strip()


def _ao20bc_requested_agent(text: Any, explicit: Optional[str] = None) -> Optional[str]:
    raw = _ao20bc_norm(text)

    # AO20H-HF2 — typed @mention wins over stale UI visible_agent/selected_agent.
    # The frontend can legitimately keep Chris/Orion selected while the user types
    # @Orkio. The textual command must be the source of truth.
    if re.search(r"(^|\s)@orkio\b", raw):
        return "Orkio"
    if re.search(r"(^|\s)@orion\b", raw):
        return "Orion"
    if re.search(r"(^|\s)@(?:chris|cris)\b", raw):
        return "Chris"

    explicit_norm = _ao20bc_norm(explicit)
    if explicit_norm:
        if "orion" in explicit_norm:
            return "Orion"
        if "chris" in explicit_norm or "cris" in explicit_norm:
            return "Chris"
        if "orkio" in explicit_norm:
            return "Orkio"

    # Natural-language mentions remain useful, but they must be weaker than
    # explicit UI target and typed @mentions.
    if re.search(r"(^|\s)orkio\b", raw):
        return "Orkio"
    if re.search(r"(^|\s)orion\b", raw):
        return "Orion"
    if re.search(r"(^|\s)(chris|cris)\b", raw):
        return "Chris"
    return None


def _ao20bc_requested_patch_id(text: Any) -> Optional[str]:
    raw = _ao20bc_norm(text)
    # Normalize AO-20A / AO20A / ao20bc-lite into AO20A/AO20BC.
    match = re.search(r"\bao\s*-?\s*(20(?:bc|[a-z]))\b", raw, flags=re.I)
    if match:
        return "AO" + match.group(1).upper().replace("-", "")
    if "realtime orchestration stabilizer" in raw:
        return "AO20A"
    if "master router precedence" in raw or "router precedence lock" in raw:
        return "AO20B"
    if "unified realtime intent" in raw or "unified text realtime intent" in raw:
        return "AO20C"
    return None


def _ao20bc_resolve_route(text: Any, requested_agent: Optional[str] = None, source: str = "chat") -> Dict[str, Any]:
    raw = _ao20bc_norm(text)
    explicit_agent = _ao20bc_requested_agent(text, requested_agent)

    technical_markers = [
        "auditoria", "auditar", "readonly", "read only", "read-only", "war room",
        "sse", "runtime", "router",
        "proposal builder", "proposal_only", "proposal only", "backend", "frontend",
        "guard", "events batch", "events:batch", "orquestracao", "orquestracao real",
        "orquestracao", "orquestracao", "execution graph", "child_execution_graphs",
        "ao20", "ao 20", "patch minimo", "patch minimo", "diff preview",
    ]
    # AO68A-HF2:
    # "realtime", "voice", "voz" e "stream" tambem aparecem em pedidos naturais
    # de conversa por voz. Esses termos nao devem, sozinhos, capturar o usuario
    # para AUDITORIA FOCADA / AO20BC.
    realtime_conversation_markers = [
        "conversa rapida por voz", "conversa rápida por voz",
        "conversar por voz", "falar por voz", "abrir voz",
        "chamada de voz", "sessao de voz", "sessão de voz",
        "conversa em tempo real", "voz em tempo real",
        "dois minutos", "2 minutos", "ate dois minutos", "até dois minutos",
        "simular a experiencia", "simular a experiência",
        "experiencia de conversa natural", "experiência de conversa natural",
        "transicao para voz", "transição para voz",
    ]
    technical_denial_markers = [
        "nao preciso de auditoria", "não preciso de auditoria",
        "sem auditoria tecnica", "sem auditoria técnica",
        "nao quero auditoria", "não quero auditoria",
        "nao preciso de analise tecnica", "não preciso de análise técnica",
        "apenas quero simular", "quero simular a experiencia", "quero simular a experiência",
    ]
    orchestration_markers = [
        "orquestracao", "orquestrar", "child_execution_graphs", "dispatch_executed",
        "squad", "subagente", "multiagente", "multi agente",
    ]
    proposal_markers = [
        "proposal_only", "proposal only", "proposta", "patch", "diff preview",
        "rollback", "human_approval", "approval", "aprovacao", "aprovação",
    ]
    valuation_markers = [
        "valuation", "quanto vale", "valor da plataforma", "valor da empresa",
        "pre money", "pre-money", "post money", "post-money", "mrr", "arr",
        "captação", "captacao", "investidor", "investimento", "go to market",
        "go-to-market", "business plan", "plano de negocios", "plano de negocios",
    ]

    has_technical = any(m in raw for m in technical_markers)
    has_realtime_conversation = any(m in raw for m in realtime_conversation_markers)
    has_technical_denial = any(m in raw for m in technical_denial_markers)
    has_orchestration = any(m in raw for m in orchestration_markers)
    has_proposal = any(m in raw for m in proposal_markers)
    has_valuation = any(m in raw for m in valuation_markers)

    # AO68A-HF2: conversa natural sobre voz/realtime tem precedencia sobre AO20BC.
    # Mantem auditoria tecnica quando houver pedido tecnico real, mas libera a jornada
    # quando o usuario explicitamente pede experiencia/conversa natural e nega auditoria.
    if explicit_agent in (None, "Orkio") and has_realtime_conversation and has_technical_denial:
        has_technical = False

    requested_patch_id = _ao20bc_requested_patch_id(text)

    blocked_routes: List[str] = []
    route_family = "general"
    resolved_agent = explicit_agent or "Orkio"
    route_reason = "default_orkio"

    if explicit_agent:
        route_reason = "explicit_mention_precedence"

    if has_technical:
        route_family = "technical_audit"
        if has_orchestration:
            route_family = "orchestration_audit"
        if explicit_agent in (None, "Orkio"):
            resolved_agent = "Orkio"
        elif explicit_agent == "Orion":
            resolved_agent = "Orion"
        elif explicit_agent == "Chris":
            resolved_agent = "Chris"
        route_reason = (route_reason + "_and_technical_scope") if explicit_agent else "technical_scope"
        if resolved_agent != "Chris":
            blocked_routes.append("chris_valuation")
        if requested_patch_id and requested_patch_id.startswith("AO20"):
            blocked_routes.append("orion_ao16c_stale")
            blocked_routes.append("ao15_ao16_ao17_stale_checkpoint")

    if has_proposal:
        route_family = "proposal_governance"
        if explicit_agent == "Orion" or ("orion" in raw and explicit_agent is None):
            resolved_agent = "Orion"
        route_reason = (route_reason + "_and_proposal_scope") if route_reason else "proposal_scope"
        if requested_patch_id and requested_patch_id.startswith("AO20"):
            blocked_routes.append("ao16c_stale_proposal")

    if has_valuation and not has_technical:
        route_family = "valuation"
        if explicit_agent in (None, "Chris"):
            resolved_agent = "Chris"
        route_reason = (route_reason + "_and_valuation_scope") if explicit_agent else "valuation_scope"

    # Explicit @Orkio technical requests must never be rewritten to Chris.
    if explicit_agent == "Orkio" and has_technical:
        resolved_agent = "Orkio"
        if "chris_valuation" not in blocked_routes:
            blocked_routes.append("chris_valuation")

    # Scope lock: AO20 requests cannot generate AO16C/AO15/AO16B/AO17 as the active patch.
    generated_patch_id = requested_patch_id if (requested_patch_id and requested_patch_id.startswith("AO20")) else None

    return {
        "ao20bc": True,
        "source": source or "chat",
        "requested_agent": explicit_agent,
        "resolved_agent": resolved_agent,
        "route_family": route_family,
        "route_reason": route_reason,
        "blocked_routes": list(dict.fromkeys([x for x in blocked_routes if x])),
        "requested_patch_id": requested_patch_id,
        "generated_patch_id": generated_patch_id,
        "technical_scope": bool(has_technical),
        "orchestration_scope": bool(has_orchestration),
        "proposal_scope": bool(has_proposal),
        "valuation_scope": bool(has_valuation and not has_technical),
        "scope_lock": bool(requested_patch_id and requested_patch_id.startswith("AO20")),
    }


def _ao20bc_router_audit_answer(text: Any, route: Dict[str, Any]) -> str:
    execution_id = f"ao20bc_route_audit_{new_id()[:10]}"
    trace_nodes = [
        {"id": f"{execution_id}_router", "agent": "Router", "status": "completed"},
        {"id": f"{execution_id}_realtime", "agent": "Realtime", "status": "completed"},
        {"id": f"{execution_id}_orchestrator", "agent": "Orchestrator", "status": "completed"},
        {"id": f"{execution_id}_audit", "agent": "AO20BC", "status": "completed"},
    ]

    try:
        audit(
            db,
            org_slug=org,
            user_id=uid,
            action="execution_graph.persisted",
            request_id=execution_id,
            path="/api/chat/stream",
            status_code=200,
            latency_ms=0,
            meta={
                "ao_patch": "AO20F",
                "execution_id": execution_id,
                "route_family": "technical_audit",
                "resolved_agent": resolved_agent,
                "nodes": trace_nodes,
                "trace_mode": "persistent_auditlog",
            },
        )
    except Exception:
        try:
            db.rollback()
        except Exception:
            pass


    blocked = ", ".join(route.get("blocked_routes") or []) or "nenhuma"
    return (
        "AUDITORIA FOCADA — ORKIO AO20BC / ROUTER / REALTIME / ORCHESTRATION\n\n"
        "1. Diagnóstico objetivo\n"
        "- O pedido foi classificado pelo Router Precedence Lock antes de qualquer fast-path de Chris/Orion/template.\n"
        "- @mention explícito e escopo técnico agora têm precedência sobre memória da thread, agente anterior e valuation fast-path.\n\n"
        "2. Execution Trace Lite\n"
        f"- execution_id: {execution_id}\n"
        f"- requested_agent: {route.get('requested_agent') or 'não explicitado'}\n"
        f"- resolved_agent: {route.get('resolved_agent')}\n"
        f"- route_family: {route.get('route_family')}\n"
        f"- route_reason: {route.get('route_reason')}\n"
        f"- blocked_routes: {blocked}\n"
        f"- requested_patch_id: {route.get('requested_patch_id') or 'não solicitado'}\n"
        f"- generated_patch_id: {route.get('generated_patch_id') or 'não gerado'}\n"
        "- dispatch_executed: true\n"
        "- write_executed: false\n\n"
        "3. Problema A — @Orkio roteado para Chris\n"
        "- Causa raiz: valuation/Chris fast-path era amplo demais e podia vencer o comando explícito atual.\n"
        "- Correção operacional: escopo técnico bloqueia chris_valuation salvo pedido explícito para @Chris.\n\n"
        "4. Problema B — Orion Proposal Builder stale / AO-16C\n"
        "- Causa raiz: proposal builder usava checkpoint/template antigo quando não havia scope lock.\n"
        "- Correção operacional: pedidos AO20* bloqueiam AO16C/AO15/AO16B/AO17 como proposta principal.\n\n"
        "5. Problema C — Realtime / Voice Intent Drift\n"
        "- Causa raiz provável: browser realtime, backend events:batch e guard podiam atuar como autoridades concorrentes.\n"
        "- Correção operacional: intenções técnicas/multiagente devem ser roteadas ao backend como fonte única.\n\n"
        "6. Problema D — Orquestração lógica vs runtime real\n"
        "- Estado atual: o sistema pode renderizar child_execution_graphs, mas ainda não prova runtime distribuído persistente.\n"
        "- Próximo estágio seguro: criar execution graph persistente apenas após o router estar estável.\n\n"
        "7. Patch mínimo recomendado\n"
        "- AO20BC-LITE: Router Precedence + Unified Realtime Intent + Execution Trace Lite.\n\n"
        "8. Veredito GO/NO-GO\n"
        "- GO para validação controlada do router e realtime unificado.\n"
        "- NO-GO para declarar runtime multiagente distribuído enterprise completo sem AO20F persistente."
    )


# AO20E — Orchestration Fast-Path Guard
# This stays lightweight: it renders an auditable orchestration graph without
# creating migrations or claiming distributed runtime execution.
def _ao20e_is_orchestration_audit_request(text: Any) -> bool:
    raw = _ao20bc_norm(text)
    if not raw:
        return False
    orchestration_terms = [
        "orquestracao", "orquestrar", "orchestration",
        "orion e chris", "orion + chris", "chris e orion",
        "agentes lideres", "agentes líderes",
        "child_execution_graphs", "dispatch_executed", "write_executed",
        "squad", "squads", "subagentes", "multiagente", "multi agente",
        "execution graph", "merge final",
    ]
    readonly_terms = ["readonly", "read only", "read-only", "auditoria", "auditar", "audit"]
    return any(t in raw for t in orchestration_terms) and any(t in raw for t in readonly_terms)


def _ao20h_hf2_is_explicit_orkio_orchestration_request(text: Any) -> bool:
    raw = _ao20bc_norm(text)
    if not raw:
        return False
    if not re.search(r"(^|\s)@orkio\b", raw):
        return False

    readonly_terms = [
        "readonly", "read only", "read-only",
        "auditoria", "auditar", "audit",
    ]
    orchestration_terms = [
        "orquestracao", "orquestrar", "orchestration",
        "orion e chris", "orion + chris", "chris e orion",
        "child_execution_graphs", "dispatch_executed", "write_executed",
        "agentes lideres", "agentes líderes",
        "squad", "squads", "multiagente", "multi agente",
        "execution graph",
    ]
    return any(t in raw for t in readonly_terms) and any(t in raw for t in orchestration_terms)


def _ao20h_hf2_orkio_orchestration_route(text: Any) -> Dict[str, Any]:
    route = _ao20bc_resolve_route(text, requested_agent="Orkio", source="chat")
    blocked = list(route.get("blocked_routes") or [])
    blocked.extend([
        "direct_agent_message",
        "visible_agent_stale_override",
        "chris_governance_response",
        "patch_governance_response",
        "proposal_only_builder",
        "internal_warroom_governed_surgical_v2",
        "chris_valuation",
    ])

    route.update({
        "requested_agent": "Orkio",
        "resolved_agent": "Orkio",
        "route_family": "orchestration_audit",
        "route_reason": "explicit_orkio_mention_precedence_over_visible_agent_and_governance",
        "technical_scope": True,
        "orchestration_scope": True,
        "proposal_scope": False,
        "valuation_scope": False,
        "blocked_routes": list(dict.fromkeys([x for x in blocked if x])),
        "ao20h_hf2_mention_lock": True,
    })
    return route


