def _pick_target_agent_by_slug(target_agents: Optional[List[Dict[str, Any]]], slug: str) -> Optional[Dict[str, Any]]:
    wanted = _canonical_runtime_agent_slug(slug)
    if not wanted:
        return None
    for ag in list(target_agents or []):
        current = _canonical_runtime_agent_slug((ag or {}).get("slug") or (ag or {}).get("name"))
        if current == wanted:
            return ag
    return None


def _is_hidden_catalog_request(user_text: str) -> bool:
    return bool(_hidden_catalog_request_flags(user_text).get("requested"))

def _is_runtime_source_audit_request(user_text: str) -> bool:
    txt = (user_text or "").strip().lower()
    if not txt:
        return False
    patterns = [
        r"auditoria\s+de\s+fonte",
        r"runtime\s+source\s+audit",
        r"source\s+audit",
        r"diverg[êe]ncias?\s+entre\s+fontes",
        r"cat[aá]logo\s+p[úu]blico",
        r"cat[aá]logo\s+privilegiad",
        r"seed\s+oculto",
        r"ocultos?\s+e\s+internos?",
        r"agentes\s+com\s+hidden\s*=\s*true",
        r"agentes\s+com\s+internal\s*=\s*true",
        r"agentes\s+com\s+system\s*=\s*true",
        r"agentes\s+system",
        r"veredito\s+final",
        r"consist[êe]ncia\s+entre\s+fontes",
    ]
    return any(re.search(p, txt, flags=re.IGNORECASE) for p in patterns)

def _looks_like_pwa_console_execution_request(user_text: str) -> bool:
    txt = (user_text or "").strip().lower()
    if not txt:
        return False
    scope_patterns = [
        r"\bpwa\b",
        r"app\s+console",
        r"\bconsole\b",
        r"\bthreads?\b",
        r"\bagentes?\b",
        r"\bagents?\b",
        r"sidebar",
        r"ux",
        r"frontend",
        r"sele[cç][aã]o\s+de\s+threads",
        r"sele[cç][aã]o\s+de\s+agentes",
    ]
    repair_patterns = [
        r"corrig",
        r"consert",
        r"restaur",
        r"ajust",
        r"executar\s+corre[cç][aã]o",
        r"aplicar\s+corre[cç][aã]o",
        r"aplique\s+o\s+patch",
        r"aplicar\s+patch",
        r"fix",
        r"repair",
        r"deixe\s+de\s+abortar",
        r"fazer\s+com\s+que\s+orion\s+consiga\s+executar",
    ]
    has_scope = any(re.search(p, txt, flags=re.IGNORECASE) for p in scope_patterns)
    has_repair = any(re.search(p, txt, flags=re.IGNORECASE) for p in repair_patterns)
    return bool(has_scope and has_repair)


def _default_forced_orion_specialists(
    user_text: str,
    requested_specialists: Optional[List[str]] = None,
) -> List[str]:
    specialists = [
        _canonical_dispatch_specialist_slug(item)
        for item in list(requested_specialists or [])
    ]
    specialists = [item for item in specialists if item]
    if specialists:
        seen: set[str] = set()
        ordered: List[str] = []
        for item in specialists:
            if item in seen:
                continue
            ordered.append(item)
            seen.add(item)
        return ordered

    if _looks_like_pwa_console_execution_request(user_text):
        return ["orion", "cto", "ux_frontend"]

    return ["orion", "auditor", "cto"]


def _looks_like_final_readonly_analysis_request_message(user_text: str) -> bool:
    txt = (user_text or "").strip().lower()
    if not txt:
        return False

    has_analysis = bool(re.search(
        r"an[áa]lise detalhada|an[áa]lise arquitetural|an[áa]lise t[ée]cnica final|an[áa]lise t[ée]cnica|auditoria t[ée]cnica|auditoria externa|parecer t[ée]cnico|diagn[óo]stico t[ée]cnico|melhorias priorizadas|recomendac[aã]o consolidada|an[áa]lise final",
        txt,
        flags=re.IGNORECASE,
    ))
    has_scope = bool(re.search(
        r"code|codebase|c[óo]digo|codigo|runtime|backend|frontend|console|chat stream|sse|intent|governan[çc]a|github bridge|ux|orkio|plataforma|sistema|arquitetura|t[ée]cnic[ao]",
        txt,
        flags=re.IGNORECASE,
    ))
    read_only = bool(re.search(
        r"read[- ]only|somente leitura|n[ãa]o executar|nao executar|n[ãa]o abrir pr|nao abrir pr|n[ãa]o escrever|nao escrever",
        txt,
        flags=re.IGNORECASE,
    ))
    wants_final_output = bool(re.search(
        r"entregue apenas a an[áa]lise final|entregar apenas a an[áa]lise final|n[ãa]o resolva squad|nao resolva squad|n[ãa]o retorne trace|nao retorne trace",
        txt,
        flags=re.IGNORECASE,
    ))
    return bool(has_analysis and has_scope and read_only and wants_final_output)


def _runtime_orion_dispatch_request_flags(user_text: str) -> Dict[str, Any]:
    txt = (user_text or "").strip()
    normalized = txt.lower()
    if not normalized:
        return {"requested": False, "requested_specialists": [], "reason": ""}
    if _looks_like_final_readonly_analysis_request_message(txt):
        return {"requested": False, "requested_specialists": [], "reason": "final_readonly_analysis"}

    specialist_aliases = [
        (r"\borion\b", "orion"),
        (r"\barquiteto\b", "architect"),
        (r"\barchitect\b", "architect"),
        (r"\bauditor\b", "auditor"),
        (r"\bcto\b", "cto"),
        (r"\bdevops\b", "devops"),
        (r"\bsre\b", "devops"),
        (r"\bseguran[çc]a\b", "security"),
        (r"\bsecurity\b", "security"),
        (r"\bux[_/\s-]*frontend\b", "ux_frontend"),
        (r"\bux\s+frontend\b", "ux_frontend"),
        (r"\bfrontend\s+ux\b", "ux_frontend"),
        (r"\bfrontend\b", "ux_frontend"),
        (r"\bui[_/\s-]*ux\b", "ux_frontend"),
        (r"\bux\b", "ux_frontend"),
    ]
    requested_specialists: List[str] = []
    seen_specialists: set[str] = set()
    for pattern, slug in specialist_aliases:
        if re.search(pattern, normalized, flags=re.IGNORECASE):
            if slug not in seen_specialists:
                requested_specialists.append(slug)
                seen_specialists.add(slug)

    if _looks_like_pwa_console_execution_request(txt):
        return {
            "requested": True,
            "requested_specialists": _default_forced_orion_specialists(txt, requested_specialists),
            "reason": "forced_orion_pwa_console_repair",
            "pwa_console_repair": True,
        }

    wants_dispatch_patterns = [
        r"acione\s+sua\s+equipe\s+t[ée]cnica",
        r"acione\s+a\s+equipe\s+t[ée]cnica",
        r"acione\s+sua\s+equipe\s+interna",
        r"acione\s+seu\s+squad\s+t[ée]cnico",
        r"fa[çc]a\s+uma\s+varredura\s+operacional",
        r"varredura\s+t[ée]cnica",
        r"diagn[óo]stico\s+executivo",
        r"diagn[óo]stico\s+t[ée]cnico",
        r"auditoria\s+operacional",
        r"auditoria\s+t[ée]cnica",
        r"runtime\s+diagnostic",
        r"execution\s+receipts",
        r"dispatch\s+receipts",
        r"specialist\s+reports",
    ]
    wants_dispatch = any(re.search(p, normalized, flags=re.IGNORECASE) for p in wants_dispatch_patterns)

    if not wants_dispatch and len(requested_specialists) >= 2:
        wants_dispatch = bool(re.search(r"diagn[óo]stico|auditoria|varredura|runtime|opera(cional|tional)", normalized, flags=re.IGNORECASE))

    if not wants_dispatch:
        return {"requested": False, "requested_specialists": [], "reason": ""}

    requested_specialists = _default_forced_orion_specialists(txt, requested_specialists)

    return {
        "requested": True,
        "requested_specialists": requested_specialists,
        "reason": "forced_orion_runtime_dispatch",
        "pwa_console_repair": False,
    }


