def _load_recent_thread_context_messages(
    db: Session,
    *,
    org: str,
    thread_id: str,
    limit: int = 12,
) -> List[Dict[str, str]]:
    if not thread_id:
        return []

    try:
        rows = db.execute(
            select(Message.role, Message.content)
            .where(
                Message.org_slug == org,
                Message.thread_id == thread_id,
            )
            .order_by(Message.created_at.desc())
            .limit(max(1, int(limit or 12)))
        ).all()
    except Exception:
        try:
            db.rollback()
        except Exception:
            pass
        return []

    out: List[Dict[str, str]] = []
    for role, content in reversed(list(rows or [])):
        text_value = str(content or "").strip()
        if text_value:
            out.append(
                {
                    "role": str(role or "user").strip() or "user",
                    "content": text_value,
                }
            )
    return out




# AO80B — Restore thread context before any welcome/public fast-path.
def _ao80_thread_id_hash(thread_id: Optional[str]) -> str:
    raw = str(thread_id or "").strip()
    if not raw:
        return ""
    try:
        return hashlib.sha256(raw.encode("utf-8")).hexdigest()[:12]
    except Exception:
        return "hash_failed"


def _ao80_count_thread_messages(
    db: Session,
    *,
    org: str,
    thread_id: str,
) -> int:
    if not thread_id:
        return 0
    try:
        return int(
            db.execute(
                select(func.count(Message.id)).where(
                    Message.org_slug == org,
                    Message.thread_id == thread_id,
                )
            ).scalar() or 0
        )
    except Exception:
        try:
            db.rollback()
        except Exception:
            pass
        return 0


_AO80_CONTINUITY_TERMS = (
    "continue",
    "de onde paramos",
    "de onde parou",
    "depois do refresh",
    "após o refresh",
    "apos o refresh",
    "pós-refresh",
    "pos-refresh",
    "documento",
    "arquivo",
    "anexo",
    "analisamos",
    "analisado",
    "valor",
    "bônus",
    "bonus",
    "lembra",
    "lembrar",
    "retome",
    "retomar",
)


def _ao80_is_continuity_request(user_text: Any) -> bool:
    normalized = re.sub(r"\s+", " ", str(user_text or "").strip().lower())
    if not normalized:
        return False
    return any(term in normalized for term in _AO80_CONTINUITY_TERMS)


def _ao80_build_thread_rehydration_snapshot(
    db: Session,
    *,
    org: str,
    thread_id: str,
    recent_messages: Optional[List[Dict[str, str]]] = None,
    file_ids: Optional[List[str]] = None,
) -> Dict[str, Any]:
    prior_message_count = _ao80_count_thread_messages(db, org=org, thread_id=thread_id)
    recent = list(recent_messages or [])
    docs = list(file_ids or [])
    return {
        "thread_id_hash": _ao80_thread_id_hash(thread_id),
        "prior_message_count": prior_message_count,
        "recent_message_count": len(recent),
        "attached_docs_count": len(docs),
        "document_context_available": bool(docs),
        "context_rehydrated": bool(thread_id) and (prior_message_count > 0 or bool(recent) or bool(docs)),
    }


def _ao80_should_block_welcome_fastpath(
    *,
    message: Any,
    rehydration: Optional[Dict[str, Any]],
) -> bool:
    snapshot = dict(rehydration or {})
    prior_count = int(snapshot.get("prior_message_count") or 0)
    has_docs = bool(snapshot.get("attached_docs_count") or 0)
    continuity_intent = _ao80_is_continuity_request(message)
    # A first-contact welcome is only safe for an empty thread. In a restored or
    # document-bearing thread, prefer contextual runtime or a graceful fallback.
    return bool(prior_count > 0 or has_docs or continuity_intent)


def _append_ao75_task_first_overlay(
    runtime_enrichment: Optional[Dict[str, Any]],
    intent_contract: Optional[Dict[str, Any]],
) -> Dict[str, Any]:
    data = dict(runtime_enrichment or {})
    contract = dict(intent_contract or {})
    if not contract.get("concrete_task"):
        return data

    task_overlay = (
        "TASK-FIRST RESPONSE CONTRACT. "
        "Answer the user's concrete task before presenting Patroai, services, implementation or calls to action. "
        "Use available evidence, separate confirmed facts from inference, state operational limitations honestly, "
        "and never claim an external action, document access or execution that was not actually confirmed. "
        "Orkio remains the public speaker."
    )
    current_overlay = str(data.get("system_overlay") or "").strip()
    data["system_overlay"] = (
        current_overlay + ("\n\n" if current_overlay else "") + task_overlay
    ).strip()

    runtime_hints = (
        dict(data.get("runtime_hints") or {})
        if isinstance(data.get("runtime_hints"), dict)
        else {}
    )
    runtime_hints["ao75_intent"] = {
        "version": contract.get("version"),
        "intent": contract.get("intent"),
        "reason": contract.get("reason"),
        "confidence": contract.get("confidence"),
        "requires_document_context": bool(contract.get("requires_document_context")),
        "public_fastpath_allowed": bool(contract.get("public_fastpath_allowed", True)),
        "memory_commit_allowed": bool(contract.get("memory_commit_allowed", False)),
        "speaker": "Orkio",
    }
    data["runtime_hints"] = runtime_hints
    return data


