@app.get("/api/admin/evolution/proposals/{proposal_id}/execution-plan")
def admin_evolution_proposal_execution_plan(
    proposal_id: str,
    _admin=Depends(require_admin_access),
):
    """
    AO-16/AO-17: provides a controlled dry-run plan bridge for Admin visibility.

    For AO-17C/AO-18A, this route is stage-aware: it must reference the existing
    AO-17B branch and must not suggest creating a new branch.
    """
    row = _admin_evolution_get_proposal(proposal_id)
    if not row:
        raise HTTPException(status_code=404, detail="proposal_not_found")

    can_dry_run = bool(row.get("can_dry_run"))
    execution_status = str(row.get("execution_status") or "not_started").strip()
    dry_run_completed = execution_status == "dry_run_completed"
    branch_pr_plan = _admin_evolution_build_branch_pr_plan(row)

    # AO-23B_EXECUTION_PLAN_WRAPPER_STAGE_AWARE
    branch_pr_plan_stage = str(branch_pr_plan.get("stage") or "").strip().upper()
    branch_pr_plan_mode = str(branch_pr_plan.get("mode") or "").strip()
    is_ao23b_frontend_push_stage = (
        branch_pr_plan_stage == "AO-23B"
        or branch_pr_plan_mode == "governed_frontend_push_plan_readonly"
    )
    is_ao23_frontend_publication_stage = (
        branch_pr_plan_stage == "AO-23"
        or branch_pr_plan_mode == "governed_frontend_publication_plan_readonly"
    )
    is_restore_point_stage = branch_pr_plan_stage == "AO-17C/AO-18A"

    if dry_run_completed and is_ao23b_frontend_push_stage:
        next_stage = "AO-23C governed frontend push execution only after explicit Admin confirmation and publication preflight validation"
    elif dry_run_completed and is_ao23_frontend_publication_stage:
        next_stage = "AO-23B governed frontend push/publication only after explicit Admin approval and publication preflight validation"
    elif dry_run_completed and is_restore_point_stage:
        next_stage = "AO-17C/AO-18A restore point branch patch plan review (read-only)"
    elif dry_run_completed:
        next_stage = "AO-17A branch/pr plan review (read-only)"
    elif can_dry_run:
        next_stage = "AO-16 controlled dry-run"
    else:
        next_stage = row.get("next_state") or "readonly"

    if dry_run_completed and is_ao23b_frontend_push_stage:
        execution_plan_message = "AO-23B disponível em modo read-only: push governado dos commits locais somente após confirmação Admin explícita, validação de publicação e sem deploy/migration automático."
    elif dry_run_completed and is_ao23_frontend_publication_stage:
        execution_plan_message = "AO-23 disponível em modo read-only: publicação frontend somente após aprovação Admin explícita e dry-run concluído, sem push/deploy/migration automático."
    elif dry_run_completed and is_restore_point_stage:
        execution_plan_message = "AO-17C/AO-18A disponível em modo read-only: patch na branch existente somente após restore point e aprovação Admin explícita."
    elif dry_run_completed:
        execution_plan_message = "AO-17A disponível em modo read-only: branch/PR somente após aprovação Admin explícita."
    else:
        execution_plan_message = "AO-16 permite dry-run governado. Não executa escrita, commit, deploy ou migration."

    return {
        "ok": True,
        "proposal_id": proposal_id,
        "proposal_status": row.get("status"),
        "execution_enabled": False,
        "can_execute_real": False,
        "can_dry_run": can_dry_run,
        "dry_run_endpoint": f"/api/admin/evolution/proposals/{proposal_id}/dry-run",
        "execution_status": execution_status,
        "next_required_stage": next_stage,
        "smoke_tests_required": True,
        "rollback_plan_required": True,
        "branch_pr_plan_required": dry_run_completed,
        "restore_point_required": bool(branch_pr_plan.get("restore_point_required")),
        "snapshot_required": bool(branch_pr_plan.get("snapshot_required")),
        "can_prepare_branch_pr": bool(branch_pr_plan.get("can_prepare_branch_pr")),
        "can_prepare_branch_patch": bool(branch_pr_plan.get("can_prepare_branch_patch")),
        "can_prepare_push": bool(branch_pr_plan.get("can_prepare_push")),
        "publication_plan_required": bool(dry_run_completed and (is_ao23_frontend_publication_stage or is_ao23b_frontend_push_stage)),
        "branch_pr_plan_endpoint": f"/api/admin/evolution/proposals/{proposal_id}/branch-pr-plan",
        "branch_pr_plan": branch_pr_plan,
        "message": execution_plan_message,
        "rollback_plan": row.get("rollback_plan") or "",
        "checklist": row.get("checklist") or [],
    }



@app.get("/api/admin/evolution/proposals/{proposal_id}/branch-pr-plan")
def admin_evolution_proposal_branch_pr_plan(
    proposal_id: str,
    _admin=Depends(require_admin_access),
):
    """
    AO-17A: read-only Branch/PR Runner plan.

    This endpoint does not create branches, write files, commit, open PRs,
    merge, deploy or run migrations. It only exposes the next-stage contract.
    """
    row = _admin_evolution_get_proposal(proposal_id)
    if not row:
        raise HTTPException(status_code=404, detail="proposal_not_found")
    plan = _admin_evolution_build_branch_pr_plan(row)
    return {
        "ok": True,
        "execution_enabled": False,
        "can_execute_real": False,
        "write_allowed": False,
        "mode": "branch_pr_runner_plan_readonly",
        "plan": plan,
    }


# ================================
# AO-17B-CREATE — Criação governada de branch temporária
# ================================

class AdminEvolutionBranchCreateRequest(BaseModel):
    branch: Optional[str] = None
    repo_target: Optional[str] = "both"


def _admin_evolution_is_ao17b_branch_creation_proposal(proposal: Dict[str, Any]) -> bool:
    p = proposal if isinstance(proposal, dict) else {}
    title = str(p.get("title") or "").strip().lower()
    summary = str(p.get("summary") or "").strip().lower()
    source = str(p.get("source_message") or "").strip().lower()
    text_value = "\n".join([title, summary, source])
    return (
        "ao-17b" in text_value
        and (
            "branch tempor" in text_value
            or "criação governada de branch" in text_value
            or "criacao governada de branch" in text_value
            or "branch creation" in text_value
        )
    )


def _admin_evolution_safe_branch_name(value: Any, proposal_id: str) -> str:
    raw = str(value or "").strip()
    if not raw:
        branch_slug = re.sub(r"[^a-z0-9._-]+", "-", str(proposal_id or "").lower()).strip("-") or "proposal"
        raw = f"ao-17/{branch_slug}"

    raw = raw.replace("refs/heads/", "").strip().strip("/")
    raw = re.sub(r"\s+", "-", raw)

    if not raw.startswith("ao-17/"):
        raw = f"ao-17/{raw}"

    if (
        not raw
        or raw.startswith("/")
        or raw.endswith("/")
        or ".." in raw
        or "\\" in raw
        or not re.fullmatch(r"[A-Za-z0-9._/\-]+", raw)
    ):
        raise HTTPException(status_code=400, detail="unsafe_branch_name")

    return raw


def _admin_evolution_branch_repo_targets(repo_target: Optional[str]) -> List[Dict[str, str]]:
    wanted = str(repo_target or "both").strip().lower()
    if wanted in {"", "default", "auto"}:
        wanted = "both"

    targets: List[Dict[str, str]] = []
    seen: set = set()

    def _add(kind: str, repo: str) -> None:
        repo_slug = _github_normalize_repo_slug(repo)
        if not repo_slug or repo_slug.lower() in seen:
            return
        seen.add(repo_slug.lower())
        targets.append({"kind": kind, "repo": repo_slug})

    if wanted in {"both", "all", "backend", "api"}:
        _add("backend", _github_backend_repo())

    if wanted in {"both", "all", "frontend", "web", "ui"}:
        _add("frontend", _github_frontend_repo())

    # Fallback seguro: se só houver um repo legado configurado, usa o backend resolver.
    if not targets and wanted in {"both", "all"}:
        _add("backend", _github_backend_repo())

    return targets


def _admin_evolution_record_branch_create_execution(
    *,
    proposal: Dict[str, Any],
    receipt: Dict[str, Any],
    actor: str,
    org_slug: str,
) -> Dict[str, Any]:
    """Registra receipt auditável da criação de branch sem alterar status do dry-run."""
    pid = str(proposal.get("proposal_id") or "").strip()
    if not pid:
        raise HTTPException(status_code=400, detail="proposal_id_required")

    execution_id = str(receipt.get("execution_id") or "").strip() or ("exec_" + uuid.uuid4().hex[:12])
    receipt["execution_id"] = execution_id

    if not _admin_evolution_bootstrap_db_schema():
        receipt["audit_recorded"] = False
        receipt["audit_record_error"] = "evolution_schema_unavailable"
        return receipt

    now = _admin_evolution_now()
    status = "branch_created" if bool(receipt.get("ok")) else "branch_create_failed"
    smoke_plan = [
        "Branch temporária criada ou confirmada como existente.",
        "Nenhum arquivo foi escrito.",
        "Nenhum commit foi criado.",
        "Nenhum PR foi aberto.",
        "Nenhum merge foi executado.",
        "Nenhum deploy foi executado.",
        "Nenhuma migration foi executada.",
        "main permaneceu sem escrita direta.",
    ]

    db = SessionLocal()
    try:
        db.execute(text("""
            INSERT INTO admin_evolution_executions (
                execution_id, proposal_id, org_slug, status, mode, created_by, approved_by,
                risk, rollback_plan, smoke_checklist_json, result_json,
                created_at, updated_at, started_at, finished_at
            ) VALUES (
                :execution_id, :proposal_id, :org_slug, :status, :mode, :created_by, :approved_by,
                :risk, :rollback_plan, :smoke_checklist_json, :result_json,
                :created_at, :updated_at, :started_at, :finished_at
            )
        """), {
            "execution_id": execution_id,
            "proposal_id": pid,
            "org_slug": org_slug,
            "status": status,
            "mode": "ao17b_branch_create_only",
            "created_by": str(actor or ""),
            "approved_by": str(proposal.get("approved_by") or ""),
            "risk": str(proposal.get("risk") or "baixo_medio"),
            "rollback_plan": str(receipt.get("rollback_plan") or proposal.get("rollback_plan") or ""),
            "smoke_checklist_json": _admin_evolution_json_dump(smoke_plan),
            "result_json": _admin_evolution_json_dump(receipt),
            "created_at": now,
            "updated_at": now,
            "started_at": now,
            "finished_at": now,
        })
        db.execute(text("""
            UPDATE admin_evolution_proposals
            SET updated_at = :updated_at
            WHERE proposal_id = :proposal_id
        """), {
            "proposal_id": pid,
            "updated_at": now,
        })
        db.commit()
        receipt["audit_recorded"] = True
        receipt["audit_execution_status"] = status
        return receipt
    except Exception as e:
        try:
            db.rollback()
        except Exception:
            pass
        try:
            logger.exception(
                "ADMIN_EVOLUTION_AO17B_BRANCH_RECEIPT_RECORD_FAILED proposal_id=%s execution_id=%s error=%s",
                pid,
                execution_id,
                str(e)[:240],
            )
        except Exception:
            pass
        receipt["audit_recorded"] = False
        receipt["audit_record_error"] = str(e)[:240]
        return receipt
    finally:
        try:
            db.close()
        except Exception:
            pass


def _admin_evolution_create_governed_branch(
    proposal_id: str,
    *,
    actor: str = "",
    org_slug: Optional[str] = None,
    branch_override: Optional[str] = None,
    repo_target: Optional[str] = "both",
) -> Dict[str, Any]:
    pid = str(proposal_id or "").strip()
    if not pid:
        raise HTTPException(status_code=400, detail="proposal_id_required")

    proposal = _admin_evolution_get_proposal(pid)
    if not proposal:
        raise HTTPException(status_code=404, detail="proposal_not_found")

    if str(proposal.get("status") or "").strip().lower() != "approved":
        raise HTTPException(status_code=409, detail="proposal_must_be_approved_before_branch_creation")

    if str(proposal.get("execution_status") or "").strip().lower() != "dry_run_completed":
        raise HTTPException(status_code=409, detail="dry_run_must_be_completed_before_branch_creation")

    if not _admin_evolution_is_ao17b_branch_creation_proposal(proposal):
        raise HTTPException(status_code=409, detail="proposal_not_ao17b_branch_creation")

    plan = _admin_evolution_build_branch_pr_plan(proposal)
    suggested_branch = str(plan.get("suggested_branch") or "").strip()
    branch_name = _admin_evolution_safe_branch_name(branch_override or suggested_branch, pid)
    org = str(org_slug or proposal.get("org_slug") or "public").strip() or "public"
    trace_id = f"ao17b_{pid}_{uuid.uuid4().hex[:8]}"

    targets = _admin_evolution_branch_repo_targets(repo_target)
    if not targets:
        diagnostics = _github_repo_config_diagnostics(repo_target=repo_target)
        receipt = {
            "ok": False,
            "stage": "AO-17B-CREATE",
            "mode": "branch_creation_only",
            "proposal_id": pid,
            "proposal_status": proposal.get("status"),
            "execution_status": proposal.get("execution_status"),
            "branch": branch_name,
            "branch_name": branch_name,
            "branch_created": False,
            "branch_already_exists": False,
            "repo_receipts": [],
            "repo_config": diagnostics,
            "execution_enabled": False,
            "can_execute_real": False,
            "can_write_repository": False,
            "can_commit": False,
            "can_open_pr": False,
            "can_merge": False,
            "can_deploy": False,
            "can_run_migration": False,
            "write_allowed": False,
            "file_write_allowed": False,
            "commit_allowed": False,
            "deploy_allowed": False,
            "migration_allowed": False,
            "main_branch_write_allowed": False,
            "blocked_actions": ["write_files", "commit", "open_pr", "merge", "deploy", "migration", "main_branch_write"],
            "message": "Nenhum repositório GitHub válido configurado para criação de branch.",
            "trace_id": trace_id,
        }
        return _admin_evolution_record_branch_create_execution(
            proposal=proposal,
            receipt=receipt,
            actor=actor,
            org_slug=org,
        )

    governance = {
        # Autorização interna restrita ao action=create_branch.
        # O receipt externo mantém escrita de arquivo/commit/PR/deploy bloqueados.
        "patch_mode": "approved_apply",
        "write_allowed": True,
        "human_approval_required": True,
        "human_approved": True,
        "approval_id": f"ao17b:{pid}",
        "audit_receipt_id": f"ao17b:{pid}",
        "risk_level": str(proposal.get("risk") or "baixo_medio"),
        "allowed_action": "create_branch_only",
        "proposal_id": pid,
    }

    repo_receipts: List[Dict[str, Any]] = []
    for target in targets:
        kind = str(target.get("kind") or "repo")
        repo = str(target.get("repo") or "")
        try:
            result = _github_create_branch_capability(
                branch=branch_name,
                repo_target=kind,
                user_text=f"AO-17B create governed temporary branch only for proposal {pid} in {kind}. No files, commit, PR, merge, deploy or migration.",
                trace_id=trace_id,
                governance=governance,
            )
        except Exception as e:
            result = {
                "handled": True,
                "success": False,
                "provider": "github",
                "repo": repo,
                "branch": branch_name,
                "message": f"Falha inesperada ao criar branch governada: {str(e)[:220]}",
            }

        msg = str(result.get("message") or "")
        msg_low = msg.lower()
        already_exists = ("já existe" in msg_low) or ("ja existe" in msg_low) or ("already exists" in msg_low)
        branch_created = bool(result.get("success"))
        ok = branch_created or already_exists

        repo_receipts.append({
            "ok": ok,
            "repo_kind": kind,
            "repo": str(result.get("repo") or repo),
            "branch": str(result.get("branch") or branch_name),
            "base_branch": str(result.get("base_branch") or ""),
            "verified_ref": str(result.get("verified_ref") or ""),
            "commit_sha": str(result.get("commit_sha") or ""),
            "branch_created": branch_created,
            "branch_already_exists": already_exists,
            "github_repo_status": result.get("github_repo_status"),
            "github_ref_status": result.get("github_ref_status"),
            "github_branch_status": result.get("github_branch_status"),
            "token_present": result.get("token_present"),
            "token_source": result.get("token_source"),
            "token_fingerprint": result.get("token_fingerprint"),
            "message": msg,
            "raw_success": bool(result.get("success")),
        })

    ok = bool(repo_receipts) and all(bool(x.get("ok")) for x in repo_receipts)
    branch_created = any(bool(x.get("branch_created")) for x in repo_receipts)
    branch_already_exists = bool(repo_receipts) and all(bool(x.get("branch_already_exists")) or bool(x.get("branch_created")) for x in repo_receipts)

    receipt = {
        "ok": ok,
        "stage": "AO-17B-CREATE",
        "mode": "branch_creation_only",
        "proposal_id": pid,
        "proposal_status": proposal.get("status"),
        "execution_status": proposal.get("execution_status"),
        "dry_run_completed": True,
        "branch": branch_name,
        "branch_name": branch_name,
        "suggested_branch": branch_name,
        "branch_created": branch_created,
        "branch_already_exists": branch_already_exists and not branch_created,
        "repo_receipts": repo_receipts,
        "trace_id": trace_id,
        "execution_enabled": False,
        "can_execute_real": False,
        "branch_create_allowed": True,
        "can_create_branch_again": False,
        "can_write_repository": False,
        "can_commit": False,
        "can_open_pr": False,
        "can_merge": False,
        "can_deploy": False,
        "can_run_migration": False,
        "write_allowed": False,
        "file_write_allowed": False,
        "commit_allowed": False,
        "deploy_allowed": False,
        "migration_allowed": False,
        "main_branch_write_allowed": False,
        "blocked_actions": ["write_files", "commit", "open_pr", "merge", "deploy", "migration", "main_branch_write"],
        "rollback_plan": (
            "Cleanup seguro: deletar somente a branch temporária criada neste receipt "
            f"({branch_name}), sem tocar main, commits, PRs, deploys ou migrations."
        ),
        "next_required_stage": "AO-17C file write only after explicit Admin approval and patch artifact validation",
        "message": (
            "Branch temporária criada/confirmada. Nenhum arquivo, commit, PR, merge, deploy ou migration foi executado."
            if ok
            else "Falha ao criar/confirmar branch temporária. Nenhum arquivo, commit, PR, merge, deploy ou migration foi executado."
        ),
    }

    try:
        logger.info(
            "ADMIN_EVOLUTION_AO17B_BRANCH_CREATE proposal_id=%s branch=%s ok=%s repos=%s actor=%s trace_id=%s",
            pid,
            branch_name,
            ok,
            ",".join([str(x.get("repo") or "") for x in repo_receipts]),
            actor,
            trace_id,
        )
    except Exception:
        pass

    return _admin_evolution_record_branch_create_execution(
        proposal=proposal,
        receipt=receipt,
        actor=actor,
        org_slug=org,
    )




# ================================
# AO-20 — Criação governada de Pull Request
# ================================

class AdminEvolutionCreatePullRequestRequest(BaseModel):
    source_branch: Optional[str] = None
    target_branch: Optional[str] = "main"
    repo_target: Optional[str] = "frontend"
    title: Optional[str] = None
    body: Optional[str] = None
    confirm_create_pr: Optional[bool] = False


def _admin_evolution_record_pr_create_execution(
    *,
    proposal: Dict[str, Any],
    receipt: Dict[str, Any],
    actor: str,
    org_slug: str,
) -> Dict[str, Any]:
    """Registra receipt auditável da criação governada de PR sem merge/deploy."""
    pid = str(proposal.get("proposal_id") or "").strip()
    if not pid:
        raise HTTPException(status_code=400, detail="proposal_id_required")

    execution_id = str(receipt.get("execution_id") or "").strip() or ("exec_" + uuid.uuid4().hex[:12])
    receipt["execution_id"] = execution_id

    if not _admin_evolution_bootstrap_db_schema():
        receipt["audit_recorded"] = False
        receipt["audit_record_error"] = "evolution_schema_unavailable"
        return receipt

    now = _admin_evolution_now()
    status = "pull_request_created" if bool(receipt.get("ok")) else "pull_request_failed"
    smoke_plan = [
        "Pull Request criado ou confirmado sem merge.",
        "Branch origem temporária foi validada.",
        "Branch destino main foi validada.",
        "Diff foi validado antes da criação do PR.",
        "Nenhum merge foi executado.",
        "Nenhum deploy foi executado.",
        "Nenhuma migration foi executada.",
        "main permaneceu sem escrita direta.",
    ]

    db = SessionLocal()
    try:
        db.execute(text("""
            INSERT INTO admin_evolution_executions (
                execution_id, proposal_id, org_slug, status, mode, created_by, approved_by,
                risk, rollback_plan, smoke_checklist_json, result_json,
                created_at, updated_at, started_at, finished_at
            ) VALUES (
                :execution_id, :proposal_id, :org_slug, :status, :mode, :created_by, :approved_by,
                :risk, :rollback_plan, :smoke_checklist_json, :result_json,
                :created_at, :updated_at, :started_at, :finished_at
            )
        """), {
            "execution_id": execution_id,
            "proposal_id": pid,
            "org_slug": org_slug,
            "status": status,
            "mode": "ao20_governed_create_pull_request_only",
            "created_by": str(actor or ""),
            "approved_by": str(proposal.get("approved_by") or ""),
            "risk": str(proposal.get("risk") or "baixo"),
            "rollback_plan": str(receipt.get("rollback_plan") or proposal.get("rollback_plan") or ""),
            "smoke_checklist_json": _admin_evolution_json_dump(smoke_plan),
            "result_json": _admin_evolution_json_dump(receipt),
            "created_at": now,
            "updated_at": now,
            "started_at": now,
            "finished_at": now,
        })
        db.execute(text("""
            UPDATE admin_evolution_proposals
            SET updated_at = :updated_at
            WHERE proposal_id = :proposal_id
        """), {"proposal_id": pid, "updated_at": now})
        db.commit()
        receipt["audit_recorded"] = True
        receipt["audit_execution_status"] = status
        return receipt
    except Exception as e:
        try:
            db.rollback()
        except Exception:
            pass
        try:
            logger.exception(
                "ADMIN_EVOLUTION_AO20_PR_RECEIPT_RECORD_FAILED proposal_id=%s execution_id=%s error=%s",
                pid,
                execution_id,
                str(e)[:240],
            )
        except Exception:
            pass
        receipt["audit_recorded"] = False
        receipt["audit_record_error"] = str(e)[:240]
        return receipt
    finally:
        try:
            db.close()
        except Exception:
            pass


def _admin_evolution_validate_ao20_pr_diff(
    *,
    repo_target: str,
    source_branch: str,
    target_branch: str,
    expected_files: List[str],
) -> Dict[str, Any]:
    """Valida diff líquido antes de criar PR governado AO-20."""
    from urllib.parse import quote

    repo, _, token, _repo_kind = _github_resolve_repo_branch(
        repo_target=repo_target,
        user_text="AO-20 create governed pull request diff validation",
    )
    if not token or not repo:
        raise HTTPException(status_code=503, detail="github_capability_unavailable")

    source = re.sub(r"^refs/heads/", "", str(source_branch or "").strip())
    target = re.sub(r"^refs/heads/", "", str(target_branch or "").strip())
    if not source or not target:
        raise HTTPException(status_code=400, detail="source_and_target_branch_required")

    status, body = _github_api_json(
        "GET",
        f"https://api.github.com/repos/{repo}/compare/{quote(target, safe='')}...{quote(source, safe='')}",
        None,
    )
    if status != 200 or not isinstance(body, dict):
        raise HTTPException(status_code=409, detail={
            "error": "github_compare_failed",
            "status": status,
            "message": (body.get("message") if isinstance(body, dict) else None) or "Falha ao comparar branches no GitHub.",
        })

    changed_files = []
    files = body.get("files") or []
    if isinstance(files, list):
        for item in files:
            if isinstance(item, dict) and item.get("filename"):
                changed_files.append(str(item.get("filename") or "").strip())

    changed_files = [x for x in changed_files if x]
    expected = [str(x or "").strip() for x in (expected_files or []) if str(x or "").strip()]
    if not expected:
        raise HTTPException(status_code=400, detail="expected_files_required")

    if sorted(changed_files) != sorted(expected):
        raise HTTPException(status_code=409, detail={
            "error": "unexpected_pr_diff_files",
            "expected_files": expected,
            "changed_files": changed_files,
        })

    ahead_by = int(body.get("ahead_by") or 0)
    if ahead_by <= 0:
        raise HTTPException(status_code=409, detail="source_branch_has_no_commits_ahead")

    return {
        "ok": True,
        "repo": repo,
        "repo_target": repo_target,
        "source_branch": source,
        "target_branch": target,
        "changed_files": changed_files,
        "ahead_by": ahead_by,
        "behind_by": int(body.get("behind_by") or 0),
        "total_commits": int(body.get("total_commits") or 0),
    }


# AO-20_GOVERNED_CREATE_PR_ROUTE
@app.post("/api/admin/evolution/proposals/{proposal_id}/create-pr")
def admin_evolution_proposal_create_pr(
    proposal_id: str,
    body: Optional[AdminEvolutionCreatePullRequestRequest] = None,
    x_org_slug: Optional[str] = Header(default=None),
    _admin=Depends(require_admin_access),
):
    """
    AO-20: cria somente Pull Request governado.

    Não faz merge, deploy, migration nem escrita direta em main.
    """
    actor = ""
    if isinstance(_admin, dict):
        actor = str(_admin.get("email") or _admin.get("sub") or "")

    org = get_org(x_org_slug)
    pid = str(proposal_id or "").strip()
    if not pid:
        raise HTTPException(status_code=400, detail="proposal_id_required")

    proposal = _admin_evolution_get_proposal(pid)
    if not proposal:
        raise HTTPException(status_code=404, detail="proposal_not_found")

    if str(proposal.get("status") or "").strip().lower() != "approved":
        raise HTTPException(status_code=409, detail="proposal_must_be_approved_before_create_pr")

    if str(proposal.get("execution_status") or "").strip() != "dry_run_completed":
        raise HTTPException(status_code=409, detail="dry_run_must_be_completed_before_create_pr")

    body_obj = body if isinstance(body, AdminEvolutionCreatePullRequestRequest) else AdminEvolutionCreatePullRequestRequest()
    if not bool(body_obj.confirm_create_pr):
        raise HTTPException(status_code=409, detail="confirm_create_pr_required")

    plan = _admin_evolution_build_branch_pr_plan(proposal)
    if str(plan.get("stage") or "").strip() != "AO-19":
        raise HTTPException(status_code=409, detail={
            "error": "proposal_is_not_ao19_pr_stage",
            "stage": plan.get("stage"),
        })

    source_branch = str(body_obj.source_branch or plan.get("source_branch") or plan.get("head_branch") or "").strip()
    target_branch = str(body_obj.target_branch or plan.get("target_branch") or plan.get("base_branch") or "main").strip() or "main"
    repo_target = str(body_obj.repo_target or plan.get("repo_target") or "frontend").strip().lower() or "frontend"

    source_branch = re.sub(r"^refs/heads/", "", source_branch)
    target_branch = re.sub(r"^refs/heads/", "", target_branch)

    if repo_target not in {"frontend", "web", "ui"}:
        raise HTTPException(status_code=400, detail="ao20_only_frontend_repo_supported")
    repo_target = "frontend"

    if not source_branch.startswith("ao-17/"):
        raise HTTPException(status_code=400, detail="source_branch_must_be_ao17_temporary_branch")

    if target_branch != "main":
        raise HTTPException(status_code=400, detail="ao20_target_branch_must_be_main")

    expected_files = plan.get("target_files") or proposal.get("target_files") or []
    expected_files = [str(x or "").strip() for x in expected_files if str(x or "").strip()]
    if expected_files != ["src/routes/legal/Terms.jsx"]:
        raise HTTPException(status_code=409, detail={
            "error": "ao20_unexpected_target_files",
            "expected_contract": ["src/routes/legal/Terms.jsx"],
            "actual_target_files": expected_files,
        })

    diff_receipt = _admin_evolution_validate_ao20_pr_diff(
        repo_target=repo_target,
        source_branch=source_branch,
        target_branch=target_branch,
        expected_files=expected_files,
    )

    trace_id = f"ao20_{pid}_{uuid.uuid4().hex[:8]}"
    title = str(body_obj.title or plan.get("suggested_pr_title") or "AO-19 — Criação Governada de Pull Request").strip()
    if title.startswith("AO-19: AO-19"):
        title = "AO-19 — Criação Governada de Pull Request"

    pr_body = str(body_obj.body or "").strip() or (
        "PR governado criado pelo Orkio AO-20.\n\n"
        f"- proposal_id: {pid}\n"
        f"- source_branch: {source_branch}\n"
        f"- target_branch: {target_branch}\n"
        "- merge: bloqueado\n"
        "- deploy: bloqueado\n"
        "- migration: bloqueada\n"
        "- main_direct_write: bloqueada\n"
    )

    # AO-20_CENTRAL_GOVERNANCE_APPROVED_APPLY_PAYLOAD
    # The central GitHub write enforcer requires patch_mode=approved_apply,
    # write_allowed=true and human_approved=true even when the only allowed
    # action is opening a PR. Merge/deploy/migration/main remain blocked below.
    approval_ref = str(proposal.get("approved_by") or actor or pid or "").strip()
    governance = {
        "source": "admin_evolution_ao20",
        "proposal_id": pid,
        "patch_mode": "approved_apply",
        "write_allowed": True,
        "human_approval_required": True,
        "human_approved": True,
        "human_approval_observed": True,
        "approved_by": approval_ref,
        "approval_id": f"ao20_create_pr:{pid}",
        "audit_receipt_id": f"ao20_create_pr:{pid}",
        "risk_level": str(proposal.get("risk") or "baixo"),
        "allowed_write_actions": ["open_pr"],
        "open_pr": True,
        "allow_pr": True,
        "pr_allowed": True,
        "main_branch_write_allowed": False,
        "merge_allowed": False,
        "deploy_allowed": False,
        "migration_allowed": False,
    }

    pr_result = _github_create_pull_request_capability(
        head=source_branch,
        base=target_branch,
        title=title,
        repo_target=repo_target,
        user_text="AO-20 create governed Pull Request from AdminEvolutionCenter",
        body=pr_body,
        trace_id=trace_id,
        governance=governance,
    )

    ok = bool(isinstance(pr_result, dict) and pr_result.get("success"))
    receipt = {
        "ok": ok,
        "stage": "AO-20",
        "mode": "governed_create_pull_request_only",
        "proposal_id": pid,
        "execution_id": "exec_" + uuid.uuid4().hex[:12],
        "source_branch": source_branch,
        "target_branch": target_branch,
        "repo_target": repo_target,
        "target_files": expected_files,
        "diff_validation": diff_receipt,
        "pull_request": pr_result,
        "pull_request_number": pr_result.get("pull_request_number") if isinstance(pr_result, dict) else None,
        "pull_request_url": pr_result.get("pull_request_url") if isinstance(pr_result, dict) else None,
        "merge_allowed": False,
        "deploy_allowed": False,
        "migration_allowed": False,
        "main_branch_write_allowed": False,
        "rollback_plan": str(proposal.get("rollback_plan") or "Rollback seguro: fechar o Pull Request sem merge."),
        "message": (
            "AO-20 criou Pull Request governado. Merge, deploy e migration permanecem bloqueados."
            if ok
            else "AO-20 não conseguiu criar Pull Request governado. Nenhum merge, deploy ou migration foi executado."
        ),
    }

    recorded = _admin_evolution_record_pr_create_execution(
        proposal=proposal,
        receipt=receipt,
        actor=actor,
        org_slug=org,
    )

    return {
        "ok": ok,
        "stage": "AO-20",
        "proposal_id": pid,
        "execution_enabled": False,
        "can_execute_real": False,
        "pull_request_created": ok,
        "pull_request_number": recorded.get("pull_request_number"),
        "pull_request_url": recorded.get("pull_request_url"),
        "source_branch": source_branch,
        "target_branch": target_branch,
        "repo_target": repo_target,
        "merge_allowed": False,
        "deploy_allowed": False,
        "migration_allowed": False,
        "main_branch_write_allowed": False,
        "receipt": recorded,
    }






# ================================
# AO-22B — Execução governada de merge do Pull Request
# ================================

class AdminEvolutionMergePullRequestRequest(BaseModel):
    pr_number: Optional[int] = 6
    source_branch: Optional[str] = "ao-17/evo_f05bef3b8228"
    target_branch: Optional[str] = "main"
    repo_target: Optional[str] = "frontend"
    merge_method: Optional[str] = "merge"
    commit_title: Optional[str] = None
    commit_message: Optional[str] = None
    confirm_merge_pr: Optional[bool] = False


def _admin_evolution_validate_ao22_merge_preflight(
    *,
    repo_target: str,
    pr_number: int,
    source_branch: str,
    target_branch: str,
    expected_files: List[str],
) -> Dict[str, Any]:
    """Valida PR #6 antes de qualquer merge governado AO-22B."""
    from urllib.parse import quote

    repo, _, token, _repo_kind = _github_resolve_repo_branch(
        repo_target=repo_target,
        user_text="AO-22B governed merge preflight",
    )
    if not token or not repo:
        raise HTTPException(status_code=503, detail="github_capability_unavailable")

    prn = int(pr_number or 0)
    if prn != 6:
        raise HTTPException(status_code=400, detail="ao22b_only_pr_6_supported")

    source = re.sub(r"^refs/heads/", "", str(source_branch or "").strip())
    target = re.sub(r"^refs/heads/", "", str(target_branch or "").strip())
    if source != "ao-17/evo_f05bef3b8228":
        raise HTTPException(status_code=400, detail="ao22b_source_branch_mismatch")
    if target != "main":
        raise HTTPException(status_code=400, detail="ao22b_target_branch_must_be_main")

    expected = [str(x or "").strip() for x in (expected_files or []) if str(x or "").strip()]
    if expected != ["src/routes/legal/Terms.jsx"]:
        raise HTTPException(status_code=409, detail={
            "error": "ao22b_unexpected_target_files",
            "expected_contract": ["src/routes/legal/Terms.jsx"],
            "actual_target_files": expected,
        })

    status_pr, pr_body = _github_api_json(
        "GET",
        f"https://api.github.com/repos/{repo}/pulls/{prn}",
        None,
    )
    if status_pr != 200 or not isinstance(pr_body, dict):
        raise HTTPException(status_code=409, detail={
            "error": "github_pr_lookup_failed",
            "status": status_pr,
            "message": (pr_body.get("message") if isinstance(pr_body, dict) else None) or "Falha ao consultar PR no GitHub.",
        })

    if str(pr_body.get("state") or "").strip().lower() != "open":
        raise HTTPException(status_code=409, detail={
            "error": "pr_not_open",
            "state": pr_body.get("state"),
        })

    if bool(pr_body.get("draft")):
        raise HTTPException(status_code=409, detail="pr_is_draft")

    head_ref = str(((pr_body.get("head") or {}).get("ref")) or "").strip()
    base_ref = str(((pr_body.get("base") or {}).get("ref")) or "").strip()
    if head_ref != source or base_ref != target:
        raise HTTPException(status_code=409, detail={
            "error": "pr_branch_contract_mismatch",
            "expected_head": source,
            "actual_head": head_ref,
            "expected_base": target,
            "actual_base": base_ref,
        })

    status_files, files_body = _github_api_json(
        "GET",
        f"https://api.github.com/repos/{repo}/pulls/{prn}/files",
        None,
    )
    if status_files != 200 or not isinstance(files_body, list):
        raise HTTPException(status_code=409, detail={
            "error": "github_pr_files_lookup_failed",
            "status": status_files,
        })

    changed_files: List[str] = []
    for item in files_body:
        if isinstance(item, dict) and item.get("filename"):
            changed_files.append(str(item.get("filename") or "").strip())
    changed_files = [x for x in changed_files if x]

    if sorted(changed_files) != sorted(expected):
        raise HTTPException(status_code=409, detail={
            "error": "unexpected_pr_files_before_merge",
            "expected_files": expected,
            "changed_files": changed_files,
        })

    compare_receipt = _admin_evolution_validate_ao20_pr_diff(
        repo_target=repo_target,
        source_branch=source,
        target_branch=target,
        expected_files=expected,
    )

    mergeable = pr_body.get("mergeable")
    mergeable_state = str(pr_body.get("mergeable_state") or "").strip()
    if mergeable is False or mergeable_state.lower() in {"dirty", "blocked"}:
        raise HTTPException(status_code=409, detail={
            "error": "pr_not_mergeable",
            "mergeable": mergeable,
            "mergeable_state": mergeable_state,
        })

    return {
        "ok": True,
        "repo": repo,
        "repo_target": repo_target,
        "pr_number": prn,
        "pr_url": str(pr_body.get("html_url") or "").strip(),
        "source_branch": source,
        "target_branch": target,
        "head_ref": head_ref,
        "base_ref": base_ref,
        "state": str(pr_body.get("state") or "").strip(),
        "draft": bool(pr_body.get("draft")),
        "mergeable": mergeable,
        "mergeable_state": mergeable_state,
        "changed_files": changed_files,
        "compare": compare_receipt,
    }


def _github_merge_pull_request_capability(
    *,
    repo_target: str,
    pr_number: int,
    merge_method: str,
    commit_title: str,
    commit_message: str,
    trace_id: str,
    governance: Dict[str, Any],
) -> Dict[str, Any]:
    """Executa merge governado de PR via GitHub, sem deploy/migration."""
    repo, _, token, _repo_kind = _github_resolve_repo_branch(
        repo_target=repo_target,
        user_text="AO-22B governed merge pull request",
    )
    blocked = _github_enforce_governed_write(
        action="merge_pr",
        governance=governance,
        repo=repo,
        branch="main",
    )
    if blocked:
        return blocked

    if not token or not repo:
        return {"handled": True, "success": False, "provider": "github", "message": "GitHub capability não está habilitada no ambiente."}

    prn = int(pr_number or 0)
    method = str(merge_method or "merge").strip().lower()
    if method not in {"merge", "squash", "rebase"}:
        method = "merge"

    cache_key = _github_action_cache_key(
        "merge_pr",
        repo,
        str(prn),
        method,
        commit_title,
        commit_message,
        trace_id,
    )
    cached = _github_action_cache_get(cache_key)
    if cached:
        return cached

    payload = {
        "merge_method": method,
        "commit_title": commit_title or f"AO-22B governed merge PR #{prn}",
        "commit_message": commit_message or f"Governed merge executed by Orkio AO-22B. trace_id={trace_id}",
    }

    _github_log("GITHUB_PR_MERGE_ATTEMPT", repo=repo, number=prn, method=method, trace_id=trace_id or "")
    status, body = _github_api_json(
        "PUT",
        f"https://api.github.com/repos/{repo}/pulls/{prn}/merge",
        payload,
    )

    if status != 200 or not isinstance(body, dict) or not bool(body.get("merged")):
        msg = (body.get("message") if isinstance(body, dict) else None) or "Falha ao executar merge do Pull Request no GitHub."
        _github_log("GITHUB_PR_MERGE_FAILED", repo=repo, number=prn, status=status, trace_id=trace_id or "")
        return {
            "handled": True,
            "success": False,
            "provider": "github",
            "repo": repo,
            "pull_request_number": prn,
            "status": status,
            "message": msg,
            "body": body if isinstance(body, dict) else {},
        }

    sha = str(body.get("sha") or "").strip()
    result = {
        "handled": True,
        "success": True,
        "provider": "github",
        "repo": repo,
        "pull_request_number": prn,
        "merged": True,
        "merge_commit_sha": sha,
        "message": str(body.get("message") or "Pull Request mergeado com confirmação operacional."),
    }
    _github_log("GITHUB_PR_MERGE_OK", repo=repo, number=prn, sha=sha, trace_id=trace_id or "")
    return _github_action_cache_put(cache_key, result, ttl_seconds=30)


def _admin_evolution_record_merge_execution(
    *,
    proposal: Dict[str, Any],
    receipt: Dict[str, Any],
    actor: str,
    org_slug: str,
) -> Dict[str, Any]:
    """Registra receipt auditável do merge governado AO-22B."""
    pid = str(proposal.get("proposal_id") or "").strip()
    execution_id = str(receipt.get("execution_id") or "").strip() or ("exec_" + uuid.uuid4().hex[:12])
    receipt["execution_id"] = execution_id

    if not _admin_evolution_bootstrap_db_schema():
        receipt["audit_recorded"] = False
        receipt["audit_record_error"] = "evolution_schema_unavailable"
        return receipt

    now = _admin_evolution_now()
    status = "merge_completed" if bool(receipt.get("ok")) else "merge_failed"
    smoke_plan = [
        "PR #6 foi validado antes do merge.",
        "Files changed continha apenas src/routes/legal/Terms.jsx.",
        "Merge foi executado apenas se confirm_merge_pr=true.",
        "Nenhum deploy foi executado.",
        "Nenhuma migration foi executada.",
        "Rollback plan está presente.",
    ]

    db = SessionLocal()
    try:
        db.execute(text("""
            INSERT INTO admin_evolution_executions (
                execution_id, proposal_id, org_slug, status, mode, created_by, approved_by,
                risk, rollback_plan, smoke_checklist_json, result_json,
                created_at, updated_at, started_at, finished_at
            ) VALUES (
                :execution_id, :proposal_id, :org_slug, :status, :mode, :created_by, :approved_by,
                :risk, :rollback_plan, :smoke_checklist_json, :result_json,
                :created_at, :updated_at, :started_at, :finished_at
            )
        """), {
            "execution_id": execution_id,
            "proposal_id": pid,
            "org_slug": org_slug,
            "status": status,
            "mode": "ao22b_governed_merge_pull_request",
            "created_by": str(actor or ""),
            "approved_by": str(proposal.get("approved_by") or ""),
            "risk": str(proposal.get("risk") or "baixo"),
            "rollback_plan": str(receipt.get("rollback_plan") or proposal.get("rollback_plan") or ""),
            "smoke_checklist_json": _admin_evolution_json_dump(smoke_plan),
            "result_json": _admin_evolution_json_dump(receipt),
            "created_at": now,
            "updated_at": now,
            "started_at": now,
            "finished_at": now,
        })
        db.execute(text("""
            UPDATE admin_evolution_proposals
            SET updated_at = :updated_at
            WHERE proposal_id = :proposal_id
        """), {"proposal_id": pid, "updated_at": now})
        db.commit()
        receipt["audit_recorded"] = True
        receipt["audit_execution_status"] = status
        return receipt
    except Exception as e:
        try:
            db.rollback()
        except Exception:
            pass
        try:
            logger.exception(
                "ADMIN_EVOLUTION_AO22B_MERGE_RECEIPT_RECORD_FAILED proposal_id=%s execution_id=%s error=%s",
                pid,
                execution_id,
                str(e)[:240],
            )
        except Exception:
            pass
        receipt["audit_recorded"] = False
        receipt["audit_record_error"] = str(e)[:240]
        return receipt
    finally:
        try:
            db.close()
        except Exception:
            pass


# AO-22B_GOVERNED_MERGE_PR_ROUTE
@app.post("/api/admin/evolution/proposals/{proposal_id}/merge-pr")
def admin_evolution_proposal_merge_pr(
    proposal_id: str,
    body: Optional[AdminEvolutionMergePullRequestRequest] = None,
    x_org_slug: Optional[str] = Header(default=None),
    _admin=Depends(require_admin_access),
):
    """
    AO-22B: executa somente merge governado do PR #6.

    Não faz deploy, migration nem escrita direta em main fora do merge do PR.
    """
    actor = ""
    if isinstance(_admin, dict):
        actor = str(_admin.get("email") or _admin.get("sub") or "")

    org = get_org(x_org_slug)
    pid = str(proposal_id or "").strip()
    if not pid:
        raise HTTPException(status_code=400, detail="proposal_id_required")

    proposal = _admin_evolution_get_proposal(pid)
    if not proposal:
        raise HTTPException(status_code=404, detail="proposal_not_found")

    if str(proposal.get("status") or "").strip().lower() != "approved":
        raise HTTPException(status_code=409, detail="proposal_must_be_approved_before_merge")

    if str(proposal.get("execution_status") or "").strip() != "dry_run_completed":
        raise HTTPException(status_code=409, detail="dry_run_must_be_completed_before_merge")

    plan = _admin_evolution_build_branch_pr_plan(proposal)
    if str(plan.get("stage") or "").strip() != "AO-22":
        raise HTTPException(status_code=409, detail={
            "error": "proposal_is_not_ao22_merge_stage",
            "stage": plan.get("stage"),
            "mode": plan.get("mode"),
        })

    body_obj = body if isinstance(body, AdminEvolutionMergePullRequestRequest) else AdminEvolutionMergePullRequestRequest()
    if not bool(body_obj.confirm_merge_pr):
        raise HTTPException(status_code=409, detail="confirm_merge_pr_required")

    pr_number = int(body_obj.pr_number or plan.get("pr_number") or 0)
    source_branch = str(body_obj.source_branch or plan.get("source_branch") or plan.get("head_branch") or "").strip()
    target_branch = str(body_obj.target_branch or plan.get("target_branch") or plan.get("base_branch") or "main").strip() or "main"
    repo_target = str(body_obj.repo_target or plan.get("repo_target") or "frontend").strip().lower() or "frontend"
    if repo_target not in {"frontend", "web", "ui"}:
        raise HTTPException(status_code=400, detail="ao22b_only_frontend_repo_supported")
    repo_target = "frontend"

    expected_files = plan.get("target_files") or proposal.get("target_files") or []
    expected_files = [str(x or "").strip() for x in expected_files if str(x or "").strip()]

    preflight = _admin_evolution_validate_ao22_merge_preflight(
        repo_target=repo_target,
        pr_number=pr_number,
        source_branch=source_branch,
        target_branch=target_branch,
        expected_files=expected_files,
    )

    trace_id = f"ao22b_{pid}_{uuid.uuid4().hex[:8]}"
    approval_ref = str(proposal.get("approved_by") or actor or pid or "").strip()
    governance = {
        "source": "admin_evolution_ao22b",
        "proposal_id": pid,
        "patch_mode": "approved_apply",
        "write_allowed": True,
        "human_approval_required": True,
        "human_approved": True,
        "human_approval_observed": True,
        "approved_by": approval_ref,
        "approval_id": f"ao22b_merge_pr:{pid}",
        "audit_receipt_id": f"ao22b_merge_pr:{pid}",
        "risk_level": str(proposal.get("risk") or "baixo"),
        "allowed_write_actions": ["merge_pr"],
        "merge_pr_allowed": True,
        "merge_allowed": True,
        "deploy_allowed": False,
        "migration_allowed": False,
        "main_direct_write_allowed": False,
        "main_branch_write_allowed": False,
    }

    title = str(body_obj.commit_title or "AO-22B — Merge Governado do Pull Request #6").strip()
    message = str(body_obj.commit_message or (
        "Merge governado executado pelo Orkio AO-22B.\n\n"
        f"- proposal_id: {pid}\n"
        f"- pr_number: {pr_number}\n"
        "- deploy: bloqueado\n"
        "- migration: bloqueada\n"
        "- rollback: revert do merge commit ou PR corretivo\n"
    )).strip()

    merge_result = _github_merge_pull_request_capability(
        repo_target=repo_target,
        pr_number=pr_number,
        merge_method=str(body_obj.merge_method or "merge"),
        commit_title=title,
        commit_message=message,
        trace_id=trace_id,
        governance=governance,
    )

    ok = bool(isinstance(merge_result, dict) and merge_result.get("success"))
    receipt = {
        "ok": ok,
        "stage": "AO-22B",
        "mode": "governed_merge_pull_request",
        "proposal_id": pid,
        "execution_id": "exec_" + uuid.uuid4().hex[:12],
        "pr_number": pr_number,
        "pr_url": preflight.get("pr_url"),
        "source_branch": preflight.get("source_branch"),
        "target_branch": preflight.get("target_branch"),
        "repo_target": repo_target,
        "target_files": expected_files,
        "preflight": preflight,
        "merge": merge_result,
        "merge_executed": ok,
        "merge_commit_sha": merge_result.get("merge_commit_sha") if isinstance(merge_result, dict) else "",
        "deploy_allowed": False,
        "migration_allowed": False,
        "main_direct_write_allowed": False,
        "rollback_plan": str(proposal.get("rollback_plan") or "Rollback: revert do merge commit ou novo PR corretivo, sem deploy automático."),
        "message": (
            "AO-22B executou merge governado do PR #6. Deploy e migration permanecem bloqueados."
            if ok
            else "AO-22B não conseguiu executar merge governado. Nenhum deploy ou migration foi executado."
        ),
    }

    recorded = _admin_evolution_record_merge_execution(
        proposal=proposal,
        receipt=receipt,
        actor=actor,
        org_slug=org,
    )

    return {
        "ok": ok,
        "stage": "AO-22B",
        "proposal_id": pid,
        "execution_enabled": False,
        "can_execute_real": False,
        "merge_executed": ok,
        "merge_commit_sha": recorded.get("merge_commit_sha"),
        "pr_number": pr_number,
        "pr_url": preflight.get("pr_url"),
        "deploy_allowed": False,
        "migration_allowed": False,
        "main_direct_write_allowed": False,
        "receipt": recorded,
    }




