            "móvel",
            "movel",
            "landing",
            "landing page",
            "botão de login",
            "botao de login",
            "login na landing",
            "onboarding",
            "lista de chats",
            "lista dos chats",
            "lista de conversas",
            "lista de threads",
            "threads",
            "sidebar",
            "menu lateral",
            "nao aparece a lista",
