@app.post("/api/tts")
async def tts_endpoint(
    inp: TTSIn,
    x_org_slug: Optional[str] = Header(default=None),
    x_trace_id: Optional[str] = Header(default=None),
    user=Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """V2V-PATCH: Generate speech audio from text (OpenAI TTS).
    Returns audio/mpeg. Resolves voice: message_id → agent_id → inp.voice → default voice.
    Emits structured logs: v2v_tts_ok / v2v_tts_fail."""
    trace_id = x_trace_id or new_id()
    if OpenAI is None:
        raise HTTPException(status_code=503, detail="OpenAI SDK not available")
    api_key = os.getenv("OPENAI_API_KEY", "").strip()
    if not api_key:
        raise HTTPException(status_code=503, detail="OPENAI_API_KEY not configured")

    org = get_request_org(user, x_org_slug)

    # Resolve voice: admin/db → env-by-agent → explicit inp.voice → configured default
    # AO47B1_REALTIME_DUPLICATE_AUDIO_GUARD
    # Evita áudio duplicado: quando há sessão Realtime ativa no mesmo thread,
    # o TTS clássico não deve gerar uma segunda fala.
    try:
        tts_thread_id = str(getattr(inp, "thread_id", "") or "").strip()
    except Exception:
        tts_thread_id = ""

    if tts_thread_id:
        try:
            active_realtime = db.execute(
                select(RealtimeSession)
                .where(
                    RealtimeSession.org_slug == org,
                    RealtimeSession.thread_id == tts_thread_id,
                    RealtimeSession.ended_at.is_(None),
                )
                .order_by(RealtimeSession.started_at.desc())
            ).scalar_one_or_none()

            if active_realtime:
                logger.warning(
                    "AO47B1_TTS_BLOCKED_DURING_ACTIVE_REALTIME trace_id=%s org=%s thread_id=%s realtime_session_id=%s",
                    trace_id,
                    org,
                    tts_thread_id,
                    active_realtime.id,
                )
                return {
                    "ok": True,
                    "blocked": True,
                    "reason": "active_realtime_session",
                    "thread_id": tts_thread_id,
                    "realtime_session_id": active_realtime.id,
                }
        except Exception:
            logger.exception(
                "AO47B1_REALTIME_DUPLICATE_AUDIO_GUARD_FAILED trace_id=%s org=%s thread_id=%s",
                trace_id,
                org,
                tts_thread_id,
            )

    # AO65V-BE1 — Voice Identity Alignment for /api/tts.
    # Explicit inp.voice must win over message_id/agent_id/database voice.
    # This keeps the message playback button aligned with the intended Orkio voice.
    default_tts_voice = _normalize_voice_id(
        (
            os.getenv("OPENAI_TTS_VOICE_DEFAULT", "")
            or os.getenv("OPENAI_REALTIME_VOICE_DEFAULT", "")
            or os.getenv("ORKIO_VOICE_ID", "")
            or "cedar"
        ),
        default="cedar",
    )
    _VALID_VOICES = ("alloy","ash","ballad","cedar","coral","echo","fable","marin","nova","onyx","sage","shimmer","verse")

    requested_voice_raw = str(getattr(inp, "voice", "") or "").strip()
    requested_voice = (
        _normalize_voice_id(requested_voice_raw, default=default_tts_voice)
        if requested_voice_raw
        else ""
    )

    voice = requested_voice or default_tts_voice
    resolved_via = "inp.voice" if requested_voice else "default"
    fallback_used = False

    try:
        # AO65V-BE1:
        # If the frontend explicitly sends a voice, do not let message_id/agent_id
        # or Agent.voice_id override it. This is required for voice identity lock.
        if not requested_voice:
            if inp.message_id:
                msg = db.execute(select(Message).where(
                    Message.org_slug == org, Message.id == inp.message_id
                )).scalar_one_or_none()
                if msg and msg.agent_id:
                    agent = db.execute(select(Agent).where(
                        Agent.org_slug == org, Agent.id == msg.agent_id
                    )).scalar_one_or_none()
                    if agent:
                        voice = resolve_agent_voice(agent)
                        resolved_via = f"message_id→agent:{agent.name}"
            elif inp.agent_id:
                agent = db.execute(select(Agent).where(
                    Agent.org_slug == org, Agent.id == inp.agent_id
                )).scalar_one_or_none()
                if agent:
                    voice = resolve_agent_voice(agent)
                    resolved_via = f"agent_id:{agent.name}"
    except Exception:
        logger.exception("TTS_VOICE_RESOLVE_FAILED trace_id=%s", trace_id)

    if voice not in _VALID_VOICES:
        voice = default_tts_voice if default_tts_voice in _VALID_VOICES else "cedar"
        resolved_via = f"{resolved_via}|invalid_voice_default"

    safe_resolved_via = _ascii_safe_text(resolved_via) or "default"
    speed = max(0.25, min(4.0, inp.speed))
    # Keep the legacy browser-safe format unless the endpoint is deliberately
    # refactored to negotiate media type per format.
    tts_format = "mp3"
    tts_input = _sanitize_tts_text(inp.text)
    if not tts_input:
        raise HTTPException(status_code=400, detail="TTS text is empty after sanitization")

    tts_model = os.getenv("OPENAI_TTS_MODEL", "gpt-4o-mini-tts").strip() or "gpt-4o-mini-tts"
    logger.info(
        "v2v_play_start trace_id=%s org=%s requested_voice=%s resolved_voice=%s resolved_via=%s chars=%d model=%s format=%s",
        trace_id,
        org,
        requested_voice or "",
        voice,
        resolved_via,
        len(tts_input),
        tts_model,
        tts_format,
    )

    try:
        client = OpenAI(api_key=api_key)
        response = client.audio.speech.create(
            model=tts_model,
            voice=voice,
            input=tts_input,
            speed=speed,
            response_format=tts_format,
        )
        from fastapi.responses import StreamingResponse
        import io
        audio_bytes = _read_audio_bytes(response)
        logger.info(
            "v2v_tts_ok trace_id=%s org=%s voice=%s bytes=%d",
            trace_id, org, voice, len(audio_bytes),
        )
        return StreamingResponse(
            io.BytesIO(audio_bytes),
            media_type="audio/mpeg",
            headers={
                "Content-Disposition": "inline; filename=tts.mp3",
                "Cache-Control": "no-cache",
                "X-Trace-Id": trace_id,
                "X-V2V-Voice": voice,
                "X-V2V-Requested-Voice": requested_voice or "",
                "X-V2V-Resolved-Voice": voice,
                "X-V2V-Resolved-Via": safe_resolved_via,
                "X-V2V-TTS-Format": tts_format,
                "X-V2V-Fallback-Used": "false",
            },
        )
    except Exception as e:
        # AO65V-BE1:
        # If the caller explicitly requested a voice, never silently switch to a
        # different voice. A 502 is safer than speaking with the wrong identity.
        if requested_voice:
            logger.exception(
                "v2v_tts_fail trace_id=%s model=%s requested_voice=%s resolved_voice=%s resolved_via=%s fallback_used=%s error=%s",
                trace_id,
                tts_model,
                requested_voice,
                voice,
                resolved_via,
                False,
                str(e),
            )
            raise HTTPException(status_code=502, detail=f"TTS generation failed for requested voice {voice}: {str(e)}")

        fallback_used = True
        fallback_voice = {"cedar": "nova", "marin": "alloy"}.get(voice, "nova")
        logger.warning(
            "v2v_tts_fallback trace_id=%s org=%s original_model=%s original_voice=%s fallback_model=%s fallback_voice=%s requested_voice=%s resolved_via=%s error=%s",
            trace_id,
            org,
            tts_model,
            voice,
            "gpt-4o-mini-tts",
            fallback_voice,
            requested_voice or "",
            resolved_via,
            str(e),
        )
        try:
            response = client.audio.speech.create(
                model="gpt-4o-mini-tts",
                voice=fallback_voice,
                input=tts_input,
                speed=speed,
                response_format=tts_format,
            )
            from fastapi.responses import StreamingResponse
            import io
            audio_bytes = _read_audio_bytes(response)
            logger.info(
                "v2v_tts_ok trace_id=%s org=%s voice=%s bytes=%d fallback_used=%s",
                trace_id,
                org,
                fallback_voice,
                len(audio_bytes),
                fallback_used,
            )
            return StreamingResponse(
                io.BytesIO(audio_bytes),
                media_type="audio/mpeg",
                headers={
                    "Content-Disposition": "inline; filename=tts.mp3",
                    "Cache-Control": "no-cache",
                    "X-Trace-Id": trace_id,
                    "X-V2V-Voice": fallback_voice,
                    "X-V2V-Requested-Voice": requested_voice or "",
                    "X-V2V-Resolved-Voice": fallback_voice,
                    "X-V2V-Resolved-Via": safe_resolved_via,
                    "X-V2V-TTS-Format": tts_format,
                    "X-V2V-Fallback-Used": "true",
                },
            )
        except Exception as e2:
            logger.exception("v2v_tts_fail trace_id=%s model=%s voice=%s fallback_used=%s error=%s", trace_id, tts_model, voice, True, str(e2))
            raise HTTPException(status_code=502, detail=f"TTS generation failed: {str(e2)} (check OPENAI_TTS_MODEL/voice/key)")


# Public TTS for landing page (rate-limited by text length)
@app.post("/api/public/tts")
async def public_tts_endpoint(inp: TTSIn, request: Request):
    """Public TTS endpoint (no auth) — limited to 500 chars for landing/demo."""
    if len(inp.text) > 500:
        raise HTTPException(status_code=400, detail="Public TTS limited to 500 characters")
    # Rate limit: máximo PUBLIC_TTS_MAX_PER_MINUTE chamadas/IP/minuto
    _ip = request.client.host if request.client else "unknown"
    _now = time.time()
    with _public_tts_lock:
        calls = _public_tts_calls.get(_ip, [])
        calls = [t for t in calls if _now - t < 60]
        if len(calls) >= _PUBLIC_TTS_MAX_PER_MINUTE:
            # Atualizar mesmo no 429 para não vazar entry vazia
            _public_tts_calls[_ip] = calls
            raise HTTPException(status_code=429, detail="Too many TTS requests. Try again in a minute.")
        calls.append(_now)
        _public_tts_calls[_ip] = calls
        # F-08 FIX: eviction periódica — remover IPs com janela expirada para evitar memory leak
        # Executa 1/50 das chamadas (heurística barata, sem overhead de timer separado)
        if len(_public_tts_calls) > 200:
            _stale = [ip for ip, ts_list in _public_tts_calls.items()
                      if not ts_list or (_now - max(ts_list)) > 120]
            for ip in _stale:
                del _public_tts_calls[ip]
    if OpenAI is None:
        raise HTTPException(status_code=503, detail="OpenAI SDK not available")
    api_key = os.getenv("OPENAI_API_KEY", "").strip()
    if not api_key:
        raise HTTPException(status_code=503, detail="OPENAI_API_KEY not configured")

    voice = inp.voice if inp.voice in ("alloy", "echo", "fable", "onyx", "nova", "shimmer", "cedar", "ash", "ballad", "coral", "marin", "sage", "verse") else "cedar"
    try:
        client = OpenAI(api_key=api_key)
        response = client.audio.speech.create(
            model=os.getenv("OPENAI_TTS_MODEL", "gpt-4o-mini-tts").strip() or "gpt-4o-mini-tts",
            voice=voice,
            input=inp.text[:500],
            speed=max(0.25, min(4.0, inp.speed)),
            response_format="mp3",
        )
        from fastapi.responses import StreamingResponse
        import io
        return StreamingResponse(
            io.BytesIO(response.content),
            media_type="audio/mpeg",
            headers={"Content-Disposition": "inline; filename=tts.mp3", "Cache-Control": "no-cache"},
        )
    except Exception as e:
        logger.exception("PUBLIC_TTS_FAILED")
        raise HTTPException(status_code=500, detail=f"TTS failed: {str(e)}")


# Speech-to-Text (STT) endpoint using Whisper

def _normalize_stt_text(text: str) -> str:
    s = (text or "").strip()
    if not s:
        return ""
    s = re.sub(r"\s+", " ", s).strip()
    s = s[:1].upper() + s[1:] if s else s
    if re.search(r"[.!?…]$", s):
        return s
    lower = s.lower()
    question_starters = (
        "quem", "que", "qual", "quais", "quando", "onde", "como", "por que",
        "porque", "quanto", "quantos", "pode", "poderia", "devo", "será", "sera",
        "você", "voce", "há", "ha", "tem", "existe"
    )
    first = lower.split(" ", 1)[0]
    is_question = (
        lower.startswith(question_starters)
        or first in question_starters
        or lower.endswith(" né")
        or lower.endswith(" nao")
        or lower.endswith(" não")
    )
    # Avoid forcing punctuation on very short fragments that are often interim speech
    if len(s.split()) <= 2 and not is_question:
        return s
    return s + ("?" if is_question else ".")

@app.post("/api/stt")
async def stt_endpoint(
    file: UploadFile = UpFile(...),
    language: Optional[str] = Form(default=None),
    x_org_slug: Optional[str] = Header(default=None),
    x_trace_id: Optional[str] = Header(default=None),
    user=Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """V2V-PATCH: Transcribe audio to text using the shared STT pipeline."""
    _ = db
    return await _transcribe_audio_common(
        file=file,
        language=language,
        user=user,
        x_org_slug=x_org_slug,
        x_trace_id=x_trace_id,
    )


# ==========================
# Realtime/WebRTC (V2V) routes
# ==========================
# ORKIO_AO60A_REALTIME_SUPPORT_EXTRACTION:
# schemas and voice normalization live in app/runtime/realtime_support.py.
# Routes remain here in AO60A to keep extraction small, reversible and low-risk.









def _detect_excluded_agent_names(message: str) -> List[str]:
    raw = (message or "").strip().lower()
    if not raw:
        return []

    aliases = {
        "orkio": [r"@orkio\b", r"\borkio\b"],
        "chris": [r"@chris\b", r"\bchris\b", r"\bcfo\b"],
        "orion": [r"@orion\b", r"\borion\b", r"\bcto\b"],
        # AO68A-HF3:
        # Negative mentions such as "não preciso de auditoria técnica" must not
        # be interpreted as an explicit request for the Auditor agent.
        "auditor": [r"@auditor\b", r"\bauditor\b", r"auditoria\s+t[ée]cnica", r"technical\s+auditor", r"runtime\s+audit"],
    }

    pre_negation = r"(?:sem|exceto|exclude|excluding|without|bloque(?:ar|ie)|remov(?:er|a)|nao\s+incluir|não\s+incluir|nao\s+chamar|não\s+chamar|nao\s+usar|não\s+usar)"
    post_negation = r"(?:nao\s+pode|não\s+pode|nao\s+deve|não\s+deve|nao\s+responder|não\s+responder|nao\s+assinar|não\s+assinar|nao\s+interceptar|não\s+interceptar|nao\s+substituir|não\s+substituir|fora\s+deste\s+teste)"

    excluded: List[str] = []
    for canonical, pats in aliases.items():
        hit = False
        for alias_pat in pats:
            if re.search(rf"{pre_negation}\s+{alias_pat}", raw, flags=re.IGNORECASE):
                hit = True
                break
            if re.search(rf"{alias_pat}.*?{post_negation}", raw, flags=re.IGNORECASE):
                hit = True
                break
        if hit and canonical not in excluded:
            excluded.append(canonical)
    return excluded

def _orion_only_request_flags(message: str) -> Dict[str, Any]:
    raw = (message or "").strip().lower()
    if not raw:
        return {"requested": False, "excluded_agents": []}
    excluded = _detect_excluded_agent_names(message)
    explicit_orion = bool(re.search(r"@orion\b|\borion\b", raw, flags=re.IGNORECASE))
    explicit_team = bool(re.search(r"@team\b|\bteam\b|\bequipe\b|\bboard\b|\bconselho\b", raw, flags=re.IGNORECASE))
    explicit_other = []
    for other in ("chris", "orkio"):
        if other in excluded:
            continue
        if re.search(rf"@{other}\b|\b{other}\b", raw, flags=re.IGNORECASE):
            explicit_other.append(other)
    requested = bool(explicit_orion and not explicit_team and not explicit_other)
    return {"requested": requested, "excluded_agents": excluded}

def _detect_requested_agent_names(message: str) -> List[str]:
    raw = (message or "").strip().lower()
    if not raw:
        return []
    excluded = set(_detect_excluded_agent_names(message))
    requested: List[str] = []
    patterns = [
        ("orkio", [r"@orkio\b", r"\borkio\b", r"host\b", r"moderador", r"moderator"]),
        ("chris", [r"@chris\b", r"\bchris\b", r"\bcfo\b", r"financeir", r"financial", r"financ"]),
        ("orion", [
            r"@orion\b", r"\borion\b", r"\boria\b", r"\bauria\b", r"\baurya\b",
            r"\borion only\b", r"orion only", r"\bcto\b", r"noss[oa]\s+cto",
            r"chief technology officer", r"signer\s*[:=]\s*orion", r"required_signer\s*[:=]\s*orion"
        ]),
        ("auditor", [r"@auditor\b", r"\bauditor\b", r"technical auditor", r"auditoria t[ée]cnica", r"runtime audit"]),
        ("systems_architect", [r"systems architect", r"system architect"]),
        ("ux_frontend", [r"ux/frontend", r"ux_frontend", r"ux frontend", r"@ux\s+frontend\b", r"frontend ux", r"@ux\b", r"@frontend\b"]),
    ]
    for name, pats in patterns:
        if name.strip().lower() in excluded:
            continue
        for pat in pats:
            if re.search(pat, raw, flags=re.IGNORECASE):
                requested.append(name)
                break

    normalized = "_" + re.sub(r"[^a-z0-9_]+", "_", raw.replace("@", " ")) + "_"
    for slug in list(get_full_agent_roster() or []):
        canonical = _canonical_dispatch_specialist_slug(slug)
        if not canonical:
            continue
        if canonical in excluded:
            continue
        token = f"_{canonical}_"
        if token in normalized and canonical not in requested:
            requested.append(canonical)

    if re.search(r"@team\b|\bteam\b|\bequipe\b|\bboard\b|\bconselho\b|\bambos\b|\btodos\b", raw, flags=re.IGNORECASE):
        if not any(item not in {"orion", "orkio", "team", "time"} for item in requested):
            for name in ("chris", "orion"):
                if name in excluded:
                    continue
                if name not in requested:
                    requested.append(name)
    return requested

def _build_realtime_handoff_line(host_name: str, requested: List[str]) -> Optional[str]:
    if not requested:
        return None
    # Keep handoff short to avoid adding another long concurrent turn.
    first = requested[0]
    if len(requested) == 1:
        return f"{host_name}: claro, vou chamar {first} agora."
    return f"{host_name}: claro, vou começar com {first} agora."


def _explicit_agent_override(db: Session, org: str, text: str) -> List[Agent]:
    """
    Detecta pedido explícito de agente por nome/alias e resolve diretamente do banco.
    Respeita exclusões explícitas como "Chris não pode responder" / "sem Chris".
    Ignora planner e AgentLink.
    """
    raw = (text or "").strip().lower()
    if not raw:
        return []

    excluded = set(_detect_excluded_agent_names(text))
    requested: List[str] = []

    patterns = {
        "Orion": ["orion", "oria", "auria", "aurya", "cto", "nossa cto", "nosso cto", "@orion"],
        "Chris": ["chris", "cfo", "@chris"],
        "Orkio": ["orkio", "@orkio"],
    }

    for canonical, aliases in patterns.items():
        if canonical.strip().lower() in excluded:
            continue
        if any(alias in raw for alias in aliases):
            requested.append(canonical)

    if re.search(r"@team\b|\bteam\b|\bequipe\b|\bboard\b|\bconselho\b|\bambos\b|\btodos\b", raw, flags=re.IGNORECASE):
        for canonical in ("Chris", "Orion"):
            if canonical.strip().lower() in excluded:
                continue
            if canonical not in requested:
                requested.append(canonical)

    if not requested:
        return []

    rows = db.execute(
        select(Agent).where(
            Agent.org_slug == org,
            Agent.name.in_(requested),
        )
    ).scalars().all()

    by_name = {(a.name or "").strip().lower(): a for a in rows}
    ordered = [by_name[name.strip().lower()] for name in requested if name.strip().lower() in by_name]
    return ordered


def _constraint_bullet_clean(value: Any) -> str:
    raw = str(value or "").strip()
    if not raw:
        return ""
    raw = re.sub(r"^\s*[-*•]+\s*", "", raw)
    raw = re.sub(r"^\s*\d+[.)]\s*", "", raw)
    return raw.strip()


def _extract_realtime_constraint_scalar(text: str, keys: List[str]) -> Optional[str]:
    raw = text or ""
    for key in keys:
        match = re.search(rf"(?im)^\s*{re.escape(key)}\s*[:=]\s*([^\n#]+?)\s*$", raw)
        if match:
            cleaned = _constraint_bullet_clean(match.group(1))
            slug = _canonical_dispatch_specialist_slug(cleaned)
            if slug:
                return slug
    return None


def _extract_realtime_constraint_list(text: str, keys: List[str]) -> List[str]:
    raw = text or ""
    lines = raw.splitlines()
    collected: List[str] = []
    active = False

    for line in lines:
        stripped = line.strip()
        lowered = stripped.lower()
        matched_key = None
        for key in keys:
            if lowered.startswith(f"{key.lower()}:") or lowered.startswith(f"{key.lower()}="):
                matched_key = key
                break
        if matched_key is not None:
            active = True
            inline = re.split(r"[:=]", stripped, maxsplit=1)[1].strip() if re.search(r"[:=]", stripped) else ""
            if inline:
                parts = [_constraint_bullet_clean(part) for part in re.split(r"[,;]", inline) if _constraint_bullet_clean(part)]
                collected.extend(parts)
            continue
        if not active:
            continue
        if not stripped:
            if collected:
                break
            continue
        if re.match(r"^\s*[-*•]\s+", line) or re.match(r"^\s*\d+[.)]\s+", line):
            cleaned = _constraint_bullet_clean(stripped)
            if cleaned:
                collected.append(cleaned)
            continue
        if re.match(r"^[A-Za-z0-9_/@.\-]+\s*[:=]", stripped):
            break
        if collected:
            break

    if not collected:
        for key in keys:
            match = re.search(rf"(?im)^\s*{re.escape(key)}\s*[:=]\s*([^\n#]+?)\s*$", raw)
            if match:
                parts = [_constraint_bullet_clean(part) for part in re.split(r"[,;]", match.group(1)) if _constraint_bullet_clean(part)]
                collected.extend(parts)
                break

    out: List[str] = []
    seen: set = set()
    for item in collected:
        slug = _canonical_dispatch_specialist_slug(item)
        if slug and slug not in seen:
            out.append(slug)
            seen.add(slug)
    return out


def _extract_realtime_constraint_count(text: str) -> Optional[int]:
    raw = text or ""
    for pattern in (
        r"(?im)^\s*selected_specialists_count_must_be\s*[:=]\s*(\d+)\s*$",
        r"(?im)^\s*selected_specialists_count\s*[:=]\s*(\d+)\s*$",
    ):
        match = re.search(pattern, raw)
        if match:
            try:
                return int(match.group(1))
            except Exception:
                return None
    return None


def _realtime_hard_constraints_from_message(text: str) -> Dict[str, Any]:
    required_signer = _extract_realtime_constraint_scalar(text, ["required_signer", "signer_must_be", "signer_must"])
    specialists_required = _extract_realtime_constraint_list(text, ["specialists_required", "allowed_specialists_only"])
    specialists_forbidden = _extract_realtime_constraint_list(text, ["specialists_forbidden", "forbidden_specialists"])
    count_must_be = _extract_realtime_constraint_count(text)
    if count_must_be is None and specialists_required:
        count_must_be = len(specialists_required)
    return {
        "required_signer": required_signer,
        "specialists_required": specialists_required,
        "specialists_forbidden": specialists_forbidden,
        "selected_specialists_count_must_be": count_must_be,
        "has_hard_constraints": bool(required_signer or specialists_required or specialists_forbidden or count_must_be is not None),
    }


def _apply_realtime_hard_constraints_to_targets(
    *,
    target_agents: List[Any],
    alias_to_agent: Dict[str, Any],
    requested_names: Optional[List[str]],
    mention_tokens: Optional[List[str]],
    message_text: str,
    db: Optional[Session] = None,
    org: Optional[str] = None,
) -> Dict[str, Any]:
    constraints = _realtime_hard_constraints_from_message(message_text)
    if not constraints.get("has_hard_constraints"):
        return {
            "target_agents": list(target_agents or []),
            "requested_names": list(requested_names or []),
            "mention_tokens": list(mention_tokens or []),
            "violations": [],
            "constraints": constraints,
            "hard_multi": False,
        }

    unique_agents: List[Any] = []
    seen_ids: set = set()
    for ag in list(target_agents or []):
        agid = getattr(ag, "id", None)
        if agid in seen_ids:
            continue
        unique_agents.append(ag)
        seen_ids.add(agid)

    def _resolve_by_slug(slug: str) -> Any:
        return _resolve_dispatch_agent_by_slug(
            slug,
            alias_to_agent=alias_to_agent,
            db=db,
            org=org,
        )

    required_signer = constraints.get("required_signer")
    specialists_required = list(constraints.get("specialists_required") or [])
    specialists_forbidden = set(constraints.get("specialists_forbidden") or [])
    count_must_be = constraints.get("selected_specialists_count_must_be")
    violations: List[str] = []

    if specialists_required:
        constrained_targets: List[Any] = []
        missing: List[str] = []
        seen_req_ids: set = set()
        for slug in specialists_required:
            ag = _resolve_by_slug(slug)
            if ag is None:
                missing.append(slug)
                continue
            agid = getattr(ag, "id", None)
            if agid in seen_req_ids:
                continue
            constrained_targets.append(ag)
            seen_req_ids.add(agid)
        if missing:
            violations.append("missing required specialists: " + ", ".join(missing))
        unique_agents = constrained_targets

    if specialists_forbidden:
        forbidden_hits: List[str] = []
        filtered: List[Any] = []
        for ag in unique_agents:
            slug = _canonical_dispatch_specialist_slug(getattr(ag, "name", None))
            if slug in specialists_forbidden:
                forbidden_hits.append(slug)
                continue
            filtered.append(ag)
        unique_agents = filtered
        if forbidden_hits:
            violations.append("forbidden specialists selected: " + ", ".join(sorted(set(forbidden_hits))))

    if required_signer:
        signer_agent = _resolve_by_slug(required_signer)
        if signer_agent is None:
            violations.append(f"required signer unavailable: {required_signer}")
        else:
            signer_id = getattr(signer_agent, "id", None)
            if all(getattr(ag, "id", None) != signer_id for ag in unique_agents):
                unique_agents = [signer_agent] + unique_agents

    deduped: List[Any] = []
    seen_ids = set()
    for ag in unique_agents:
        agid = getattr(ag, "id", None)
        if agid in seen_ids:
            continue
        deduped.append(ag)
        seen_ids.add(agid)
    unique_agents = deduped

    if count_must_be is not None:
        try:
            expected_count = int(count_must_be)
        except Exception:
            expected_count = None
        if expected_count is not None and len(unique_agents) != expected_count:
            violations.append(f"selected_specialists_count_must_be={expected_count} but got {len(unique_agents)}")

    requested_out = list(requested_names or [])
    if specialists_required:
        requested_out = list(specialists_required)

    mention_out = list(mention_tokens or [])
    if specialists_required:
        mention_out = [f"@{slug}" for slug in specialists_required]

    hard_multi = bool(
        len(list(specialists_required or [])) > 1
        or ((count_must_be is not None) and int(count_must_be or 0) > 1)
    )

    return {
        "target_agents": unique_agents,
        "requested_names": requested_out,
        "mention_tokens": mention_out,
        "violations": violations,
        "constraints": constraints,
        "hard_multi": hard_multi,
    }


def _run_realtime_multi_agent_turn(
    db: Session,
    *,
    org: str,
    rs: RealtimeSession,
    user: Dict[str, Any],
    message: str,
) -> List[Dict[str, Any]]:
    """
    Bridge do Realtime -> runtime multi-agent do chat.
    Recebe um transcript.final do usuário e executa os agentes ligados ao host da sessão.
    Retorna lista de respostas [{agent_id, agent_name, text}].
    """
    text_in = (message or "").strip()
    if not text_in:
        return []

    try:
        ensure_core_agents(db, org)
    except Exception:
        logger.exception("ENSURE_CORE_AGENTS_REALTIME_FAILED org=%s", org)

    host_agent = None
    if getattr(rs, "agent_id", None):
        host_agent = db.execute(
            select(Agent).where(
                Agent.org_slug == org,
                Agent.id == rs.agent_id,
            )
        ).scalar_one_or_none()

    if not host_agent:
        return []

    # AO20BC-LITE — server-side realtime authority lock.
    # Frontend guard is helpful but not authoritative: transcript.final may reach
    # /api/realtime/events:batch before the browser finishes its guard branch.
    guarded_reply = _guard_realtime_message(text_in)
    if guarded_reply:
        created = now_ts()
        try:
            db.add(
                Message(
                    id=new_id(),
                    org_slug=org,
                    thread_id=rs.thread_id,
                    user_id=None,
                    user_name=None,
                    role="assistant",
                    content=guarded_reply,
                    agent_id=getattr(host_agent, "id", None),
                    agent_name=getattr(host_agent, "name", None) or "Orkio",
                    created_at=created,
                )
            )
            db.add(
                RealtimeEvent(
                    id=new_id(),
                    org_slug=org,
                    session_id=rs.id,
                    thread_id=rs.thread_id,
                    speaker_type="agent",
                    speaker_id=getattr(host_agent, "id", None),
                    agent_id=getattr(host_agent, "id", None),
                    agent_name=getattr(host_agent, "name", None) or "Orkio",
                    event_type="response.final",
                    transcript_raw=guarded_reply,
                    transcript_punct=guarded_reply,
                    created_at=created,
                    client_event_id=None,
                    meta=json.dumps({
                        "source": "ao20bc_realtime_server_guard",
                        "guarded": True,
                        "blocked_multi_agent": True,
                        "route_audit": _ao20bc_resolve_route(text_in, requested_agent=getattr(host_agent, "name", None), source="realtime"),
                    }, ensure_ascii=False),
                )
            )
            db.commit()
        except Exception:
            try:
                db.rollback()
            except Exception:
                pass
            logger.exception("AO20BC_REALTIME_GUARD_PERSIST_FAILED session_id=%s", getattr(rs, "id", None))
        return [{
            "agent_id": getattr(host_agent, "id", None),
            "agent_name": getattr(host_agent, "name", None) or "Orkio",
            "text": guarded_reply,
        }]

    route_plan = _ao20bc_resolve_route(text_in, requested_agent=getattr(host_agent, "name", None), source="realtime")
    try:
        logger.info("AO20BC_REALTIME_ROUTE session_id=%s route=%s", getattr(rs, "id", None), json.dumps(route_plan, ensure_ascii=False, sort_keys=True))
    except Exception:
        pass

    explicit_agents = _explicit_agent_override(db, org, text_in)
    if explicit_agents:
        logger.info("REALTIME_EXPLICIT_AGENT_OVERRIDE session_id=%s requested=%s resolved=%s", rs.id, text_in, [getattr(a, "name", None) for a in explicit_agents])
        target_agents: List[Agent] = explicit_agents
    else:
        linked_ids = get_linked_agent_ids(db, org, host_agent.id)
        ordered_ids = [host_agent.id] + [x for x in linked_ids if x and x != host_agent.id]

        target_agents: List[Agent] = []
        if ordered_ids:
            rows = db.execute(
                select(Agent).where(
                    Agent.org_slug == org,
                    Agent.id.in_(ordered_ids),
                )
            ).scalars().all()
            by_id = {a.id: a for a in rows}
            target_agents = [by_id[x] for x in ordered_ids if x in by_id]

        if not target_agents:
            target_agents = [host_agent]

    requested_names = _detect_requested_agent_names(text_in)

    if requested_names:
        requested_norm = [x.strip().lower() for x in requested_names]

        filtered = [
            a for a in target_agents
            if (a.name or "").strip().lower() in requested_norm
        ]

        if not filtered:
            # fallback crítico: busca direta por nome se AgentLink não estiver configurado
            fallback_agents = db.execute(
                select(Agent).where(
                    Agent.org_slug == org,
                    Agent.name.in_(requested_names),
                )
            ).scalars().all()

            if fallback_agents:
                target_agents = fallback_agents
        else:
            # When the user explicitly requests specialists, skip host-only answer and bring them immediately.
            target_agents = filtered

    all_org_agents = db.execute(
        select(Agent).where(Agent.org_slug == org)
    ).scalars().all()
    alias_to_agent: Dict[str, Any] = {}
    for ag in list(all_org_agents or []):
        if not ag:
            continue
        ag_name = (getattr(ag, "name", None) or "").strip()
        if not ag_name:
            continue
        full = ag_name.lower()
        full_variants = {
            full,
            full.replace("/", "_"),
            full.replace("/", " "),
            full.replace("-", "_"),
            full.replace("-", " "),
        }
        for variant in list(full_variants):
            if variant:
                alias_to_agent.setdefault(variant, ag)
        first = full.split()[0] if full.split() else full
        if first:
            alias_to_agent.setdefault(first, ag)
        slug = _canonical_dispatch_specialist_slug(ag_name)
        if slug:
            alias_to_agent.setdefault(slug, ag)
        if slug == "orion":
            for extra in ("orion", "oria", "auria", "aurya", "cto", "nosso cto", "nossa cto", "chief technology officer", "orion_cto", "orion cto"):
                alias_to_agent.setdefault(extra, ag)
        elif slug == "auditor":
            for extra in ("auditor", "technical_auditor", "technical auditor", "runtime_auditor", "runtime auditor"):
                alias_to_agent.setdefault(extra, ag)
        elif slug == "systems_architect":
            for extra in ("systems_architect", "systems architect", "cto_delegate", "cto delegate"):
                alias_to_agent.setdefault(extra, ag)
        elif slug == "ux_frontend":
            for extra in ("ux_frontend", "ux/frontend", "ux frontend", "frontend ux", "ux", "frontend"):
                alias_to_agent.setdefault(extra, ag)

    mention_tokens: List[str] = [f"@{name}" for name in requested_names]
    if _looks_like_final_readonly_analysis_request_message(text_in):
        _realtime_constraint_guard = {
            "target_agents": list(target_agents or []),
            "requested_names": list(requested_names or []),
            "mention_tokens": list(mention_tokens or []),
            "violations": [],
            "constraints": {},
            "hard_multi": False,
        }
    else:
        _realtime_constraint_guard = _apply_realtime_hard_constraints_to_targets(
            target_agents=target_agents,
            alias_to_agent=alias_to_agent,
            requested_names=requested_names,
            mention_tokens=mention_tokens,
            message_text=text_in,
            db=db,
            org=org,
        )
    target_agents = list(_realtime_constraint_guard.get("target_agents") or target_agents)
    requested_names = list(_realtime_constraint_guard.get("requested_names") or requested_names)
    mention_tokens = list(_realtime_constraint_guard.get("mention_tokens") or mention_tokens)
    realtime_constraint_violations = list(_realtime_constraint_guard.get("violations") or [])
    realtime_constraints = dict(_realtime_constraint_guard.get("constraints") or {})
    hard_multi = bool(_realtime_constraint_guard.get("hard_multi"))

    tid = rs.thread_id
    uid = user.get("sub")

    prev = db.execute(
        select(Message)
        .where(Message.org_slug == org, Message.thread_id == tid)
        .order_by(Message.created_at.asc())
    ).scalars().all()

    if realtime_constraint_violations:
        violation_text = _build_runtime_constraint_violation_text(realtime_constraints, realtime_constraint_violations)
        signer_slug = str(realtime_constraints.get("required_signer") or "orion").strip().lower() or "orion"
        signer_agent = alias_to_agent.get(signer_slug) or host_agent
        signer_id = getattr(signer_agent, "id", None) if signer_agent is not None else None
        signer_name = getattr(signer_agent, "name", None) if signer_agent is not None else signer_slug.title()
        try:
            db.add(
                Message(
                    id=new_id(),
                    org_slug=org,
                    thread_id=tid,
                    user_id=None,
                    user_name=None,
                    role="assistant",
                    content=violation_text,
                    agent_id=signer_id,
                    agent_name=signer_name,
                    created_at=now_ts(),
                )
            )
            db.add(
                RealtimeEvent(
                    id=new_id(),
                    org_slug=org,
                    session_id=rs.id,
                    thread_id=tid,
                    speaker_type="agent",
                    speaker_id=signer_id,
                    agent_id=signer_id,
                    agent_name=signer_name,
                    event_type="response.final",
                    transcript_raw=violation_text,
                    transcript_punct=violation_text,
                    created_at=now_ts(),
                    client_event_id=None,
                    meta=json.dumps({"source": "realtime_constraint_violation"}, ensure_ascii=False),
                )
            )
            db.commit()
        except Exception:
            try:
                db.rollback()
            except Exception:
                pass
        return [{
            "agent_id": signer_id,
            "agent_name": signer_name,
            "text": violation_text,
        }]

    # Realtime turn-taking policy:
    # - explicit single specialist -> only that specialist speaks
    # - explicit multi/team/board -> only one specialist speaks per realtime turn
    # - default multi-agent team mode -> also limit to one specialist per turn
    # IMPORTANT: hard multi-agent constraints preserve the full internal squad for this execution.
    if len(target_agents) > 1 and not hard_multi:
        target_agents = target_agents[:1]

    has_team = bool(hard_multi or len(target_agents) > 1)
    answers: List[Dict[str, Any]] = []

    handoff_line = _build_realtime_handoff_line(getattr(host_agent, "name", None) or "Orkio", requested_names)
    if handoff_line:
        try:
            db.add(
                Message(
                    id=new_id(),
                    org_slug=org,
                    thread_id=tid,
                    user_id=None,
                    user_name=None,
                    role="assistant",
                    content=handoff_line,
                    agent_id=host_agent.id,
                    agent_name=host_agent.name,
                    created_at=now_ts(),
                )
            )
            db.add(
                RealtimeEvent(
                    id=new_id(),
                    org_slug=org,
                    session_id=rs.id,
                    thread_id=tid,
                    speaker_type="agent",
                    speaker_id=host_agent.id,
                    agent_id=host_agent.id,
                    agent_name=host_agent.name,
                    event_type="response.final",
                    transcript_raw=handoff_line,
                    transcript_punct=handoff_line,
                    created_at=now_ts(),
                    client_event_id=None,
                    meta=json.dumps({"source": "realtime_multi_agent_handoff"}, ensure_ascii=False),
                )
            )
            db.commit()
        except Exception:
            try:
                db.rollback()
            except Exception:
                pass

    for agent in target_agents:
        history: List[Dict[str, str]] = []
        for pm in prev[-24:]:
            role = "assistant" if pm.role == "assistant" else ("system" if pm.role == "system" else "user")
            if has_team and role == "assistant":
                if not pm.agent_id or pm.agent_id != agent.id:
                    continue
            history.append({"role": role, "content": (pm.content or "")})

        linked_agent_ids = get_linked_agent_ids(db, org, agent.id)
        scope_agent_ids = [agent.id] + linked_agent_ids
        agent_file_ids = get_agent_file_ids(db, org, scope_agent_ids)

        if tid:
            thread_file_ids = [
                r[0]
                for r in db.execute(
                    select(File.id).where(
                        File.org_slug == org,
                        File.scope_thread_id == tid,
                        File.origin == "chat",
                    )
                ).all()
            ]
            if thread_file_ids:
                agent_file_ids = list(dict.fromkeys((agent_file_ids or []) + thread_file_ids))

        effective_top_k = agent.rag_top_k if getattr(agent, "rag_enabled", True) else 6

        citations: List[Dict[str, Any]] = []
        if getattr(agent, "rag_enabled", True):
            try:
                citations = keyword_retrieve(
                    db,
                    org_slug=org,
                    query=text_in,
                    top_k=effective_top_k,
                    file_ids=agent_file_ids,
                )
            except Exception:
                citations = []

        temperature = None
        if getattr(agent, "temperature", None):
            try:
                temperature = float(agent.temperature)
            except Exception:
                temperature = None

        user_msg = _build_agent_prompt(agent, text_in, has_team or bool(requested_names), mention_tokens)
        effective_system_prompt = agent.system_prompt if agent else None
        effective_system_prompt = _append_orkio_ceo_scope_overlay(
            effective_system_prompt,
            agent_name=getattr(agent, "name", None),
            final_speaker=getattr(agent, "name", None),
        )

        ans_obj = _openai_answer(
            user_msg,
            citations,
            history=history,
            system_prompt=effective_system_prompt,
            model_override=(agent.model if agent else None),
            temperature=temperature,
        )

        answer = (ans_obj or {}).get("text") or ""
        answer = answer.strip()
        if not answer:
            logger.warning("REALTIME_AGENT_EMPTY_ANSWER session_id=%s agent=%s", rs.id, getattr(agent, "name", None))
            continue
        logger.info("REALTIME_AGENT_ANSWER_READY session_id=%s agent=%s chars=%s", rs.id, getattr(agent, "name", None), len(answer))

        m_ass = Message(
            id=new_id(),
            org_slug=org,
            thread_id=tid,
            user_id=None,
            user_name=None,
            role="assistant",
            content=answer,
            agent_id=agent.id,
            agent_name=agent.name,
            created_at=now_ts(),
        )
        db.add(m_ass)

        try:
            db.add(
                RealtimeEvent(
                    id=new_id(),
                    org_slug=org,
                    session_id=rs.id,
                    thread_id=tid,
                    speaker_type="agent",
                    speaker_id=agent.id,
                    agent_id=agent.id,
                    agent_name=agent.name,
                    event_type="response.final",
                    transcript_raw=answer,
                    transcript_punct=answer,
                    created_at=now_ts(),
                    client_event_id=None,
                    meta=json.dumps({"source": "realtime_multi_agent"}, ensure_ascii=False),
                )
            )
        except Exception:
            pass

        answers.append({
            "agent_id": agent.id,
            "agent_name": agent.name,
            "text": answer,
        })

    db.commit()

    try:
        _audit(db, org, uid, action="realtime.multi_agent.turn", meta={
            "session_id": rs.id,
            "thread_id": tid,
            "host_agent_id": getattr(host_agent, "id", None),
            "requested_agents": requested_names,
            "target_agents": [a.get("agent_name") for a in answers],
        })
    except Exception:
        pass

    return answers







# AO19D_REALTIME_TELEMETRY_LAYER
# Server-side classification for frontend WebRTC telemetry persisted through /api/realtime/events:batch.
AO19D_REALTIME_TELEMETRY_CRITICAL_EVENTS = {
    "telemetry.TOKEN_RECEIVED",
    "telemetry.EPHEMERAL_TOKEN_READY",
    "telemetry.PEER_CREATED",
    "telemetry.SDP_HANDSHAKE_OK",
    "telemetry.SDP_HANDSHAKE_ERROR",
    "telemetry.PEER_CONNECTED",
    "telemetry.DATA_CHANNEL_OPEN",
    "telemetry.DATA_CHANNEL_CLOSE",
    "telemetry.SESSION_UPDATED",
    "telemetry.SESSION_UPDATE_ERROR",
    "telemetry.RESPONSE_CREATE_SENT",
    "telemetry.RESPONSE_CREATED",
    "telemetry.RESPONSE_DONE",
    "telemetry.RESPONSE_DONE_WITHOUT_TEXT",
    "telemetry.REALTIME_ERROR",
    "telemetry.REALTIME_BOOT_ERROR",
    "telemetry.AUDIO_PLAY_START",
    "telemetry.AUDIO_PLAY_BLOCKED",
    "telemetry.MIC_READY",
    "telemetry.TRANSCRIPT_FINAL",
}

def _ao19d_realtime_event_name(event_type: str) -> str:
    raw = str(event_type or "").strip()
    if raw.startswith("telemetry."):
        return raw.split(".", 1)[1].upper()
    return raw.upper()

def _ao19d_safe_meta(meta: Any) -> Dict[str, Any]:
    if isinstance(meta, dict):
        return meta
    return {}









