@app.post("/api/beta/waitlist", response_model=BetaWaitlistOut)
def register_beta_waitlist(
    inp: BetaWaitlistIn,
    request: Request,
    db: Session = Depends(get_db),
):
    """Register closed-beta interest without creating a new database table.

    The stable id is derived from the normalized e-mail, making retries
    idempotent. Optional access codes are stored only as a SHA-256 digest.
    """

    if not inp.consent:
        raise HTTPException(
            status_code=400,
            detail="Autorize o contato para entrar na Lista Prioritária.",
        )

    email = str(inp.email).strip().lower()
    name = inp.name.strip()
    company = (inp.company or "").strip()
    whatsapp = (inp.whatsapp or "").strip() or None
    source = re.sub(r"[^a-z0-9_.:-]+", "_", inp.source.strip().lower()).strip("_")
    source = source or "orkio_closed_beta_gate"

    access_code = re.sub(r"\s+", "", (inp.access_code or "")).strip().upper()
    access_code_sha256 = (
        hashlib.sha256(access_code.encode("utf-8")).hexdigest()
        if access_code
        else None
    )

    waitlist_id = (
        "beta_waitlist_"
        + hashlib.sha256(email.encode("utf-8")).hexdigest()[:32]
    )
    ip = request.client.host if request.client else "unknown"
    user_agent = request.headers.get("user-agent", "")

    stored_payload = {
        "kind": "beta_waitlist",
        "company": company or None,
        "source": source,
        "access_code_sha256": access_code_sha256,
    }

    existing = db.execute(
        select(ContactRequest).where(ContactRequest.id == waitlist_id)
    ).scalar_one_or_none()

    registration_status = "already_registered" if existing else "registered"
    contact = existing

    if contact is None:
        contact = ContactRequest(
            id=waitlist_id,
            full_name=name,
            email=email,
            whatsapp=whatsapp,
            subject="Lista Prioritária ORKIO OS",
            message=json.dumps(stored_payload, ensure_ascii=False, sort_keys=True),
            privacy_request_type=None,
            consent_terms=False,
            consent_marketing=True,
            ip_address=ip,
            user_agent=user_agent,
            terms_version=None,
            status="pending",
            retention_until=now_ts() + (2 * 365 * 86400),
            created_at=now_ts(),
        )
        db.add(contact)
        try:
            db.commit()
        except IntegrityError:
            # A concurrent retry may have inserted the deterministic id first.
            db.rollback()
            contact = db.execute(
                select(ContactRequest).where(ContactRequest.id == waitlist_id)
            ).scalar_one_or_none()
            if contact is None:
                raise
            registration_status = "already_registered"
    else:
        # Preserve idempotency while refreshing user-provided contact details.
        contact.full_name = name
        contact.whatsapp = whatsapp
        contact.message = json.dumps(
            stored_payload,
            ensure_ascii=False,
            sort_keys=True,
        )
        contact.ip_address = ip
        contact.user_agent = user_agent
        db.add(contact)
        db.commit()

    channels = ["email"]
    if whatsapp:
        channels.append("whatsapp")

    for channel in channels:
        consent_exists = db.execute(
            select(MarketingConsent).where(
                MarketingConsent.contact_id == waitlist_id,
                MarketingConsent.channel == channel,
                MarketingConsent.opt_out_date.is_(None),
            )
        ).scalar_one_or_none()
        if consent_exists is None:
            db.add(
                MarketingConsent(
                    id=new_id(),
                    contact_id=waitlist_id,
                    channel=channel,
                    opt_in_date=now_ts(),
                    ip=ip,
                    source=source,
                    created_at=now_ts(),
                )
            )

    db.commit()

    try:
        audit(
            db,
            "public",
            None,
            "beta.waitlist.registered",
            request_id=ensure_request_id(request),
            path="/api/beta/waitlist",
            status_code=200,
            latency_ms=0,
            meta={
                "waitlist_id": waitlist_id,
                "source": source,
                "status": registration_status,
            },
        )
    except Exception:
        logger.exception(
            "BETA_WAITLIST_AUDIT_FAILED waitlist_id=%s",
            waitlist_id,
        )

    return {
        "ok": True,
        "waitlist_id": waitlist_id,
        "status": registration_status,
        "message": (
            "Cadastro já estava na Lista Prioritária."
            if registration_status == "already_registered"
            else "Cadastro registrado na Lista Prioritária."
        ),
    }


@app.post("/api/public/contact")
def public_contact(inp: ContactIn, request: Request = None, db: Session = Depends(get_db)):
    """Public contact form — stores request + consent records for LGPD compliance."""
    ip = _client_ip(request) if request else "unknown"
    ua = (request.headers.get("user-agent", "") if request else "")
    normalized_email = inp.email.lower().strip()
    email_rate_hash = hashlib.sha256(normalized_email.encode("utf-8")).hexdigest()

    if not inp.consent_terms:
        raise HTTPException(status_code=400, detail="Você precisa aceitar os Termos de Uso.")

    if not _rate_limit_check(
        _rl_contact_lock,
        _rl_contact_calls,
        f"ip:{ip}",
        _CONTACT_MAX_PER_WINDOW,
        window=_CONTACT_RATE_WINDOW_SECONDS,
    ):
        raise HTTPException(
            status_code=429,
            detail="Muitas solicitações de contato. Aguarde alguns minutos e tente novamente.",
            headers={"Retry-After": str(_CONTACT_RATE_WINDOW_SECONDS)},
        )

    if not _rate_limit_check(
        _rl_contact_lock,
        _rl_contact_calls,
        f"email:{email_rate_hash}",
        _CONTACT_EMAIL_MAX_PER_WINDOW,
        window=_CONTACT_RATE_WINDOW_SECONDS,
    ):
        raise HTTPException(
            status_code=429,
            detail="Muitas solicitações para este contato. Aguarde alguns minutos e tente novamente.",
            headers={"Retry-After": str(_CONTACT_RATE_WINDOW_SECONDS)},
        )

    cr = ContactRequest(
        id=new_id(),
        full_name=inp.full_name.strip(),
        email=normalized_email,
        whatsapp=(inp.whatsapp or "").strip() or None,
        subject=inp.subject.strip(),
        message=inp.message.strip(),
        privacy_request_type=inp.privacy_request_type,
        consent_terms=inp.consent_terms,
        consent_marketing=inp.consent_marketing,
        ip_address=ip,
        user_agent=ua,
        terms_version=inp.terms_version or TERMS_VERSION,
        retention_until=now_ts() + (5 * 365 * 86400),  # 5 years
        created_at=now_ts(),
    )
    db.add(cr)
    db.commit()

    # Record marketing consent if given
    if inp.consent_marketing:
        try:
            db.add(MarketingConsent(
                id=new_id(), contact_id=cr.id, channel="email",
                opt_in_date=now_ts(), ip=ip, source="contact_form", created_at=now_ts(),
            ))
            db.commit()
        except Exception:
            logger.exception("MARKETING_CONSENT_CONTACT_FAILED")

    try:
        audit(
            db,
            "public",
            None,
            "contact.submitted",
            request_id=ensure_request_id(request),
            path="/api/public/contact",
            status_code=200,
            latency_ms=0,
            meta={
                "contact_id": cr.id,
                "has_whatsapp": bool(cr.whatsapp),
                "privacy_request_type": cr.privacy_request_type,
                "consent_marketing": bool(cr.consent_marketing),
            },
        )
    except Exception:
        logger.warning("CONTACT_AUDIT_FAILED contact_id=%s", cr.id)


    # AO67I — Contact Delivery Reliability
    delivery_result = None
    try:
        from app.services.contact_delivery_service import (
            build_contact_notification_payload,
            contact_request_status_from_delivery,
            deliver_contact_notifications,
            public_contact_message,
        )

        delivery_payload = build_contact_notification_payload(
            contact_id=cr.id,
            full_name=inp.full_name,
            email=inp.email,
            whatsapp=inp.whatsapp or "",
            subject=inp.subject,
            message=inp.message,
            privacy_request_type=inp.privacy_request_type,
            consent_terms=inp.consent_terms,
            consent_marketing=inp.consent_marketing,
            ip=ip,
            user_agent=ua,
            terms_version=cr.terms_version,
            created_at=cr.created_at,
        )

        delivery_result = deliver_contact_notifications(
            delivery_payload,
            send_email_fn=_send_resend_email,
            logger=logger,
        )

        try:
            cr.status = contact_request_status_from_delivery(delivery_result)
            db.add(cr)
            db.commit()
        except Exception:
            try:
                db.rollback()
            except Exception:
                pass
            logger.exception("CONTACT_DELIVERY_STATUS_UPDATE_FAILED contact_id=%s", cr.id)

    except Exception:
        logger.exception("CONTACT_DELIVERY_AUTOMATION_FAILED contact_id=%s", cr.id)

    try:
        from app.services.contact_delivery_service import public_contact_message
        public_message = public_contact_message(delivery_result)
    except Exception:
        public_message = "Recebemos sua mensagem. Responderemos assim que possível."

    return {
        "ok": True,
        "id": cr.id,
        "message": public_message,
        "email_delivery": (
            delivery_result.to_public_dict()
            if delivery_result is not None
            else {"status": "unknown", "configured": False, "contact_id": cr.id}
        ),
    }





# RTB09_PUBLIC_STRATEGIC_INTAKE — qualified pre-onboarding.
# This endpoint intentionally does NOT create users, invitations, signup codes or platform sessions.
def _strategic_intake_locale(inp: StrategicIntakeIn) -> str:
    raw = str(getattr(inp, "locale", "") or "").strip().lower()
    return "en" if raw.startswith("en") else "pt"


def _strategic_intake_public_message(inp: StrategicIntakeIn) -> str:
    if _strategic_intake_locale(inp) == "en":
        return (
            "Registration received. Grupo Patroai will review the information internally "
            "and may contact you if there is fit with our criteria, projects or opportunities."
        )
    return (
        "Cadastro recebido. O Grupo Patroai analisará as informações internamente "
        "e poderá entrar em contato caso exista aderência com nossos critérios, projetos ou oportunidades."
    )


def _strategic_intake_type(value: str) -> str:
    normalized = str(value or "").strip().lower()
    allowed = {"company", "investor", "consultant"}
    if normalized not in allowed:
        raise HTTPException(status_code=400, detail="Tipo de cadastro inválido.")
    return normalized


def _strategic_intake_score(payload: Dict[str, Any]) -> Dict[str, Any]:
    score = 0
    flags: List[str] = []

    email = str(payload.get("email") or "").strip().lower()
    website = str(payload.get("website") or "").strip()
    linkedin = str(payload.get("linkedin") or "").strip()
    company = str(payload.get("company") or "").strip()
    whatsapp = str(payload.get("whatsapp") or "").strip()
    person_type = str(payload.get("person_type") or "").strip()
    engagement_model = str(payload.get("engagement_model") or "").strip()
    message = str(payload.get("message") or payload.get("challenge") or "").strip()

    if company:
        score += 15
    if linkedin:
        score += 15
    if website:
        score += 10
    if whatsapp:
        score += 10
    if person_type:
        score += 5
    if engagement_model:
        score += 5
    if len(message) >= 80:
        score += 15
    if payload.get("consent_contact"):
        score += 10
    if payload.get("consent_data_review"):
        score += 10
    if payload.get("esg_focus"):
        score += 5

    if re.search(r"@(gmail|hotmail|outlook|yahoo)\.", email):
        flags.append("personal_email")
    if not linkedin and payload.get("intake_type") in {"investor", "consultant"}:
        flags.append("linkedin_missing")
    if payload.get("intake_type") == "investor" and not payload.get("person_type"):
        flags.append("person_type_missing")
    if payload.get("intake_type") == "investor" and not payload.get("capital_range"):
        flags.append("capital_range_missing")
    if payload.get("intake_type") == "consultant" and not payload.get("expertise"):
        flags.append("expertise_missing")
    if payload.get("intake_type") == "consultant" and not payload.get("engagement_model"):
        flags.append("engagement_model_missing")

    score = max(0, min(score, 100))
    tier = "low"
    if score >= 70:
        tier = "high"
    elif score >= 40:
        tier = "medium"

    return {"score": score, "tier": tier, "flags": flags}



def _rtb10_hf8_safe_line(value: Any, limit: int = 500) -> str:
    text_value = str(value or "").strip()
    text_value = re.sub(r"[\r\n\t]+", " ", text_value)
    text_value = re.sub(r"\s+", " ", text_value).strip()
    if len(text_value) > limit:
        return text_value[:limit].rstrip() + "..."
    return text_value


def _rtb10_hf8_intake_type_label(intake_type: str, locale: str = "pt") -> str:
    labels_pt = {
        "company": "Empresa / Cliente",
        "investor": "Investidor",
        "consultant": "Consultor associado",
    }
    labels_en = {
        "company": "Company / Client",
        "investor": "Investor",
        "consultant": "Associated consultant",
    }
    labels = labels_en if str(locale or "").lower().startswith("en") else labels_pt
    return labels.get(str(intake_type or "").strip().lower(), str(intake_type or "cadastro"))


def _rtb10_hf8_build_public_intake_notification(
    *,
    intake_id: str,
    intake_type: str,
    payload: Dict[str, Any],
    review: Dict[str, Any],
    request_meta: Dict[str, Any],
) -> str:
    submitted = dict(payload or {})
    locale = str(request_meta.get("locale") or submitted.get("locale") or "pt").strip()
    intake_label = _rtb10_hf8_intake_type_label(intake_type, locale)
    flags = review.get("flags") or []
    if not isinstance(flags, list):
        flags = []

    lines = [
        "Novo cadastro recebido pela landing pública do Grupo Patroai.",
        "",
        f"Protocolo: {intake_id}",
        f"Perfil: {intake_label}",
        "Status inicial: under_review",
        f"Score: {review.get('score')} / Tier: {review.get('tier')}",
        f"Flags: {', '.join([str(x) for x in flags]) if flags else 'sem flags'}",
        "",
        "Dados principais:",
        f"- Nome: {_rtb10_hf8_safe_line(submitted.get('full_name'))}",
        f"- E-mail: {_rtb10_hf8_safe_line(submitted.get('email'))}",
        f"- WhatsApp: {_rtb10_hf8_safe_line(submitted.get('whatsapp'))}",
        f"- Empresa/organização: {_rtb10_hf8_safe_line(submitted.get('company'))}",
        f"- Cargo/função: {_rtb10_hf8_safe_line(submitted.get('role'))}",
        f"- Cidade/UF: {_rtb10_hf8_safe_line(submitted.get('city'))} / {_rtb10_hf8_safe_line(submitted.get('state'))}",
        f"- País: {_rtb10_hf8_safe_line(submitted.get('country'))}",
        f"- LinkedIn: {_rtb10_hf8_safe_line(submitted.get('linkedin'))}",
        f"- Site: {_rtb10_hf8_safe_line(submitted.get('website'))}",
        "",
        "Campos estratégicos:",
        f"- Segmento: {_rtb10_hf8_safe_line(submitted.get('segment'))}",
        f"- Área de interesse: {_rtb10_hf8_safe_line(submitted.get('interest_area'))}",
        f"- Pessoa física/jurídica: {_rtb10_hf8_safe_line(submitted.get('person_type'))}",
        f"- Perfil/tese do investidor: {_rtb10_hf8_safe_line(submitted.get('investor_type'))}",
        f"- Faixa/tese: {_rtb10_hf8_safe_line(submitted.get('capital_range'))}",
        f"- Especialidade: {_rtb10_hf8_safe_line(submitted.get('expertise'))}",
        f"- Modelo de atuação: {_rtb10_hf8_safe_line(submitted.get('engagement_model'))}",
        f"- Disponibilidade: {_rtb10_hf8_safe_line(submitted.get('availability'))}",
        "",
        "Mensagem / desafio:",
        _rtb10_hf8_safe_line(submitted.get("message") or submitted.get("challenge"), limit=1200) or "não informado",
        "",
        "Consentimentos:",
        f"- Termos: {bool(submitted.get('consent_terms'))}",
        f"- Análise de dados: {bool(submitted.get('consent_data_review'))}",
        f"- Contato operacional: {bool(submitted.get('consent_contact'))}",
        f"- Marketing opcional: {bool(submitted.get('consent_marketing'))}",
        "",
        "Contexto jurídico-operacional:",
        f"- Termos: {TERMS_VERSION}",
        f"- Privacidade: {PRIVACY_VERSION}",
        f"- Cookies: {COOKIES_VERSION}",
        f"- Controladora: {PATROAI_LEGAL_NAME}",
        f"- CNPJ: {PATROAI_CNPJ}",
        f"- Canal institucional: {PATROAI_CONTACT_EMAIL}",
        f"- Canal de privacidade: {PATROAI_PRIVACY_EMAIL}",
        "",
        "Contexto técnico:",
        f"- Rota: {_rtb10_hf8_safe_line(request_meta.get('route'))}",
        f"- Origem: {_rtb10_hf8_safe_line(request_meta.get('source'))}",
        f"- Idioma: {_rtb10_hf8_safe_line(locale)}",
        f"- IP: {_rtb10_hf8_safe_line(request_meta.get('ip'))}",
        f"- User-Agent: {_rtb10_hf8_safe_line(request_meta.get('user_agent'), limit=300)}",
        "",
        "Regra central:",
        "Cadastro não é acesso. Cadastro é qualificação.",
    ]
    return "\n".join(lines)


def _rtb10_hf8_notify_public_intake(
    *,
    intake_id: str,
    intake_type: str,
    payload: Dict[str, Any],
    review: Dict[str, Any],
    request_meta: Dict[str, Any],
) -> bool:
    if not PATROAI_INTAKE_NOTIFY_ENABLED:
        logger.info("RTB10_HF8_INTAKE_EMAIL_SKIPPED disabled intake_id=%s", intake_id)
        return False

    recipients = _parse_email_recipients(PATROAI_INTAKE_NOTIFY_TO)
    if not recipients:
        logger.warning("RTB10_HF8_INTAKE_EMAIL_SKIPPED empty_recipients intake_id=%s", intake_id)
        return False

    locale = str(request_meta.get("locale") or payload.get("locale") or "pt").strip()
    label = _rtb10_hf8_intake_type_label(intake_type, locale)
    tier = str((review or {}).get("tier") or "n/a")
    subject = f"Grupo Patroai | Novo cadastro {label} | {tier} | {intake_id[:8]}"
    body = _rtb10_hf8_build_public_intake_notification(
        intake_id=intake_id,
        intake_type=intake_type,
        payload=payload,
        review=review,
        request_meta=request_meta,
    )

    sent = _send_resend_email(recipients, _ascii_safe_text(subject), _ascii_safe_text(body))
    logger.info(
        "RTB10_HF8_INTAKE_EMAIL_RESULT intake_id=%s type=%s sent=%s recipients_count=%s",
        intake_id,
        intake_type,
        sent,
        len(recipients),
    )
    return bool(sent)


def _rtb09hf2_present(value: Any) -> bool:
    return bool(str(value or "").strip())


def _rtb09hf2_validate_required_intake_fields(inp: StrategicIntakeIn, intake_type: str) -> None:
    """Strict public-intake validation.

    This endpoint is not a signup flow. Stronger qualification fields reduce spam,
    protect the private platform and make admin review useful from the first touch.
    """
    missing: List[str] = []

    def require(attr: str, label: str) -> None:
        if not _rtb09hf2_present(getattr(inp, attr, None)):
            missing.append(label)

    require("full_name", "nome completo")
    require("email", "e-mail")
    require("whatsapp", "WhatsApp")
    require("city", "cidade")
    require("state", "estado")

    if intake_type == "company":
        require("company", "empresa")
        require("role", "cargo")
        require("segment", "segmento")
        require("company_size", "tamanho da empresa")
        require("interest_area", "área de interesse")
        require("challenge", "principal desafio")
    elif intake_type == "investor":
        require("person_type", "pessoa física ou jurídica")
        require("investor_type", "perfil/tese do investidor")
        require("capital_range", "faixa indicativa ou tese")
        require("sectors", "setores de interesse")
        require("message", "mensagem complementar")
        if not (_rtb09hf2_present(inp.linkedin) or _rtb09hf2_present(inp.website)):
            missing.append("LinkedIn ou site")
    elif intake_type == "consultant":
        require("linkedin", "LinkedIn")
        require("expertise", "especialidade principal")
        require("years_experience", "anos de experiência")
        require("sectors", "setores de atuação")
        require("engagement_model", "modelo de atuação")
        require("availability", "disponibilidade")
        require("message", "mensagem complementar")

    if missing:
        raise HTTPException(
            status_code=400,
            detail="Campos obrigatórios pendentes para análise: " + ", ".join(missing) + ".",
        )


@app.post("/api/public/intake")
def public_strategic_intake(
    inp: StrategicIntakeIn,
    x_org_slug: Optional[str] = Header(default=None),
    request: Request = None,
    db: Session = Depends(get_db),
):
    """Public qualified intake for companies, investors and associated consultants.

    Security principle: cadastro não é acesso. This stores a reviewable submission
    and returns a receipt only. No account, invite, signup code or platform access
    is created here.
    """
    org = get_org(x_org_slug)
    ip = _client_ip(request) if request else "unknown"
    ua = (request.headers.get("user-agent", "") if request else "")
    normalized_email = str(inp.email).lower().strip()
    email_rate_hash = hashlib.sha256(normalized_email.encode("utf-8")).hexdigest()

    # Honeypot: silently acknowledge without storing, so bots do not learn the rule.
    if str(inp.website_url or "").strip():
        return {
            "ok": True,
            "intake_id": "received",
            "status": "received",
            "access_granted": False,
            "message": _strategic_intake_public_message(inp),
        }

    intake_type = _strategic_intake_type(inp.intake_type)

    if not inp.consent_terms or not inp.consent_data_review or not inp.consent_contact:
        raise HTTPException(
            status_code=400,
            detail="É necessário aceitar os termos, a análise de dados e o contato institucional.",
        )

    _rtb09hf2_validate_required_intake_fields(inp, intake_type)

    if not _rate_limit_check(
        _rl_contact_lock,
        _rl_contact_calls,
        f"intake-ip:{ip}",
        _CONTACT_MAX_PER_WINDOW,
        window=_CONTACT_RATE_WINDOW_SECONDS,
    ):
        raise HTTPException(
            status_code=429,
            detail="Muitas solicitações. Aguarde alguns minutos e tente novamente.",
            headers={"Retry-After": str(_CONTACT_RATE_WINDOW_SECONDS)},
        )

    if not _rate_limit_check(
        _rl_contact_lock,
        _rl_contact_calls,
        f"intake-email:{email_rate_hash}",
        _CONTACT_EMAIL_MAX_PER_WINDOW,
        window=_CONTACT_RATE_WINDOW_SECONDS,
    ):
        raise HTTPException(
            status_code=429,
            detail="Muitas solicitações para este contato. Aguarde alguns minutos e tente novamente.",
            headers={"Retry-After": str(_CONTACT_RATE_WINDOW_SECONDS)},
        )

    raw_payload = inp.dict()
    raw_payload.pop("website_url", None)
    review = _strategic_intake_score({**raw_payload, "intake_type": intake_type, "email": normalized_email})
    stored_payload = {
        "rtb": "RTB09_PUBLIC_STRATEGIC_INTAKE",
        "access_policy": "manual_review_only",
        "access_granted": False,
        "invite_created": False,
        "signup_code_created": False,
        "review_status": "under_review",
        "review": review,
        "submitted": {
            **raw_payload,
            "intake_type": intake_type,
            "email": normalized_email,
        },
        "request": {
            "ip": ip,
            "user_agent": ua,
            "received_at": now_ts(),
            "route": "/api/public/intake",
            "locale": inp.locale or "pt",
            "source": inp.source or "grupo_patroai_public_landing",
            "terms_version": TERMS_VERSION,
            "privacy_version": PRIVACY_VERSION,
            "cookies_version": COOKIES_VERSION,
            "legal_identity": {
                "trade_name": PATROAI_TRADE_NAME,
                "legal_name": PATROAI_LEGAL_NAME,
                "cnpj": PATROAI_CNPJ,
                "address": PATROAI_ADDRESS,
                "contact_email": PATROAI_CONTACT_EMAIL,
                "privacy_email": PATROAI_PRIVACY_EMAIL,
            },
        },
        "consent_record": {
            "version": TERMS_VERSION,
            "privacy_version": PRIVACY_VERSION,
            "cookies_version": COOKIES_VERSION,
            "consent_terms": bool(inp.consent_terms),
            "consent_data_review": bool(inp.consent_data_review),
            "consent_contact": bool(inp.consent_contact),
            "consent_marketing": bool(inp.consent_marketing),
            "marketing_is_optional": True,
            "contact_is_operational": True,
            "controller": {
                "trade_name": PATROAI_TRADE_NAME,
                "legal_name": PATROAI_LEGAL_NAME,
                "cnpj": PATROAI_CNPJ,
                "contact_email": PATROAI_CONTACT_EMAIL,
                "privacy_email": PATROAI_PRIVACY_EMAIL,
            },
        },
    }

    intake_id = new_id()
    message_text = json.dumps(stored_payload, ensure_ascii=False, sort_keys=True)

    cr = ContactRequest(
        id=intake_id,
        full_name=inp.full_name.strip(),
        email=normalized_email,
        whatsapp=(inp.whatsapp or "").strip() or None,
        subject=f"strategic_intake:{intake_type}",
        message=message_text,
        privacy_request_type=None,
        consent_terms=bool(inp.consent_terms),
        consent_marketing=bool(inp.consent_marketing),
        ip_address=ip,
        user_agent=ua,
        terms_version=TERMS_VERSION,
        status="under_review",
        retention_until=now_ts() + (5 * 365 * 86400),
        created_at=now_ts(),
    )
    db.add(cr)
    db.commit()

    if inp.consent_marketing:
        try:
            db.add(MarketingConsent(
                id=new_id(),
                contact_id=cr.id,
                channel="email",
                opt_in_date=now_ts(),
                ip=ip,
                source=f"strategic_intake:{intake_type}",
                created_at=now_ts(),
            ))
            db.commit()
        except Exception:
            try:
                db.rollback()
            except Exception:
                pass
            logger.exception("RTB09_MARKETING_CONSENT_INTAKE_FAILED intake_id=%s", intake_id)

    # RTB-10 HF8 — best-effort internal notification.
    # Must never block the public form response.
    notify_sent = False
    try:
        notify_sent = _rtb10_hf8_notify_public_intake(
            intake_id=intake_id,
            intake_type=intake_type,
            payload={**raw_payload, "intake_type": intake_type, "email": normalized_email},
            review=review,
            request_meta={
                "ip": ip,
                "user_agent": ua,
                "received_at": now_ts(),
                "route": "/api/public/intake",
                "locale": inp.locale or "pt",
                "source": inp.source or "grupo_patroai_public_landing",
            },
        )
    except Exception:
        notify_sent = False
        logger.exception("RTB10_HF8_INTAKE_EMAIL_NOTIFY_FAILED intake_id=%s", intake_id)

    try:
        audit(
            db,
            org,
            None,
            "strategic_intake.submitted",
            request_id=ensure_request_id(request),
            path="/api/public/intake",
            status_code=200,
            latency_ms=0,
            meta={
                "intake_id": intake_id,
                "intake_type": intake_type,
                "score": review.get("score"),
                "tier": review.get("tier"),
                "access_granted": False,
                "email_notification_sent": bool(notify_sent),
            },
        )
    except Exception:
        logger.warning("RTB09_STRATEGIC_INTAKE_AUDIT_FAILED intake_id=%s", intake_id)

    logger.info(
        "RTB09_STRATEGIC_INTAKE_RECEIVED intake_id=%s type=%s score=%s tier=%s access_granted=False",
        intake_id,
        intake_type,
        review.get("score"),
        review.get("tier"),
    )

    return {
        "ok": True,
        "intake_id": intake_id,
        "status": "under_review",
        "access_granted": False,
        "manual_review_required": True,
        "message": _strategic_intake_public_message(inp),
        "review": {
            "tier": review.get("tier"),
        },
        "legal_versions": {
            "terms": TERMS_VERSION,
            "privacy": PRIVACY_VERSION,
            "cookies": COOKIES_VERSION,
        },
        "notification": {
            "internal_email_attempted": bool(PATROAI_INTAKE_NOTIFY_ENABLED),
            "internal_email_sent": bool(notify_sent),
        },
    }


def _strategic_intake_row_to_dict(row: ContactRequest) -> Dict[str, Any]:
    parsed: Dict[str, Any] = {}
    try:
        parsed = json.loads(getattr(row, "message", "") or "{}")
        if not isinstance(parsed, dict):
            parsed = {}
    except Exception:
        parsed = {}

    submitted = parsed.get("submitted") if isinstance(parsed.get("submitted"), dict) else {}
    review = parsed.get("review") if isinstance(parsed.get("review"), dict) else {}

    return {
        "id": row.id,
        "status": row.status,
        "intake_type": str(row.subject or "").split(":", 1)[1] if ":" in str(row.subject or "") else None,
        "full_name": row.full_name,
        "email": row.email,
        "whatsapp": row.whatsapp,
        "company": submitted.get("company"),
        "role": submitted.get("role"),
        "city": submitted.get("city"),
        "state": submitted.get("state"),
        "country": submitted.get("country"),
        "linkedin": submitted.get("linkedin"),
        "website": submitted.get("website"),
        "person_type": submitted.get("person_type"),
        "engagement_model": submitted.get("engagement_model"),
        "score": review.get("score"),
        "tier": review.get("tier"),
        "flags": review.get("flags") or [],
        "access_granted": False,
        "created_at": row.created_at,
        "payload": parsed,
    }


@app.get("/api/admin/intake/submissions")
def admin_list_strategic_intake_submissions(
    status: Optional[str] = None,
    intake_type: Optional[str] = None,
    limit: int = 100,
    _admin=Depends(require_admin_access),
    db: Session = Depends(get_db),
):
    limit = max(1, min(int(limit or 100), 500))
    stmt = select(ContactRequest).where(ContactRequest.subject.like("strategic_intake:%"))
    if status:
        stmt = stmt.where(ContactRequest.status == str(status).strip())
    if intake_type:
        stmt = stmt.where(ContactRequest.subject == f"strategic_intake:{_strategic_intake_type(intake_type)}")
    rows = db.execute(stmt.order_by(ContactRequest.created_at.desc()).limit(limit)).scalars().all()
    return {"ok": True, "items": [_strategic_intake_row_to_dict(r) for r in rows]}


@app.patch("/api/admin/intake/submissions/{intake_id}")
def admin_update_strategic_intake_submission(
    intake_id: str,
    inp: StrategicIntakeAdminUpdateIn,
    _admin=Depends(require_admin_access),
    db: Session = Depends(get_db),
):
    allowed = {
        "under_review",
        "qualified",
        "meeting_requested",
        "approved_for_private_access",
        "rejected",
        "archived",
    }
    status = str(inp.status or "").strip().lower()
    if status not in allowed:
        raise HTTPException(status_code=400, detail="Status inválido para intake.")

    row = db.execute(
        select(ContactRequest).where(
            ContactRequest.id == intake_id,
            ContactRequest.subject.like("strategic_intake:%"),
        )
    ).scalar_one_or_none()
    if not row:
        raise HTTPException(status_code=404, detail="Cadastro não encontrado.")

    parsed: Dict[str, Any] = {}
    try:
        parsed = json.loads(row.message or "{}")
        if not isinstance(parsed, dict):
            parsed = {}
    except Exception:
        parsed = {}

    parsed["review_status"] = status
    parsed["access_granted"] = False
    parsed["invite_created"] = False
    parsed["signup_code_created"] = False
    parsed.setdefault("admin_review", {})
    parsed["admin_review"].update({
        "status": status,
        "internal_notes": inp.internal_notes,
        "reviewer_action": inp.reviewer_action,
        "updated_at": now_ts(),
    })

    row.status = status
    row.message = json.dumps(parsed, ensure_ascii=False, sort_keys=True)
    db.add(row)
    db.commit()

    logger.info("RTB09_STRATEGIC_INTAKE_STATUS_UPDATED intake_id=%s status=%s access_granted=False", intake_id, status)
    return {"ok": True, "item": _strategic_intake_row_to_dict(row)}


