@app.post("/api/admin/landing/proofs/reorder")
def admin_reorder_social_proofs(
    inp: SocialProofReorderIn,
    _admin=Depends(require_admin_access),
    x_org_slug: Optional[str] = Header(default=None),
    db: Session = Depends(get_db),
):
    org = get_org(x_org_slug)
    changed = 0
    ts = now_ts()
    actor = _cms_admin_actor(_admin if isinstance(_admin, dict) else {})
    for item in inp.items:
        row = db.execute(select(SocialProofItem).where(SocialProofItem.id == item.id, SocialProofItem.org_slug == org)).scalar_one_or_none()
        if not row:
            continue
        row.sort_order = int(item.sort_order)
        row.updated_at = ts
        row.updated_by = actor
        db.add(row)
        changed += 1
    db.commit()
    return {"ok": True, "changed": changed}


@app.get("/api/admin/landing/blocks")
def admin_list_landing_blocks(
    page_key: Optional[str] = None,
    status: Optional[str] = None,
    _admin=Depends(require_admin_access),
    x_org_slug: Optional[str] = Header(default=None),
    db: Session = Depends(get_db),
):
    org = get_org(x_org_slug)
    q = select(LandingContentBlock).where(LandingContentBlock.org_slug == org)
    if page_key:
        q = q.where(LandingContentBlock.page_key == _clean_page_key(page_key))
    if status:
        q = q.where(LandingContentBlock.status == _clean_status(status))
    q = q.order_by(LandingContentBlock.page_key.asc(), LandingContentBlock.sort_order.asc(), LandingContentBlock.created_at.asc())
    rows = list(db.execute(q).scalars().all())
    return {"items": [_landing_block_dict(r) for r in rows]}


@app.post("/api/admin/landing/blocks")
def admin_create_landing_block(
    inp: LandingBlockUpsertIn,
    _admin=Depends(require_admin_access),
    x_org_slug: Optional[str] = Header(default=None),
    db: Session = Depends(get_db),
):
    org = get_org(x_org_slug)
    actor = _cms_admin_actor(_admin if isinstance(_admin, dict) else {})
    existing = db.execute(
        select(LandingContentBlock).where(
            LandingContentBlock.org_slug == org,
            LandingContentBlock.page_key == _clean_page_key(inp.page_key),
            LandingContentBlock.block_key == _clean_block_key(inp.block_key),
        )
    ).scalar_one_or_none()
    if existing:
        raise HTTPException(status_code=409, detail="Block key already exists for page")
    ts = now_ts()
    row = LandingContentBlock(
        id=new_id(),
        org_slug=org,
        page_key=_clean_page_key(inp.page_key),
        block_key=_clean_block_key(inp.block_key),
        status="draft",
        sort_order=int(inp.sort_order or 100),
        created_by=actor,
        updated_by=actor,
        created_at=ts,
        updated_at=ts,
    )
    _apply_landing_block_changes(row, inp, actor)
    db.add(row)
    db.commit()
    return {"ok": True, "item": _landing_block_dict(row)}


@app.get("/api/admin/landing/blocks/{block_id}")
def admin_get_landing_block(
    block_id: str,
    _admin=Depends(require_admin_access),
    x_org_slug: Optional[str] = Header(default=None),
    db: Session = Depends(get_db),
):
    org = get_org(x_org_slug)
    row = db.execute(select(LandingContentBlock).where(LandingContentBlock.id == block_id, LandingContentBlock.org_slug == org)).scalar_one_or_none()
    if not row:
        raise HTTPException(status_code=404, detail="Landing block not found")
    return _landing_block_dict(row)


@app.put("/api/admin/landing/blocks/{block_id}")
def admin_update_landing_block(
    block_id: str,
    inp: LandingBlockUpsertIn,
    _admin=Depends(require_admin_access),
    x_org_slug: Optional[str] = Header(default=None),
    db: Session = Depends(get_db),
):
    org = get_org(x_org_slug)
    actor = _cms_admin_actor(_admin if isinstance(_admin, dict) else {})
    row = db.execute(select(LandingContentBlock).where(LandingContentBlock.id == block_id, LandingContentBlock.org_slug == org)).scalar_one_or_none()
    if not row:
        raise HTTPException(status_code=404, detail="Landing block not found")
    next_page = _clean_page_key(inp.page_key)
    next_block = _clean_block_key(inp.block_key)
    conflict = db.execute(
        select(LandingContentBlock).where(
            LandingContentBlock.org_slug == org,
            LandingContentBlock.page_key == next_page,
            LandingContentBlock.block_key == next_block,
            LandingContentBlock.id != block_id,
        )
    ).scalar_one_or_none()
    if conflict:
        raise HTTPException(status_code=409, detail="Block key already exists for page")
    changed = _apply_landing_block_changes(row, inp, actor)
    db.add(row)
    db.commit()
    return {"ok": True, "changed": changed, "item": _landing_block_dict(row)}


@app.delete("/api/admin/landing/blocks/{block_id}")
def admin_delete_landing_block(
    block_id: str,
    _admin=Depends(require_admin_access),
    x_org_slug: Optional[str] = Header(default=None),
    db: Session = Depends(get_db),
):
    org = get_org(x_org_slug)
    row = db.execute(select(LandingContentBlock).where(LandingContentBlock.id == block_id, LandingContentBlock.org_slug == org)).scalar_one_or_none()
    if not row:
        raise HTTPException(status_code=404, detail="Landing block not found")
    db.delete(row)
    db.commit()
    return {"ok": True, "deleted": block_id}


@app.post("/api/admin/landing/blocks/reorder")
def admin_reorder_landing_blocks(
    inp: LandingBlockReorderIn,
    _admin=Depends(require_admin_access),
    x_org_slug: Optional[str] = Header(default=None),
    db: Session = Depends(get_db),
):
    org = get_org(x_org_slug)
    changed = 0
    ts = now_ts()
    actor = _cms_admin_actor(_admin if isinstance(_admin, dict) else {})
    for item in inp.items:
        row = db.execute(select(LandingContentBlock).where(LandingContentBlock.id == item.id, LandingContentBlock.org_slug == org)).scalar_one_or_none()
        if not row:
            continue
        row.sort_order = int(item.sort_order)
        row.updated_at = ts
        row.updated_by = actor
        db.add(row)
        changed += 1
    db.commit()
    return {"ok": True, "changed": changed}


# =========================
# PUBLIC ORKIO PRECHAT / ENTERPRISE LEADS
# Added for landing conversion flow.
# Safe: no auth required, stores minimal context in memory and sends optional internal notification.
# =========================

_PUBLIC_PRECHAT_MEMORY: Dict[str, Dict[str, Any]] = {}


class PublicPrechatIn(BaseModel):
    source: Optional[str] = "orkio_public_prechat"
    language: Optional[str] = "pt"
    answers: Dict[str, Any] = Field(default_factory=dict)
    messages: List[Dict[str, Any]] = Field(default_factory=list)
    diagnosis: Optional[str] = ""
    trial_days: Optional[int] = 7
    metadata: Dict[str, Any] = Field(default_factory=dict)


class PublicEnterpriseLeadIn(BaseModel):
    source: Optional[str] = "orkio_public_prechat"
    name: Optional[str] = ""
    email: Optional[str] = ""
    company: Optional[str] = ""
    phone: Optional[str] = ""
    interest_type: Optional[str] = "enterprise_white_label_integrations"
    message: Optional[str] = ""
    metadata: Dict[str, Any] = Field(default_factory=dict)


@app.post("/api/public/prechat")
def public_prechat_capture(payload: PublicPrechatIn, request: Request):
    prechat_id = "pre_" + uuid.uuid4().hex[:16]
    now = now_ts()
    item = {
        "prechat_id": prechat_id,
        "session_id": prechat_id,
        "source": payload.source or "orkio_public_prechat",
        "language": payload.language or "pt",
        "answers": payload.answers or {},
        "messages": payload.messages or [],
        "diagnosis": payload.diagnosis or "",
        "trial_days": int(payload.trial_days or 7),
        "metadata": payload.metadata or {},
        "ip": request.client.host if request.client else None,
        "user_agent": request.headers.get("user-agent"),
        "created_at": now,
        "updated_at": now,
    }
    _PUBLIC_PRECHAT_MEMORY[prechat_id] = item
    return {
        "ok": True,
        "prechat_id": prechat_id,
        "session_id": prechat_id,
        "trial_days": item["trial_days"],
    }


@app.get("/api/public/prechat/{prechat_id}")
def public_prechat_get(prechat_id: str):
    item = _PUBLIC_PRECHAT_MEMORY.get(str(prechat_id or "").strip())
    if not item:
        raise HTTPException(status_code=404, detail="Prechat context not found.")
    return {"ok": True, "context": item}


@app.post("/api/public/enterprise-lead")
def public_enterprise_lead(payload: PublicEnterpriseLeadIn, request: Request):
    now = now_ts()
    lead_id = "lead_" + uuid.uuid4().hex[:16]
    metadata = payload.metadata or {}
    answers = metadata.get("answers") if isinstance(metadata, dict) else None

    subject = "Solicitação Enterprise / White Label - Orkio OS"
    body = "\n".join([
        "Nova solicitação Enterprise / White Label recebida pela landing Orkio.",
        "",
        f"Lead ID: {lead_id}",
        f"Nome: {payload.name or (answers or {}).get('name') or 'não informado'}",
        f"E-mail: {payload.email or 'não informado'}",
        f"Empresa: {payload.company or 'não informada'}",
        f"Telefone: {payload.phone or 'não informado'}",
        f"Interesse: {payload.interest_type or 'enterprise_white_label_integrations'}",
        "",
        "Mensagem / Diagnóstico:",
        payload.message or "",
        "",
        "Metadados:",
        json.dumps(metadata, ensure_ascii=False, indent=2),
        "",
        f"IP: {request.client.host if request.client else 'n/d'}",
        f"User-Agent: {request.headers.get('user-agent') or 'n/d'}",
        f"Criado em: {now}",
    ])

    sent = False
    try:
        sent = _send_resend_email(RESEND_INTERNAL_TO, subject, body)
    except Exception:
        logger.exception("PUBLIC_ENTERPRISE_LEAD_EMAIL_FAILED")

    return {
        "ok": True,
        "lead_id": lead_id,
        "email_sent": bool(sent),
        "message": "Solicitação registrada para avaliação da equipe PatroAI.",
    }


